window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]=window.__LIBQ["pham-nhan-tu-tien"]["q03"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q03"]["cotTruyen"]=[{"chuong":181,"tieuDe":"Thải Điệp Dữ Tử Chiến","tomTat":"Hàn Lập vận Liễm khí thuật đến cực hạn để giấu khí tức, không dám liều một-đánh-hai nên trơ mắt nhìn hai đệ tử Linh thú sơn cướp Hàn yên thảo, đốt xác đệ tử Thiên khuyết bảo và thu Hàn băng thiềm rồi rời đi. Chứng kiến người áo lam cẩn trọng vẫn chết vô thanh vô tức, hắn dao động muốn thối lui và ăn hai viên Trúc Cơ đan, nhưng lý trí thắng thế nên vẫn tiếp tục tiến vào trung tâm cấm địa. Kiêng kị thủ pháp khu thú của Linh thú sơn, hắn chọn đi vòng thay vì theo lộ tuyến gần nhất, đồng thời tiếc nuối nhớ con Vân sí điểu đã hoang dã một đi không trở lại. Không ngờ quyết định đi vòng cứu hắn khỏi lưới bươm bướm cảnh giới hai đệ tử Linh thú sơn giăng ra sau khi rời Ô long đàm, vì loài trùng này sợ lạnh không thả được nơi nước dị chất lạnh giá. Cuối cùng Hàn Lập tới một vách núi cổ quái, phát hiện hai thi thể đồng quy vu tận: một đệ tử Cự kiếm môn áo đen bị ti tuyến cắt đứt cổ và một sư huynh Hoàng Phong cốc áo vàng bị cự kiếm ghim xuống đất. Hắn tái dựng trận tử chiến — người Cự kiếm môn mạnh hơn nhưng bị đánh lén, còn vị sư huynh dù thắng thế bằng mưu vẫn bị đâm chết cùng lúc, tạo thành cuộc chiến không có kẻ chiến thắng."},{"chuong":182,"tieuDe":"Thiểu Nữ Dữ Ti Tuyến","tomTat":"Sau khi hiểu nguyên nhân cái chết của hai người, Hàn Lập lục soát thi thể nhưng túi trữ vật đã bị lấy đi, hắn nhận ra còn tồn tại người thứ tư có thể đang nấp gần lấy thi thể làm mồi dụ. Đề phòng kẻ địch ẩn trong bãi cỏ cao trước vách núi, hắn dùng thần niệm dò tìm để đả thảo kinh xà, không phát hiện dị thường rồi vọt đi biến mất. Khi hắn đi khuất, một thiếu nữ áo trắng Yểm Nguyệt tông khoảng mười lăm mười sáu tuổi từ bụi cỏ bước ra, tự nhận đã cướp túi trữ vật, đánh giá tư chất Hàn Lập rồi tạm tha và coi hắn như đồ chơi mới, sau đó dùng Mộc độn phù chìm trong lục quang biến mất. Hàn Lập lấy ra sợi ti tuyến trong suốt thu từ thi thể, rót pháp lực khiến nó duỗi dài hơn mười trượng, tự ẩn hình và cực sắc bén, cắt đôi mười cây đại thụ dễ dàng, hoan hỉ không thôi. Gần trung tâm cấm địa, hai nhóm đệ tử Hóa Đao Ổ và Thanh Hư môn quần đấu tranh vào hái linh dược trước, Thanh Hư môn cao hơn một bậc giết đại bộ phận đối thủ rồi xông vào khu trung tâm. Trung tâm cấm địa ẩn chứa kỳ hoa dị quả nhưng được yêu thú bậc một bảo hộ, hái thuốc thì linh dược và yêu thú mới lại sinh ra khó hiểu. Cuối chương, tại một ngã đường Hàn Lập bị một gã Cự Kiếm môn râu quai nón và một gã Thiên Khuyết Bảo chặn trước sau, tên râu quai nón nhe răng cười muốn báo thù."},{"chuong":183,"tieuDe":"Dung Linh Phù","tomTat":"Trong cấm địa, Hàn Lập bị hai tu sĩ chặn cả trước lẫn sau tại vị trí hiểm ác Nhất tuyến thiên — nơi hai bên vách núi cao và tuyệt cấm ngự khí phi hành. Nhận thấy đối phương thù địch, hắn lập tức tung thủy tráo, phóng Phi thiên thuẫn, cầm Kim phù tử mẫu nhận và phù Thổ lao thuật, di chuyển tạo thế ba góc để khỏi thụ địch hai đầu. Gã râu quai nón tu công pháp tầng mười ba, đệ tử Thiên khuyết bảo đỉnh tầng mười hai, đều vượt xa tu vi tầng mười một của Hàn Lập; hắn tự nhủ pháp lực thua kém nhưng pháp khí, phù bảo và át chủ bài Thiên lôi tử đủ bù chênh lệch, song chưa nỡ dùng. Qua đối thoại, gã râu quai nón tuyên bố Hàn Lập chọc tức hắn nên đòi tự tay giết, còn đệ tử Thiên khuyết bảo đồng ý hỗ trợ, để lộ bí mật hai người dùng Dung linh phù bậc cao — liên kết linh khí để truyền tới cùng một chỗ với tỉ lệ thành công năm-năm — nhằm liên thủ phục kích đoạt bảo. Khi gã râu quai nón dựng màn hào quang xanh biếc tiến tới, Hàn Lập nhắm sơ hở của đệ tử Thiên khuyết bảo đang lơ đãng nhìn trời, bất ngờ ném Thổ lao thuật biến thành hoàng quang bao chặt phòng ngự gã râu quai nón thành lớp vỏ vàng, giam hắn không nhúc nhích được."},{"chuong":184,"tieuDe":"Kim Quang Chuyên Chi Uy","tomTat":"Hàn Lập dùng Thổ lao thuật giăng màn hào quang vàng vây khốn tên râu quai nón Linh thú sơn — kẻ cậy vòng bảo hộ mộc thuộc tính và bầy linh thú (rắn xanh cánh thịt tím, dã thú giống Xuyên sơn giáp) chống trả. Bỏ mặc địch trong thổ lao, hắn lao tới người Thiên khuyết bảo (Nghiêm huynh đệ) và cách không dùng ti tuyến trong suốt chém đầu, khiến người chia làm hai chết ngay. Tên râu quai nón kinh hãi, ngoài mặt giả hung thần ác sát nhưng trong lòng chỉ muốn thoát thân bỏ chạy. Hàn Lập lấy phù bảo Kim quang chuyên ra khởi động, nhưng bị nó liều mạng hút ba phần pháp lực khiến hắn tái mặt, mắng Vạn bảo các bán “quỷ hút máu”. Sau khi phù bảo dừng, hắn phóng Kim quang chuyên như ngọn núi vỗ thẳng xuống, đè tên râu quai nón cùng linh thú thành đám bùn, tạo hố sâu cả trượng. Cuối cùng Hàn Lập hủy hai thi thể, thu túi trữ vật rồi rời Nhất tuyến thiên tới rừng rậm nghỉ khôi phục pháp lực."},{"chuong":185,"tieuDe":"Cường Giả","tomTat":"Hàn Lập ngồi dưới một cây đại thụ rậm rạp ngoài rìa khu rừng khôi phục nguyên khí và pháp lực, đúng lúc cả cấm địa bước vào đợt cao trào giết chóc đầu tiên của huyết sắc thí luyện. Chương phân loại ba loại đệ tử trong cấm địa: loại thực lực cực thấp chỉ làm vai bị giết (Hàn Lập là ngoại lệ nhờ dựa dị bảo), loại pháp lực khá tự lượng sức mà đi giết người đoạt bảo, và loại đỉnh Kim tự tháp tinh nhuệ nhất do thượng tầng các phái ký thác — chính bọn họ ăn ý cùng khơi mào đợt thanh tẩy đại quy mô. Một đại hán chân trần lưng mang cự kiếm bạc truy sát Tiêu Nhị của Hóa đao ổ, đánh nát hai kiện thượng phẩm pháp khí rồi chém hắn thành hai đoạn, nhưng không lấy túi trữ vật vì sợ pháp bảo khác làm phân tâm tu hành. Bên dòng suối khu phụ cận trung tâm, nam tử áo xanh tự xưng Hàn Thiên Nhai giả vờ tha nữ đệ tử Yểm nguyệt tông, đợi nàng thu pháp khí rồi bất ngờ dùng phi đao đỏ giết chết. Khắp cấm địa còn nhiều cảnh giết chóc rải rác: xác đệ tử Linh thú sơn bên vài quái thú chết, người áo lục điều khiển bầy ong vây công người mặc đạo trang. Khi Hàn Lập vừa mừng thầm pháp lực đã khôi phục thì nghe tiếng bước chân dồn dập cùng hơi thở trầm trọng chạy về phía cây đại thụ hắn đang ngồi."},{"chuong":186,"tieuDe":"Xuất Thủ","tomTat":"Hàn Lập đang tĩnh tọa khôi phục pháp lực thì một nữ đệ tử áo vàng Hoàng Phong cốc vừa té vừa chạy tới dưới tàng cây kêu cứu, phía sau là nữ áo trắng thong thả truy sát. Nhờ Khiên dẫn thuật của Chưởng môn Chung Linh Đạo, đệ tử đồng môn có thể cảm ứng vị trí lẫn nhau nên nữ áo vàng tìm được nơi ẩn của hắn. Hàn Lập không vội cứu mà dò xét pháp lực đối phương, lấy Kim phù tử mẫu nhận, phù lục phòng ngự và quấn ti tuyến trong suốt lên ngón vô danh đề phòng. Thấy nữ áo trắng chỉ mười hai tầng công pháp, hắn khu động Kim phù tử mẫu nhận phóng tử nhận đón đầu bạch quang, chính thức nhập cuộc. Nữ áo trắng đốt tan nửa trên cây cổ thụ bằng Đại hỏa cầu phù lục, phát hiện Hàn Lập chỉ mười một tầng nên khinh miệt tuyên bố diệt cả hai. Khi hắn phóng sáu thanh kim nhận và nữ áo vàng ném hỏa xà, nữ áo trắng lật ra gương cổ quái phóng thanh quang khiến chúng lơ lửng quần đảo không hạ xuống được. Nữ áo vàng tiết lộ gương chỉ chế ngự một vùng nửa khắc, nhưng cảnh báo nữ áo trắng là hậu nhân Trưởng lão Yểm Nguyệt tông nhiều pháp khí cổ quái, khiến Hàn Lập hối hận và biết mình phải liều mạng."},{"chuong":187,"tieuDe":"Hoàng Tước “Phong Nhạc”","tomTat":"Nữ tử áo trắng Yểm nguyệt tông thấy tấm gương nhỏ ngăn được kim nhận của Hàn Lập nên tự đắc, lấy ra thủy tinh cầu màu hồng phun dịch thể ăn mòn pháp khí tạo vòng bảo hộ. Hàn Lập không cho ngân câu bắn thẳng vào dịch thể mà lén dùng thượng phẩm pháp khí Thanh Tác trói nữ tử cùng vòng bảo hộ thành một cái kén, nâng phù bảo Kim quang chuyên định kết liễu; nữ tử áo vàng sư tỷ hỗ trợ bằng tiểu pháp thuật nhưng vô hiệu. Đúng lúc đó từ rừng phía sau bùng phát linh khí khổng lồ, một luồng hoàng quang bắn xuyên Thanh Tác, vòng bảo hộ và cả nữ tử áo trắng khiến nàng chết ngã tại chỗ; một thân ảnh áo lam lao tới cướp túi trữ vật. Đó là cuồng nhân Phong Nhạc của Thiên Khuyết Bảo, trung niên mặt sẹo mũi ưng đầy sát khí, công pháp đỉnh điểm tầng mười ba, khiến nữ tử áo vàng hoảng sợ vượt xa. Ngân câu của Hàn Lập bị dịch thể ăn mòn thủng lỗ chỗ hư hỏng; hắn nhận ra tiểu đao hoàng quang của Phong Nhạc là phù bảo có uy năng pháp bảo giống Kim quang chuyên. Khi Phong Nhạc định thu tấm gương và thủy tinh cầu, Hàn Lập phóng hỏa cầu phá hoại khiến hắn nổi giận; Phong Nhạc đe dọa hỏi muốn chết cách nào, Hàn Lập mỉm cười tuyên chiến muốn hắn chết."},{"chuong":188,"tieuDe":"Ác Danh","tomTat":"Phong Nhạc nổi giận trước lời khiêu khích của Hàn Lập, và chương hé lộ lai lịch ác danh của hắn: kẻ tu tiên hung tàn từng tra tấn người ba ngày, giảo hoạt núp bóng Thiên khuyết bảo để hoành hành khắp thất đại phái. Khi Phong Nhạc thúc tiểu đao hoàng mang bắn vào đầu Hàn Lập, hắn kịp triển Phi thiên thuẫn màu đen, tỏa hắc quang chặn được đòn công kích trong khoảng hai trượng. Nữ tử áo vàng nhân lúc hai người tranh đấu lén bỏ chạy, nhưng bị Phong Nhạc lóe tới chặn ở bìa rừng và đâm một đao xuyên ngực chết tại chỗ, còn Hàn Lập lạnh lùng mặc kệ kẻ phản bội tự diệt. Phong Nhạc liếm máu trên tay, nhe răng cười dọa nạt hòng khiến Hàn Lập khiếp sợ không dám toàn lực. Hàn Lập cân nhắc dùng phù bảo Kim quang chuyên uy lực kinh người nhưng nhận ra nhược điểm hao pháp thuật và chậm chạp của nó, chỉ hữu dụng khi vây khốn được đối thủ. Thấy thân pháp Phong Nhạc nhanh như tia chớp không kém La yên bộ, kế đánh lén của hắn thành vọng tưởng, cuối cùng Hàn Lập nghi ngờ đối phương cũng là người mang võ công giang hồ giống mình."},{"chuong":189,"tieuDe":"Lôi Diệt","tomTat":"Hàn Lập nghi hoặc về thân pháp thần tốc của Phong Nhạc nhưng không kịp tìm hiểu, đành xuất Kim Quang Chuyên rồi tung Kim phù tử mẫu nhận hóa tám đạo kim quang thăm dò; Phong Nhạc rút Hoàng La Tán — pháp khí phòng ngự cực cao vượt Phi Thiên Thuẫn — khiến kim nhận nổ bắn ngược. Đối kháng công thủ, Phi Thiên Thuẫn linh hoạt của Hàn Lập đỡ hết đao phong của tiểu đao hoàng mang Phong Nhạc. Hàn Lập đau lòng bày nghi binh: xuất tiểu hồ lô đen phun Hỗn Nguyên Châu rồi giơ Thanh Giao kỳ tụ linh quang xanh để hút chú ý đối phương, trong khi giấu một viên Thiên Lôi Tử màu lam lẫn trong đám châu. Đúng lúc Phong Nhạc mải đề phòng Thanh Giao kỳ, viên châu lam chạm vòng bảo hộ bùng nổ luồng sáng trắng vô thanh, khiến hắn hóa thành cát bụi chỉ còn hai nửa chân đi giày. Hàn Lập ngồi thở dài cười khổ vì mới hai ngày vào cấm địa đã dốc gần hết pháp bảo và cả đòn sát thủ cuối, lo ba ngày còn lại gặp thêm cường giả. Cuối cùng hắn quay nhìn phía đối diện thì miệng mở to, hồi lâu không nói nên lời."},{"chuong":190,"tieuDe":"Ô Ngoa","tomTat":"Sau trận đại chiến, Hàn Lập vọt tới chỗ Phong Nhạc bị Thiên lôi tử giết nhưng túi trữ vật của đối phương đã biến mất, chỉ còn lại nửa cặp chân. Hắn kiểm kê thu-chi: nhặt được gương nhỏ, Thủy tinh cầu và phù bảo tiểu đao từ nữ tử áo vàng đã chết, đổi lại tổn thất Thiên lôi tử, Ngân câu, Thanh tác cùng túi trữ vật của mình, không rõ lời hay lỗ. Hắn thả hỏa cầu thiêu hủy thi thể để diệt tích, phát hiện đôi giày đen không cháy vẫn nguyên vẹn — chính là pháp khí chế từ da yêu thú, bí mật thân pháp quỷ dị của Phong Nhạc. Mang giày vào, chỉ một bước nhỏ hắn đã phiêu ra ngoài một trượng, nhanh hơn cả Ngự Phong quyết; kết hợp La Yên bộ và Ngự Phong quyết, hắn hóa thành trận gió chém đứt cây cối trong hơn mười trượng mà không lộ thân hình. Hắn nhận ra thân pháp cực tốc này thoát khỏi cả Thiên Nhãn thuật nhưng chỉ duy trì được thời gian ngắn. Cuối cùng, hắn mai táng sơ nữ tử áo vàng rồi lóe mình lao về khu trung tâm, nơi tinh anh các phái đang tụ về chuẩn bị đợt đại thanh tẩy ngày thứ hai; sau một ngày giết chóc, đệ tử các phái chỉ còn hơn bảy mươi người."},{"chuong":191,"tieuDe":"Dị Tâm Dữ Cô Linh","tomTat":"Tại hố đất sản sinh kỳ trân dị thảo ở vùng phía tây khu trung tâm, ba tu tiên giả khác môn phái hợp sức diệt một đầu Hỏa lang ba mắt: Mông đệ tử Cự Kiếm môn dùng cự kiếm xanh chống đỡ rồi một kiếm chém chết yêu thú, còn Hướng Chi Lễ và Lý đạo trưởng phụ trợ hai bên. Hướng Chi Lễ khoe công thuyết phục liên minh hái Hỏa Long thảo và đề nghị chia đều, nhưng Mông đệ tử khi quay lưng đi hái thảo lộ một tia âm lệ ám chỉ ý định trở mặt độc chiếm. Ở vùng phía nam toàn cát vàng, một cặp đệ tử Yểm Nguyệt tông dùng Băng Trùy thuật lùng sục suốt nửa ngày truy sát cô gái áo lục; nữ đệ tử thuộc danh hiệu Yểm Nguyệt song kiều thề móc mắt nàng và mắng nam đạo lữ là phế vật. Nàng thả một phù lục màu lam hóa mây đen phóng vô số băng trùy phủ dày vùng cát nhưng không lộ mục tiêu nên tức giận rời đi. Sau khi họ đi, cô gái áo lục Linh Thú sơn — chính là Hạm Vân Chi, người từng bán Kim Trúc bút cho Hàn Lập — trồi lên với một băng trùy đâm trúng vai, tự rút ra và dốc dược phấn vàng cầm máu, tay nắm chặt một khăn lụa vàng phi phàm. Nàng khóc nhỏ vì sợ liên lụy người khác rồi quật cường gượng dậy, xiêu vẹo hướng về khu trung tâm và cuối cùng biến mất trong vùng cát vàng."},{"chuong":192,"tieuDe":"Phi Xà","tomTat":"Hàn Lập đi nửa ngày mới tới rìa khu vực trung tâm Huyết sắc thí luyện, cả đường bình yên vì người đến trước bị đám tinh anh giết sạch còn người đến sau bị Phong Nhạc cùng một nữ tử nhiều bảo vật dọn dẹp. Vì muốn tìm ba vị thuốc chính luyện Trúc Cơ đan, hắn không ẩn nấp mà tiến tới cửa đồng, ở đó thấy bức tường đá cao có ba tử thi bị đại băng trùy đâm xuyên tứ chi xếp thành chữ đại — đòn lập uy của một kẻ tâm lý biến thái. Hàn Lập giữ vẻ bình tĩnh bước qua cửa đồng đã mở, vào một tiên cảnh đầy kỳ hoa dị thảo linh khí nồng đậm. Một giọng khàn khàn giễu cợt bảo hắn an tâm đi chết, rồi hai bóng xanh từ bụi hoa đánh lén sau lưng nhưng bị thần thức hắn phát hiện né kịp. Hai vật hiện nguyên hình phi xà mọc đôi cánh xanh trong suốt, tốc độ ngang La yên bộ, truy đuổi Hàn Lập; hắn chỉ dùng cước lực chạy né để giữ sức vì thể lực chưa hồi sau hai trận ác đấu. Không tìm ra chủ nhân, Hàn Lập quyết đánh chết hai con rắn nên rút phù lục Hỏa xà thuật, nhưng chủ nhân giọng khàn nhận ra Đạp vân ngoa dưới chân hắn liền kinh ngạc kêu dừng tay muốn nói chuyện và thu phi xà về, khiến Hàn Lập chần chừ có nên ra tay hay không."},{"chuong":193,"tieuDe":"Địch Hữu Chi Phân","tomTat":"Một hán tử xấu xí tầm thước mặt lốm đốm vết đen đeo bảy tám túi lớn nhỏ xông ra từ dưới tàng cây cách Hàn Lập hai mươi trượng, kinh ngạc nhận ra Đạp vân ngoa của “lão Phong” ở chân đối phương và tự xưng là Chung Ngô của Linh thú sơn. Hàn Lập lãnh đạm thừa nhận đã giết Phong Nhạc để lập uy răn đe, đồng thời bí mật mang ti tuyến vào ngón vô danh dự phòng, song tự đánh giá tỉ lệ ám sát chỉ ba bốn phần do khoảng cách quá xa. Chung Ngô cười khinh thường từ chối báo thù cho Phong Nhạc vì chỉ có chút giao tình, vừa trò chuyện vừa liên tục lui lại kéo dài khoảng cách khiến xác suất ra tay của Hàn Lập giảm dưới một thành. Lão còn lộ bản tính tàn bạo, coi máu thịt người tu tiên là bổ dược, tiếc rẻ “kiệt tác” máu thịt trên tường do Hàn Thiên Nhai làm và lấy một khối thịt trong túi vải ném về sau. Nghi việc Hàn Lập giết Phong Nhạc là ám muội nhưng không dám chủ động thử động thủ, Chung Ngô đề nghị trao đổi ngọc giản thông tin khu trung tâm. Hai người luyện chế ngọc giản trong thời gian một chung trà, đều cố ý giấu vài chỗ quan trọng rồi nhìn nhau cười vì đều “trong lòng có quỷ”. Bề ngoài họ nói cười như bạn cũ nhưng Chung Ngô luôn giữ khoảng cách, khiến Hàn Lập trong lòng phỉ nhổ mà cười khổ trước sự cẩn thận của đối phương."},{"chuong":194,"tieuDe":"Trung Tâm Khu Bí Văn","tomTat":"Hàn Lập không nóng vội mà nghiên cứu cấu trúc khu trung tâm cấm địa: diện tích chiếm hơn một phần ba cả cấm địa, bốn phía tường đá quây vòng tròn với bốn cánh cửa đồng, chia thành ba tầng như vỏ-thịt-hạt của quả. Tầng thứ nhất là hoa viên đẹp mà ít vật hữu dụng; tầng thứ hai là sơn mạch quanh năm sương mù dày, chứa thượng phẩm linh dược cùng ba vị chủ dược luyện Trúc Cơ đan, đầy yêu thú thủ hộ; tầng thứ ba có tòa bảo tháp gần 100 trượng, nơi ở của chủ nhân cấm địa, ngăn bởi cấm chế cường đại nên vẫn là bí ẩn. Chương cũng kể lai lịch Nguyệt dương bảo châu: một tu sĩ Yểm Nguyệt tông luyện chế bảo châu khắc chế sương mù độc chướng, nhờ đó môn phái vươn lên đệ nhất Việt quốc, sau bị lục đại phái ép nên giao bảo châu làm vật chung của thất đại phái, các phái thay phiên nắm giữ và giám sát nhau. Hàn Lập chạy thẳng tới khu trung tâm đúng lúc thất đại phái chuẩn bị khu trừ sương mù vào sáng ngày thứ ba, chỉ mong hái đủ linh dược tầng hai rồi an toàn ra. Hắn khéo léo thoát khỏi sự dây dưa của hán tử xấu xí Chung Ngô, thấy y vẫn đứng nguyên tại chỗ, rồi tìm một hốc cây cũ tạo vòng phòng hộ, ngủ đến rạng sáng hôm sau để khôi phục trạng thái chờ vào sơn mạch."},{"chuong":195,"tieuDe":"Nguyệt Dương Bảo Châu chi uy","tomTat":"Hàn Lập tỉnh dậy trong hốc cây, khoanh chân khôi phục pháp lực đến đỉnh điểm chuẩn bị tiến vào cấm địa. Hắn kiểm kê năm túi trữ vật thu từ hai đại hán râu quai nón, chỉ được 23 món pháp khí gồm hạ, trung, thượng phẩm mà không có kiện đỉnh cấp nào, từ đó nhận ra trước kia mình đã hiểu lầm về sự phổ biến của đỉnh cấp pháp khí — thực tế chúng rất hiếm và phần lớn thuộc đệ tử gia tộc cường đại. Hắn thử 11 món thượng phẩm, chọn ra ba kiện đắc dụng nhất: một phi đao, một kim bạt và một bình ngọc phun độc vụ để che mắt địch nhân. Rời hốc cây, Hàn Lập theo con đường nhỏ an toàn đến lối vào thông đạo, ẩn trong bụi rậm và kinh ngạc trước sương mù trắng dày đặc che kín núi. Sau vài canh giờ chờ đợi, hắn chứng kiến uy lực Nguyệt dương bảo châu: cột sáng trắng ngưng tụ thành quang cầu khổng lồ như thái dương rồi nổ tung thành mưa quang cầu xua tan sương mù — lần đầu hắn thấy uy lực chân chính của pháp bảo cao cấp. Ngọn núi cao ngàn trượng đầy yêu thú hiện ra; các tu sĩ ẩn nấp đồng loạt lao lên núi, còn Hàn Lập nán lại quan sát xem ai chọn cùng đường với mình."},{"chuong":196,"tieuDe":"Kế Hoạch Của Hàn Lập","tomTat":"Hàn Lập chờ mấy đệ tử khác đi trước rồi chọn hướng chưa ai đi mà lặng lẽ tiến vào cấm địa núi lửa; không lâu sau, tên Chung Ngô xấu xí xuất hiện trước thông đạo, cười lạnh thả mười mấy con bướm vàng vào rừng để truy tung rồi thong thả đi theo ám toán. Bên ngoài cấm địa, các trưởng bối Kết Đan kỳ giữ cửa lo lắng cuộc đánh cược: đạo sĩ Thanh Hư Phù Vân Tử mất tự tin sau khi Khung lão quái Yểm Nguyệt tông nhúng tay, còn Nghê Thường tiên tử vẫn bình tĩnh tươi cười. Phù Vân Tử lén hỏi Lý sư tổ bày tỏ lo lắng, nhưng sau khi hắn rời đi Lý sư tổ gọi thẳng tên lão mũi trâu, nhìn thấu ý đồ Thanh Hư muốn ngồi trên đầu Hoàng Phong cốc và tỏ ra hồ ly thâm tàng bất lộ. Trong cấm địa, Hàn Lập bị Thôi Sơn thú chặn đường, dịch chuyển ra sau lưng dùng ti tuyến chẻ đôi con thú, rồi tránh Phi Linh khổng tước trung giai và nhận ra yêu thú núi lửa quá nhiều. Cuối cùng hắn chạy tới sơn động bí mật sản sinh Tử Hầu hoa, tiết lộ kế hoạch hái cây con linh dược mà người khác coi vô dụng, dùng cái bình nhỏ thần bí ban đêm nuôi dưỡng chúng trưởng thành để làm Trúc Cơ đan, chỉ lo trong ba ngày còn lại chưa đủ số lượng."},{"chuong":197,"tieuDe":"Yêu Thú Cự Ngô Công","tomTat":"Sau hai canh giờ, Hàn Lập đến động khẩu bí động chứa Tử Hầu hoa, cẩn thận quan sát thời gian một chén trà xác nhận không có mai phục rồi mới vào sâu. Hắn dùng Nguyệt Quang thạch soi đường và tạo vòng bảo hộ thổ thuộc tính trong thông đạo hẹp dài. Đến một sảnh đá thiên nhiên, hắn phát hiện ba bốn gốc Tử Hầu hoa mọc trên khối đá tím, nhưng có một con rết yêu thú bậc trung nằm ngủ canh giữ. Không muốn tiêu hao lớn pháp lực bằng phù bảo Kim Quang chuyên vì đường còn dài, hắn nghĩ ra kế dụ rắn ra khỏi hang: bố trí lưỡi dao sắc bén làm bẫy trong thông đạo, rồi nghênh ngang khiêu khích, bắn hỏa cầu chọc giận con rết. Con rết phun độc vụ đỏ, Hàn Lập giả chạy trốn dụ nó đuổi theo. Khi con rết đuổi tới, bụng nó bị lưỡi dao bẫy xẻ banh, độc huyết đen tuôn ra; Hàn Lập nhân cơ hội xuất kim quang hình tròn cùng phi đao xanh cắt về hai xúc tu con rết."},{"chuong":198,"tieuDe":"Xung Đột","tomTat":"Hàn Lập dùng hai kiện thượng phẩm pháp khí bổ xúc tu con rết yêu thú nhưng bị bật ra vì vỏ quá cứng, cuối cùng kết liễu nó nhờ mưu kế kim nhận cắm ngược ngụy trang bùn đen khiến con rết đuổi theo bị đâm banh bụng chết oan uổng. Hắn thu hoạch trọn Tử Hầu hoa xanh trong sảnh đá, khoét cả hoa lẫn đá tím vào hộp ngọc bích, dùng Thanh Linh tán giải độc huyết rồi cắt vài khối vỏ lưng con rết làm vật liệu chế nội giáp có thể ngăn một kích toàn lực của pháp khí đỉnh cấp. Trong khi Hàn Lập tiếp tục sưu tập Thiên Linh quả, ở sơn cốc đông nam ba tu sĩ giằng co tranh hai đóa Tử Hầu hoa tím bên cạnh xác Chích giác lộc. Thanh niên áo lam Thiên Khuyết bảo tự nhận một mình giết Chích giác lộc nên đòi linh dược, nhưng lão giả áo xanh và trung niên đạo sĩ Thanh Hư môn vốn quen biết cũ đã liên thủ chia đôi linh dược, gạt bỏ hắn. Thanh niên liều lao cướp bị lão giả phóng quải trượng chặn, đạo sĩ dùng Linh Hồ bộ chớp mắt bám sau lưng cảnh cáo. Thanh niên sợ hãi bỏ chạy khỏi cốc, đạo sĩ tha mạng và được lão giả khen thân pháp xuất thần nhập hóa."},{"chuong":199,"tieuDe":"Trần Thị Huynh Muội","tomTat":"Trung niên đạo sĩ mộc mạc cảnh cáo lão giả họ Lý không được giết thanh niên vừa thả (Hàn Lập), vì hắn cầm Lạc Trần châu — pháp khí thành danh của Mã Vân Long, cường giả Thiên Khuyết bảo có hy vọng Kết Đan kỳ; lão giả tỉnh ngộ, hai người mỗi người hái một gốc Tử Hầu hoa rồi chia đường. Trên đỉnh núi, phe Hoàng Phong cốc (Trần đại công tử dùng Kim thư và Ngân bút, cùng Trần thất muội) đối đầu phe Chung Ngô (Linh Thú sơn) và thanh niên Hóa Đao ổ để tranh linh thảo. Thanh niên Hóa Đao ổ chống không nổi Kim thư và Ngân bút liền nhận thua, giao linh thảo cho họ Trần rồi cùng Chung Ngô rời đi. Trần đại ca ngăn thất muội truy sát vì hai gia tộc kia không nhỏ, đồng thời nhắc chuyện tiểu tử Lục gia mưu hại thất muội đã biến mất, và người cứu nàng (Hàn Lập) có Thanh Giao kỳ mà hắn đang truy tìm. Trần thất muội chính là Trần sư muội đã trở nên lãnh nhược, mang hận người cứu vì bị bỏ nơi hoang vu và mất Trúc Cơ đan; nàng hồi tưởng đêm bị nạn trần trụi bị hai tên Lục gia vuốt ve, thẹn quá hóa giận, lấy cớ đi hái thuốc vào thạch ốc, đại ca có kế sách đi theo. Chương khép lại với hai cảnh khác: cô gái áo lục điều khiển tiểu điêu trắng đấu quái xà hai đầu cạnh cây đại thụ đỏ, và một hàng đệ tử Yểm Nguyệt tông sống sót đi trong sơn động dưới đất do một cô gái trẻ dẫn đầu."},{"chuong":200,"tieuDe":"Thiếu nữ dữ thiếu nữ","tomTat":"Một cô gái áo trắng vẻ thanh thuần nhưng thân phủ sáng bạc kỳ dị dẫn đầu đoàn đệ tử Yểm Nguyệt tông, được tôn xưng “Sư tổ” và nghi là tu sĩ Kết Đan kỳ; nữ tử điêu ngoa vùng đất cát từng gặp Hàn Lập nay cũng nhu thuận đi theo. Trước đầm nước xanh biếc, nàng ra lệnh đệ tử dùng bí pháp hợp kích Âm Dương Khiên Dẫn thuật, còn nàng phun pháp bảo viên hoàn phấn hồng dẫn dụ và diệt gọn yêu thú đỉnh cấp Bích Thủy ngạc trong bí quật mà không tổn thương ai. Ở nơi khác, đệ tử các phái tranh đoạt linh dược nhưng chưa đổ máu, cuộc chém giết thật sự sẽ chờ đến ngày cuối. Hàn Lập gặp vận đỏ, hái linh dược khắp cấm địa gần như không tốn sức, hạ hai con Thiết tí viên rồi tiến đến thạch điện nhỏ gần đỉnh núi có Thiên Linh quả. Đến nơi, hắn nhận ra cô gái áo lục từng bán Kim Trúc bút cho mình đang dùng pháp khí đỉnh cấp liều chết chống hán tử Cự Kiếm môn thao túng cự kiếm bạc, cạnh đó xác cự lang và bạch điêu bị chém đôi. Dù bị dọa cùng kết cục, nàng vẫn quật cường đòi vài hạt Liệt Dương hoa, chết cũng không tránh ra."},{"chuong":201,"tieuDe":"Vũ Si","tomTat":"Đại hán chân trần của Cự kiếm môn nổi giận vì bị cô gái áo lục khiêu khích, xuất cự kiếm màu bạc chém nát pháp khí khăn lụa của cô rồi định giết tại chỗ. Khi ngân kiếm còn cách đầu cô gái một trượng, Hàn Lập từ sau tảng đá phóng kim nhận màu vàng ngăn cản, tạo màn kim quang bảo hộ rồi lộ diện, đề nghị đôi bên ngồi xuống nói chuyện dù đi ngược nguyên tắc bản thân. Cô gái áo lục nhận ra Hàn Lập là ân nhân cũ, hai người cùng sửng sốt. Đại hán không bận tâm lời hòa giải mà chăm chú nhìn kim nhận, đoán là đỉnh cấp pháp khí và tuyên bố nếu Hàn Lập thắng sẽ tha cô gái cùng cho toàn bộ linh dược trong thạch phòng. Hàn Lập giật mình hiểu ra người này chính là “Vũ Si” lừng danh trong tu chân giới. Trận đấu bắt đầu: đại hán vung ngân kiếm tấn công, Hàn Lập rung mẫu nhận thả bảy tử nhận hóa bảy đạo kim mang đón cự kiếm, cố ý không dùng phòng ngự phù lục mà dựa vào thân pháp biến ảo, bảy tử nhận như bảy con kim xà quần với cự mãng ngân kiếm."},{"chuong":202,"tieuDe":"Diệt Khẩu","tomTat":"Hàn Lập điều khiển bảy thanh kim nhận đấu với cự kiếm màu bạc của đại hán chân trần Cự kiếm môn, nhưng đại hán dùng pháp quyết xoay chuôi kiếm biến thành vùng sáng bạc có hấp lực, hút nghiền pháp khí khiến kim nhận thất thế. Hai thượng phẩm pháp khí phi đao màu lam và phi bạt màu vàng cùng một thanh kim nhận bị lốc xoáy nghiền nát, khiến Hàn Lập đau lòng vì kim nhận phải thành bộ. Hàn Lập lấy cái gương nhỏ đoạt từ nữ nhân nhiều bảo vật, rót linh lực chiếu ánh sáng xanh vây khốn ngân kiếm giữa không trung; đại hán kinh hãi nhận ra đó là Thanh Ngưng kính — hộ thân pháp khí của Yểm Nguyệt song kiều. Đại hán tố Hàn Lập giết Yểm Nguyệt song kiều và dọa rằng tổ mẫu song kiều là Trưởng lão Kết đan kỳ Yểm Nguyệt tông sẽ đuổi giết, còn Hàn Lập biện bạch vật lấy từ tay Phong Nhạc. Sau lời cô gái áo lục xui giữ bí mật, Hàn Lập và đại hán đồng thời khởi sát tâm; Hàn Lập tiến vào trong vòng mười trượng, thân biến mất rồi hiện sau lưng dùng ti tuyến chém đầu đại hán chết ngay. Vừa giết xong, cô gái áo lục hỏi Hàn Lập có định giết mình diệt khẩu với thanh âm đầy kinh hãi."},{"chuong":203,"tieuDe":"Vô Ưu Châm Dữ Vong Trần Đan","tomTat":"Sau khi giải quyết gã Cự kiếm môn, Hàn Lập thu túi trữ vật trên thi thể đại hán, đốt xác thành tro và thu lại Thanh ngưng kính cùng ngân kiếm, kim nhận vào túi trữ vật. Hắn trò chuyện với cô gái áo lục vừa được cứu, biết nàng tên Hạm Vân Chi, cảm thấy yêu mến như tiểu muội nhưng nàng khó xử không nói vì sao gia nhập Linh thú sơn tham gia Huyết sắc thí luyện. Khi đề nghị vào thạch ốc lấy linh dược và bảo nàng lấy Liệt Dương hoa trước, hắn bất ngờ vọt tới đánh một chưởng vào sau đầu khiến nàng hôn mê, rồi ôm nàng tới một sơn động thiên nhiên gần đó. Tại đây hắn lấy ra bộ ngân châm trong hộp bạc, hồi tưởng Mặc đại phu, Lịch Phi Vũ cùng quá khứ ở Thải hà sơn, Thần thủ cốc, rồi thi triển Vô ưu châm pháp kết hợp Vong Trần hoàn để xóa trí nhớ nửa ngày của nàng nhằm bảo vệ bí mật. Hạm Vân Chi tỉnh dậy vẻ mặt mờ mịt, cầm Liệt Dương hoa rồi vội chạy xuống núi, còn Hàn Lập thở dài đi vào rừng. Ngày thứ tư trong cấm địa gian nan vì tư liệu Hoàng phong cốc có chỗ sai và yêu thú nhiều hẳn, hắn đánh chết ba yêu thú bậc trung, hai bậc cao khiến thể lực pháp lực kiệt quệ. Cuối cùng hắn dựa vào tư liệu của Chung Ngô, phát hiện gần đó còn một nơi bí mật nhiều linh dược nên quyết định tới xem một chuyến."},{"chuong":204,"tieuDe":"Thạch Điện Dữ Địa Đạo","tomTat":"Hàn Lập theo tư liệu Chung Ngô đưa đến một vùng lòng chảo bị quái thạch vây quanh, giữa có tòa thạch điện cổ cửa nhỏ, bề mặt thanh quang lưu động cho thấy bị thi cấm chế; hắn nghi ngờ vì quanh đó không có dấu người tới. Ném kim nhận thử cấm chế thì bị bắn xa mấy trượng, định rời đi thì sắc mặt đại biến, thân hình chớp biến vào cửa điện rồi kẹt trong đại sảnh trống không. Cùng lúc, sư tổ trẻ tuổi của Yểm Nguyệt tông dẫn đám đệ tử tới, cảm ứng có người ở cửa điện nhưng phóng thần thức thì bị cấm chế bài xích — lần đầu gặp cấm chế mà thần thức không xuyên qua nên hưng phấn quyết tiến vào. Nghe tiếng bước chân, Hàn Lập cắn răng chui vào địa đạo dưới lan can ngọc thạch, dùng Nguyệt quang thạch soi đường lần xuống gần trăm mét tới một thế giới đầm lầy kỳ dị đầy bùn đen sủi bọt và gió nóng đối lưu. Giữa đầm có tiểu đình bạch ngọc treo lơ lửng một hộp vàng phi phàm, quanh biên là kỳ hoa linh thảo cùng linh dược hắn cần. Vì đám tu tiên đang đến, hắn bỏ ý lấy bảo vật, vọt ra sau mô đất thi triển Nặc hình thuật ẩn thân. Sư tổ Yểm Nguyệt tông hiện thân, biết Hắc lân mãng trong đầm đã nuốt mười mấy đệ tử các phái, liền tự tin tuyên bố dùng Âm dương khiên dẫn thuật đối phó cự mãng bậc một."},{"chuong":205,"tieuDe":"Quan Chiến","tomTat":"Cô gái sư tổ Yểm Nguyệt tông phân phó đệ tử, lẩm bẩm vật thật sự cần tìm nằm trong “cái hộp” còn những thứ trước chỉ là rác rưởi; đệ tử nam nữ nắm tay song tu phát hào quang lam hồng chuẩn bị đại chiến. Hàn Lập nấp sau đống đất, nghe xưng “sư tổ” liền cả kinh, hiểu người này tầm cỡ Kết đan kỳ như Lý sư tổ bổn môn, thắc mắc vì sao lại vào được cấm địa. Cô gái phun ra pháp bảo Chu tước hoàn biến lớn như phòng, tụ mấy trăm hỏa cầu; dùng Lan hoa pháp quyết phóng cột lửa vào cột bùn khổng lồ, khiến yêu thú lộ diện. Khi thấy rõ hình rắn lân giáp xanh đen phủ hắc vụ, cô thất thanh gọi “Mặc Giao” — không phải Hắc lân mãng như dự đoán — thần sắc vừa lo vừa mừng. Cô đọc ngũ tự ngôn quyết khiến Chu tước hoàn chụp giam thân yêu thú trong lửa đỏ, giục đệ tử động thủ. Nữ tử áo trắng dẫn dắt mười mấy cột sáng hồng lam công kích, đánh thủng hắc vụ để lộ lỗ máu to bằng bát; nhưng cô gái báo giữ không được Mặc Giao nữa, khiến cục diện đại chiến chưa ngã ngũ và mở cơ hội cho Hàn Lập trục lợi."},{"chuong":206,"tieuDe":"Ý Ngoại","tomTat":"Đệ tử Yểm Nguyệt tông dưới lệnh Nam Cung sư tổ dồn ép Mặc Giao trong Chu tước hoàn, nhưng yêu thú chịu đại thương nguyên khí lột da đào thoát rồi tiến hóa thành bậc hai, thân trắng mọc sừng đen và móng vuốt, thực lực ngang tu sĩ Trúc cơ bậc trung. Mặc Giao phun chất lỏng tím giết tan chảy năm sáu đệ tử ỷ pháp khí không trốn, để lại hố sâu mấy trượng. Nam Cung sư tổ dùng Kim ti phù vây khốn yêu thú rồi định chạy, nhưng Triệu sư muội (tự xưng Yểm Nguyệt song kiều) dán Tiểu ngũ hành phù ở lối vào khiến thông đạo bị phong bế, vô tình nhốt luôn sư tổ và Hàn Lập bên trong. Hàn Lập vốn ẩn nấp xem kịch, nhận ra mình cũng không thoát được nên bất đắc dĩ ra tay cứu cô gái lúc nàng kiệt sức, dùng bảy kim nhận và Phi thiên thuẫn phòng độc. Hắn thành thật nói sợ nàng giết người đoạt bảo nên thỏa thuận liên thủ không chừa đường lui, đồng thời tự tin nàng pháp lực giảm không hại được mình. Cuối cùng Nam Cung sư tổ dùng chút pháp lực cuối cùng đưa Chu tước hoàn giữ chặt Mặc Giao, còn Hàn Lập thu thuẫn lấy ra Kim quang chuyên phù bảo, khoanh chân ngồi xuống chuẩn bị."},{"chuong":207,"tieuDe":"Đồ Giao Dữ Chiến Lợi Phẩm","tomTat":"Hàn Lập khu sử kim quang chuyên phù bảo cho nó hấp thu một phần ba pháp lực rồi hóa lớn như núi nhỏ đập xuống Mặc Giao. Mặc Giao phun dung dịch tím chặn lại, nhưng cô gái ném viên châu vàng nổ thành khói vàng bao đầu yêu thú khiến nó ngừng phun, kim chuyên liền hạ xuống đánh nát nửa đầu Mặc Giao. Cô gái dùng bình thủy tinh bắn hắc khí kéo nguyên thần Mặc Giao (hình ảnh nhỏ màu xanh) thu vào bình, mặt mày hớn hở. Cô thu Chu tước hoàn, nhường thi thể yêu thú cho Hàn Lập vì hai người hợp lực giết. Hàn Lập lấy cự kiếm bạc (ngân kiếm) chém phá được phòng ngự thân Mặc Giao ba tấc khiến cô kinh ngạc; cô phân tích kiếm chế bằng ngân tinh do tu sĩ Kết đan kỳ luyện, tà môn nên Hàn Lập không khu sử được. Cô giải thích toàn thân Mặc Giao là tài liệu quý nhưng tiếc chưa tiến hóa bậc ba nên không có nội giao đan. Bất ngờ Hàn Lập moi từ bụng yêu thú ra viên cầu đỏ; cô gái nghi ngờ vì bậc hai thủy thuộc tính không thể có giao đan đỏ, và khi vuốt nhẹ, viên cầu tự nổ phun sương khói màu hồng bao trùm cả hai người."},{"chuong":208,"tieuDe":"Hợp Hoan","tomTat":"Hàn Lập tỉnh khỏi cơn xuân mộng ôn nhu, phát hiện mình trần trụi ôm chặt một nữ tử tuyệt sắc chừng mười tám mười chín tuổi cũng không mặc gì, gương mặt vừa lạ vừa quen. Nữ tử vừa cử động thì đau đớn ngã lại vào lòng hắn, hai người tiếp tục hoan hợp — đây là lần đầu Hàn Lập thân mật với nữ tử. Sau đó cả hai mặc lại y phục, nữ tử lấy bộ quần áo trắng như tuyết từ túi trữ vật, khí chất trở nên ung dung cao quý, buộc Hàn Lập coi chuyện vừa rồi là một sai lầm và dọa sẽ giết nếu người thứ ba biết. Nữ tử giải thích viên cầu gây chuyện là túi dâm nang của Mặc Giao — thực ra là Hùng Giao hiếm thấy — chạm phải sẽ nổ ra thôi tình khí, và tiết lộ hình dáng biến hình của mình là do luyện độc môn Tố nữ luân hồi công đã đại thành, bị phá thân chỉ tổn thất năm sáu năm pháp lực. Nàng oán khí vì tư chất tầm thường của hắn mà lại có duyên phu thê với mình, song không nỡ giết. Nữ tử trấn an Hàn Lập rằng cả hai chỉ hôn mê năm sáu canh giờ, rồi thu hộp vàng phía trước và để hắn tự hái hơn mười gốc linh dược. Cuối cùng nàng tuyên bố muốn phá cấm rời đi phải hai người hợp lực, thiếu một người thì không thể rời khỏi nơi đây."},{"chuong":209,"tieuDe":"Hồi Quy","tomTat":"Trong thạch điện, đệ tử Yểm Nguyệt tông phá đá cứu sư tổ vô ích; một tiếng nổ khiến hố lớn xuất hiện trước cửa điện và nữ tử tuyệt sắc áo trắng — sư tổ nay lớn hơn một chút — bước ra, lạnh lùng ra lệnh xuất phát. Hàn Lập trở lại mặt đất với pháp lực mượn tầng mười ba (đỉnh Luyện khí kỳ) do nữ tử dùng Tố nữ luân hồi công truyền, chỉ duy trì vài canh giờ. Hai người trước đó dùng Chu tước hoàn và Kim quang chuyên phù bảo đánh thông đường hầm thoát khỏi đầm lầy lòng đất, khiến phù bảo của Hàn Lập hao hết uy năng thành phế vật còn nữ tử tổn hao hai ba chục năm công lực. Hàn Lập biết tên nàng là Nam Cung Uyển khi hỏi phương danh lúc chia tay, ảm đạm vì địa vị chênh lệch. Trên đường ra hắn giết một đệ tử Linh thú sơn đoạt túi trữ vật, rồi dùng thế sét đánh liên tiếp giết mấy người ra khỏi cấm địa an toàn. Đến ngày thứ năm, bảy tu sĩ Kết đan kỳ phá cấm mở thông đạo, đệ tử các phái lần lượt ra nhưng riêng Yểm Nguyệt tông không một ai xuất hiện, khiến Khung lão quái và Nghê Thường tiên tử lo lắng còn Lý sư tổ âm thầm mừng. Hoàng phong cốc có năm người sống sót nhiều nhất các phái; huynh muội Trần thị khinh bỉ Hàn Lập vì tưởng hắn nhát gan trốn tránh, còn hắn cuối chương lại lo lắng cho Nam Cung Uyển khi người Yểm Nguyệt tông chưa tới."},{"chuong":210,"tieuDe":"Đổ Cục","tomTat":"Gần thời điểm thông đạo cấm địa đóng, Hàn Lập nhìn thấy Hạm Vân Chi của Linh thú sơn an toàn nên thở phào. Nam Cung Uyển cầm đầu đội đệ tử Yểm Nguyệt tông ra khỏi cấm địa, lộ khuôn mặt kiều diễm khiến các tu sĩ Kết đan kỳ mới biết nữ tử trẻ đẹp này chính là Nam Cung tiên tử; Nghê Thường tiến lên quan tâm hỏi thăm. Lão hoạt đầu Hướng Chi Lễ chạy ra phút chót thì thông đạo chấn động, vỡ vụn biến mất, ai chưa ra coi như tử lộ. Cự kiếm môn trào phúng Hoàng phong cốc vì đệ tử ra ít; Khung lão quái ỷ già giục Lý sư tổ mau xem kết quả đánh cuộc. Đổ cục bắt đầu: đạo sĩ Thanh Hư môn thu hoạch áp đảo với các linh dược quý như Huyết lan, Thiên linh quả, Ngọc tủy chi, còn đạo sĩ đầu bạc cuối cùng ra bảy gốc khiến Lý sư tổ sắc mặt xanh. Đến lượt Hàn Lập, mọi người thản nhiên bỏ qua, nhưng vì linh thú ngửi mùi khiến không thể giấu, Hàn Lập đổ ra hơn hai mươi gốc linh dược đủ màu phủ khắp mặt đất, lật ngược cục diện."},{"chuong":211,"tieuDe":"Doanh Gia","tomTat":"Trận đánh cuộc thu linh dược ở cấm địa kết thúc: lượng lớn linh dược dưới chân Hàn Lập khiến Lý sư tổ mừng rỡ, còn Phù Vân Tử của Thanh Hư môn thua cược nên sắc mặt xanh, định gây khó dễ Hàn Lập nhưng bị Lý sư tổ chặn lại. Yểm Nguyệt tông lật ngược thế cờ khi mấy đệ tử phía sau bỗng giao linh dược nhiều hơn hẳn, giúp Khung lão quái thắng cả hai cuộc cược với Thanh Hư môn và Hoàng phong cốc. Phù Vân Tử miễn cưỡng giao nội đan Huyết tuyến giao còn bị chê chất lượng, tức giận rời đi; Lý sư tổ chủ động hứa trong hai mươi năm sẽ đưa hai khối thiết tinh. Các phái thu linh dược rồi lần lượt cáo từ: Yểm Nguyệt tông lên Thiên nguyệt thần chu rời trước với Nam Cung Uyển không nhìn Hàn Lập lần nào, còn Hạm Vân Chi của Linh thú sơn cười thiện ý khiến hắn lo lắng. Sau khi chỉ còn Hoàng phong cốc, Lý sư tổ tra hỏi Hàn Lập về quá trình tìm thuốc, và hắn bịa chuyện trai cò tương tranh ngư ông đắc lợi khiến sư tổ tin là hắn may mắn. Cuối cùng Lý sư tổ tuyên bố muốn trọng thưởng, đề nghị thu Hàn Lập làm ký danh đệ tử môn hạ, khiến cả cốc chấn động vì tư chất và công pháp của hắn đều bình thường."},{"chuong":212,"tieuDe":"Hoảng Nhiên","tomTat":"Được Lý sư tổ ngỏ lời thu làm đệ tử, Hàn Lập không mừng mà theo bản năng thấy bất ổn vì chuyện tốt như vậy khó tự nhiên rơi vào đầu hắn. Khi Lý sư tổ tỏ ý khó chịu, Hàn Lập nhận ra cự tuyệt một tu sĩ Kết đan kỳ sẽ chuốc hậu quả nên đóng kịch cao hứng và hành đại lễ bái sư, được lão tự xưng tên Lý Hoa Nguyên (có chỗ ghi Lý Hóa Nguyên) tặng pháp khí Bích quang đao làm lễ gặp mặt cùng lời hứa thu làm đệ tử chính thức nếu Trúc cơ thành công. Đoàn cưỡi Ngân giáp giác mãng bay mấy ngày về Hoàng phong cốc, Lý sư tổ dẫn hai quản sự vào Nghị sự điện. Tại nhà cỏ Bách thảo viên, Mã sư bá kinh ngạc trước việc Hàn Lập không chết còn được thu ký danh đệ tử, rồi tiết lộ hắn chỉ nhận được một viên Trúc cơ đan thay vì hai do quy củ cho phép sư phụ lấy nửa cống phẩm làm lễ tạ sư. Hàn Lập bề ngoài trầm ngâm khiến Mã sư bá tưởng hắn oán khí, nhưng thực ra thầm thở phào vì sắp khai lò tự luyện đan nên xem nhẹ đan dược mà quý chỗ chống lưng của Lý sư thúc. Cuối chương, hắn ghi nhận Mã sư bá là người ngoài lạnh trong nóng đáng thâm giao và được trả lại Bách dược viên để trông coi."},{"chuong":213,"tieuDe":"Chuẩn Bị","tomTat":"Sau chuyến cấm địa hơn mười ngày, Hàn Lập trở về Bách dược viên nghỉ ngơi rồi lập kế hoạch trồng linh dược và dành ba năm chuẩn bị luyện Trúc cơ đan. Hắn kiểm kê chiến lợi phẩm gồm hơn mười khối linh thạch bậc trung, nhiều linh khí, tài liệu, một ngân kiếm phế vật cùng hai vật đặc biệt: con rối cung thủ thượng phẩm cần bí thuật phân thần mới khu sử được, và một tờ giấy màu bạc hoa văn kỳ lạ chưa giải mã. Chiều ngày thứ tư, Vương sư thúc cùng một quản sự mang đến một viên Trúc cơ đan phần thưởng nhưng chiết khấu qua lời “tận hiếu kính sư phụ”; Hàn Lập ngoài mặt không ý kiến, cất đan chờ tự luyện được rồi phục dùng đồng loạt. Ba năm trôi qua với nhiều biến cố: Trần sư muội phục đan và Trúc cơ thành công, huynh trưởng nàng ăn hai viên vẫn trùng quan thất bại rồi rời sư môn; thanh danh Hàn Lập bay cao nhờ danh nghĩa ký danh đệ tử Lý sư tổ, khiến Diệp Tính lão giả trả đủ đồ đã ăn bớt. Sư phụ mới Lý Hóa Nguyên chỉ phái người đưa quyển “Thanh nguyên kiếm quyết” có bút tích rồi bặt tin ba năm. Chuẩn bị xong, Hàn Lập đến Nhạc lộc điện, khua chuông linh đánh thức đại hán ngốc nghếch giữ địa hỏa, mượn danh Lý Hóa Nguyên và trưng bút tích khiến đại hán cung kính an bài gian địa hỏa, đưa trước một khối linh thạch bậc trung làm tiền đặt cọc."},{"chuong":214,"tieuDe":"Địa Hỏa Chi Ốc","tomTat":"Hàn Lập đưa một khối linh thạch bậc trung thuộc tính hỏa cho một đại hán ngốc nghếch để nhờ an bài chỗ luyện đan; đại hán vui vẻ dùng lệnh tiễn màu tím mở cửa ổ thạch đạo và dẫn hắn vào khu Địa Hỏa Chi Ốc. Trên đường, đại hán giới thiệu đặc tính ổ thạch chịu nhiệt cao không sợ địa hỏa, và cho biết Việt quốc phải nhập ổ thạch từ các nước phía cực tây. Hai người tới một đại sảnh hình tròn khổng lồ quây ba mươi sáu gian địa hỏa; vì gian mười tám đã bị một sư bá chiếm, Hàn Lập được cấp gian mười chín. Đại hán mở cửa phòng, chỉ cho hắn bếp lò ổ thạch khảm tám đầu rồng làm địa hỏa khẩu, các hồ lô hỏa tinh, rồi giao ngọc bài trắng và giải thích rằng khi đóng cửa phòng sẽ phong bế tuyệt với ngoại giới. Sau khi đại hán rời đi, Hàn Lập nghiên cứu bếp lò, đánh tám đạo hồng quang khu sử tám đầu rồng và luyện tập điều khiển địa hỏa tới thuần thục. Cuối cùng hắn dùng Phiêu phù thuật treo Ngân ti đỉnh trên bếp lò, hong nóng đỉnh rồi lần lượt đổ hơn mười loại bột linh dược vào và đóng nắp, hoàn tất bước đầu tiên trong việc luyện chế Trúc cơ đan."},{"chuong":215,"tieuDe":"Luyện Đan Dữ Trúc Cơ","tomTat":"Hàn Lập thao túng địa hỏa, điều khiển Ngân ti đỉnh để luyện Trúc cơ đan nhưng khoảng hai mươi lần đầu đều thất bại, chỉ thu được phế đan màu lam nhạt cất vào hộp ngọc. Thời gian trôi qua nửa năm, đại hán giữ phòng địa hỏa từ vui vì thu phí chuyển sang lo lắng bất an khi hắn không chịu ra ngoài. Gần lúc định bỏ cuộc đi tìm Luyện đan sư học hỏi, Hàn Lập khai đỉnh thêm một lần liền ngưng đan thành công, luyện ra viên Trúc cơ đan đầu tiên rồi thu về hơn hai chục viên vượt xa dự tính. Hắn nghi mình có luyện đan thiên phú, được giải thích rằng thành công là nhờ nửa năm luyện liên tục cùng một loại đan không gián đoạn. Sau đó hắn nảy ý dùng Trúc cơ đan bế quan phá ải ngay trong phòng địa hỏa, khiến đại hán ngơ ngác lo sợ Lý sư tổ trút giận. Cuối cùng cửa đá bạch quang lóe lên, Hàn Lập xuất quan sau gần một năm với thân phận tu sĩ Trúc cơ kỳ, phát uy áp buộc đại hán lui lại và được đổi xưng hô từ “sư đệ” thành “sư thúc”."},{"chuong":216,"tieuDe":"Dược Lực","tomTat":"Hàn Lập rời khỏi đại hán tu sĩ ở Nhạc Lộc điện — người này than mình dùng nhiều đan dược phụ trợ vẫn không trùng quan được, cho rằng Hàn Lập tư chất khác thường vì được Lý sư tổ thu làm đệ tử. Ra khỏi Truyền tống trận, Hàn Lập giá ngự pháp khí bay đi và hồi tưởng quá trình Trúc Cơ vài tháng trước. Trong phòng địa hỏa, hắn dùng viên Trúc cơ đan đầu tiên và trải qua cơn thống khổ dữ dội: đan điền như bị liệt hỏa thiêu, đau như dao đâm rồi ngứa như kiến bò, thân phủ chất xám do tẩy tủy dịch cân. Nhận ra cần cải thiện thể chất nhiều lần, hắn dùng liên tiếp các viên đan, pháp lực tăng lên đỉnh điểm Luyện khí kỳ và chân nguyên dần chuyển hóa từ khí sang dịch thể. Đến viên thứ tám, dược lực bùng nổ khiến hắn hôn mê và trong lúc đó đã trùng quan thành công, tiến nhập Trúc cơ kỳ. Tuy nhiên dược tính tám viên đan còn sót tràn ngập toàn thân rất nguy hiểm, buộc hắn phải lấy Thanh nguyên kiếm quyết vốn coi là đồ rác ra tu luyện để hấp thu — kiếm quyết chín tầng, mỗi ba tầng mở một thần thông."},{"chuong":217,"tieuDe":"Kiếm Quyết","tomTat":"Ba tầng kiếm quyết cuối của Thanh nguyên kiếm quyết cho ra thần thông Kiếm ảnh phân quang thuật, có thể huyễn hóa kiếm ảnh giống hệt phi kiếm để mê hoặc địch nhân. Hàn Lập tuy nghi ngờ vì không thấy tu sĩ Trúc cơ kỳ nào của Hoàng phong cốc thâm luyện kiếm quyết này, vẫn liều mình luyện thử theo pháp môn hấp thụ dược lực đang phát tác; nhờ dược lực còn sót quá mạnh hắn bất ngờ luyện lên tầng thứ tư, phóng ra kiếm quang từ một thước dài tới hơn một trượng. Vì hiếu kỳ, hắn học và luyện thành hộ thể kiếm thuẫn màu xanh nước biển nhô mũi nhọn như con nhím, có thể tự động phóng kiếm quang phản kích. Rời phòng địa hỏa và bị đại hán ngốc nghếch kinh ngạc nhìn, hắn về Bách dược viên gặp lão nhân trông coi. Lão nhân cảm ứng được cảnh giới mới, kinh ngạc trước việc hắn Trúc Cơ thành công, rồi đề nghị bỏ cách xưng sư bá để cùng xưng sư huynh đệ. Hàn Lập che giấu quá trình Trúc Cơ thật, khai giả rằng thuê địa hỏa ở Nhạc lộc điện rồi bế quan gần một năm. Cuối cùng lão nhân khuyên hắn gặp Chung chưởng môn hưởng đãi ngộ đệ tử Trúc cơ kỳ và tiết lộ Thanh nguyên kiếm quyết vốn là tuyệt học trấn phái của Huyền kiếm môn bị diệt, thực có mười ba tầng, bản Hoàng phong cốc lưu truyền chỉ là bản thiếu."},{"chuong":218,"tieuDe":"Khuyết Hãm Dữ Ưu Thế","tomTat":"Mã sư huynh (tiểu lão nhân coi dược viên) tiếp tục giảng cho Hàn Lập khuyết điểm chí mạng của Thanh nguyên kiếm quyết: từ tầng bốn trở đi, pháp lực mới luyện sẽ tự tiêu tán một phần, tầng bốn mất một phần mười, tầng năm hai phần, tầng sáu ba phần, cứ mỗi tầng tăng thêm một phần mười. Vì tổn thất khủng khiếp cộng với công pháp Kết đan kỳ khó tinh tiến và bản kiếm quyết bị hư hại không đầy đủ, đệ tử bổn môn xưa cao nhất chỉ tới tầng sáu, còn thường chỉ tu ba tầng đầu để dùng thần thông kiếm quang làm trợ pháp. Hàn Lập chấn động vì đã tu tới tầng bốn nên quyết định ngừng tu ngay tại đây, dù Mã sư huynh sau đó tiết lộ ưu điểm bù trừ là mỗi tầng luyện thành làm đan điền thâm thúy, pháp lực thâm hậu hơn cùng cấp gần một phần ba. Hàn Lập vẫn giữ vững quyết định để dành đường Kết Đan, tin rằng dùng công pháp bình thường cùng linh đan phối xứng thì Kết Đan không phải bất khả. Sau đó hắn thu dọn rời dược viên, tới Nghị sự điện bàn việc và dự định mở động phủ riêng, được hai đệ tử gác cửa cung kính gọi “sư thúc” nhờ thân phận Trúc cơ kỳ. Chờ ở phòng khách, Hàn Lập cảm khái về đệ tử cấp thấp và nhớ lại năm xưa từng dùng một viên Trúc cơ đan mua chuộc Diệp Tính lão giả. Khi Chung Linh Đạo trở về, chưởng môn thấy tên quen nhưng không nhận ra hắn, đành dùng lời hàm hồ che đậy sự xấu hổ."},{"chuong":219,"tieuDe":"Hội Đàm","tomTat":"Hàn Lập đến Nghị sự điện gặp Chung chưởng môn, trực tiếp báo mình vừa Trúc Cơ thành công và xin quyền khai mở động phủ. Chung Linh Đạo kinh ngạc vì Hàn Lập mang ngụy linh căn bốn thuộc tính mà vẫn Trúc Cơ được, chuyện gần như bất khả. Khi truy nguồn gốc viên Trúc cơ đan, Hàn Lập tiết lộ mình chính là một trong ba người sống sót đi ra từ cấm địa và là đệ tử ký danh mà Lý sư tổ thu nhận, khiến chưởng môn đổi sắc và chuyển sang hậu đãi vì không muốn kết oán với đệ tử tương lai của Lý sư thúc. Chung Linh Đạo dùng bút cán vàng điền tên Hàn Lập vào ngọc điệp trắng, giao ba khối linh thạch bậc trung, một lá Mê tung kỳ và một ngọc giản chứa thủ pháp bày trận cùng điều chú ý sau Trúc Cơ. Sau khi cáo từ và xem ngọc giản giữa đường, Hàn Lập đổi hướng đến Kỳ lân các để thuê Song đồng thử, loài yêu thú có mắt thần nhìn thấu sương mù và thích đào tổ nơi nhiều linh khí, làm trợ thủ tìm nơi lập động phủ. Một nữ đệ tử trẻ ở Nghênh khách đài ra tiếp đón và vui vẻ đồng ý đưa cho hắn một con."},{"chuong":220,"tieuDe":"Linh Nhãn Chi Tuyền","tomTat":"Hàn Lập tới Nghênh khách đài trên Linh thú sơn của Kỳ lân các, thuê một con Song đồng thử với giá ba khối linh thạch cấp thấp cho ba ngày, nhận thêm túi thổ lê con thú thích ăn rồi ngự khí bay đi hướng Tây Bắc. Trên đường hắn nhận ra con thú vàng đáng yêu này thực chất là yêu thú cấp một bậc trung có răng cứng như đồng thiết và tiền trảo động kim xuyên thạch, nảy ý muốn tự nuôi một con. Bay liền một ngày, hắn chọn khu hoang lương phía Tây Bắc ngoài Thái nhạc sơn mạch — giáp Nguyên Vũ quốc và gần Khê châu — làm nơi khai mở động phủ vì ít người tu tiên quấy rầy và gần phường thị Thiên tinh tông tiện mua bán. Buộc dây thừng theo Song đồng thử, hắn bị con thú dẫn tới một vách núi cao hơn trăm trượng, dùng cự kiếm màu bạc và hộ tráo thủy thuộc tính khoét đường đá dài mười trượng rồi phá vách. Vào trong một động nham thạch linh khí nồng đậm, hắn phát hiện một nguồn suối phun nước không ngừng nơi con thú bơi lội. Kiểm tra kỹ, Hàn Lập khẳng định đây là Linh nhãn chi tuyền hiếm thấy thế gian — một dạng linh nhãn thực thể hóa có thể tăng tốc tu luyện và di chuyển pháp lực không hao tổn, một bước ngoặt lớn về tài nguyên tu luyện của hắn."},{"chuong":221,"tieuDe":"Thiên Tinh Tông Dữ Pháp Trận","tomTat":"Chương mở đầu bằng bối cảnh linh nhãn chi vật — bảo vật quý khiến các môn phái tranh đoạt điên cuồng, tại Việt quốc đã rơi hết vào tay thất đại phái; Hoàng Phong Cốc từng sở hữu nhiều nhưng bị các tu sĩ Kết đan kỳ và lão tổ Nguyên Anh kỳ chia hết, Chung đại chưởng môn không được món nào. Hàn Lập nhờ dẫn theo một con Song Đồng Thử mà tình cờ tìm được một linh nhãn chi tuyền nhất cấp ở phụ cận đỉnh núi, giúp tăng tốc tu luyện hơn nửa thành. Hắn quyết biến nham động linh tuyền thành mật thất luyện công bí mật, dùng ngân kiếm và kim nhận đào mười ba phòng cùng một đại sảnh, rồi thả Song Đồng Thử để nó tự về Kỳ Lân các. Hàn Lập bố trí một tiểu mê tung trận bằng năm lá cờ và mười viên linh thạch che dấu toàn bộ lối ra vào, lập dược viên bí mật và gắn Nguyệt quang thạch chiếu sáng. Nhận thấy học trận đạo mất hai mươi năm sẽ làm chậm hy vọng lên Kết đan kỳ, hắn chọn mua trận kỳ trận bàn thay thế và dùng lục dịch tạo một gốc linh dược ngàn năm sau hai tháng để trao đổi. Mang theo xác Ngô Công và Mặc Giao, hắn ngự khí bay về phương bắc tới Nguyên Vũ Quốc, nơi Thiên Tinh Tông là hạch tâm chính phái. Đến gần phường thị, pháp khí hình lá mất khả năng phi hành do cấm pháp cấm phi hành, và Hàn Lập bước vào khảo sát Tinh Trần Các cùng các gian luyện khí, chế phù và Linh thú viện."},{"chuong":222,"tieuDe":"Luyện Khí Cao Thủ","tomTat":"Hàn Lập đến một phường thị nhỏ tiêu điều với chỉ khoảng ba mươi người tu tiên, phần lớn tập trung về phía Tinh Trần Các, nhưng hắn chưa vội tới đó. Bị thu hút bởi chiêu bài cam kết luyện khí thất bại trả lại bằng linh thạch, hắn bước vào gian hàng luyện khí nhỏ của Từ lão giả, nơi có tráng hán Tiểu Hắc tiếp đón cùng nho sinh Vương Tử Lăng đang thảo luận với chủ tiệm. Khi Hàn Lập đòi xem đỉnh cấp pháp khí tinh phẩm, cả tiệm kinh ngạc vì loại pháp khí này giá vài trăm linh thạch, người thường cả đời khó mua nổi. Từ lão giả nhận ra hắn là tu sĩ Trúc Cơ kỳ liền cuống quýt quát Tiểu Hắc lui vào và tự xưng chủ điếm, xấu hổ thừa nhận tiệm không có tinh phẩm. Lão giả tiết lộ Từ gia nhờ ngẫu nhiên có một con hỏa nha nên phun được yêu hỏa lợi hại, dùng bí thuật bàng môn tả đạo này để luyện chế đỉnh cấp pháp khí dù chỉ là cao thủ Luyện Khí kỳ. Hàn Lập quyết định giao tài liệu cho lão luyện chế với điều kiện hắn đứng bên theo dõi và để lại một phần nguyên liệu làm thù lao nếu thành công. Trước khi rời tiệm để mua thêm đồ, hắn từ chối lời chào mời làm môi giới của Vương Tử Lăng, khẳng định chỉ Tinh Trần Các mới có loại trận kỳ, trận bàn tốt nhất."},{"chuong":223,"tieuDe":"Bí Điếm, Cạnh Mại Hội","tomTat":"Nghe Hàn Lập muốn tìm trận kỳ trận bàn tốt, nho sinh Vương Tử Lăng giải thích Tinh Trần Các chỉ có hàng của gia tộc và tán tu bình thường, còn Thiên Tinh Tông tuyệt không mang tinh phẩm chính thức ra ngoài vì căn cơ dựa vào một đạo trận pháp. Nho sinh hạ giọng đề nghị dẫn Hàn Lập đến một bí điếm ngầm bán tinh phẩm, mở một lần mỗi tháng và cách phường thị một dặm; Hàn Lập đồng ý theo đi. Qua bảy căn nhà và tám lần rẽ, họ đến một gian hàng nhỏ do Trương phu nhân coi giữ, nho sinh bàn giao khách rồi xấu hổ cáo từ. Trương phu nhân đóng cửa, ấn tay xuống góc phòng mở ra động ngầm, dẫn Hàn Lập theo địa đạo mười trượng tới cửa đá có hai hắc y hộ vệ Trúc cơ kỳ, khiến hắn kinh hãi và kiêng kị thực lực bí điếm. Vào đại sảnh tròn xa hoa, Hàn Lập toát mồ hôi khi thấy hơn nửa tu sĩ đều từ Trúc cơ kỳ trở lên, hiểu ở đây mình chỉ là người bình thường. Sau khi đợi, ba người che mặt bước ra công bố quy củ: điếm ra giá trước, khách đấu giá tự do, thiếu linh thạch có thể dùng vật phẩm thay. Cuối cùng một trung niên nam tử cao gầy bước ra giới thiệu vật đầu tiên là pháp khí Hỏa Vân Kiếm, mở màn chuỗi đấu giá."},{"chuong":224,"tieuDe":"Khôi Lỗi Ky Quan Thú","tomTat":"Phiên đấu giá tại bí điếm tiếp diễn: vật phẩm đầu là Hỏa Vân kiếm, một đỉnh cấp pháp khí mang hỏa vân công kích, tăng từ hai trăm lên bốn trăm linh thạch và được tu sĩ đeo mặt nạ trẻ con mua về. Kế đến là Hồng La Thiên lô, đan lô đỉnh cấp từng luyện ra nhiều tinh phẩm pháp khí như Huyễn Âm kiếm, Thanh Giao kỳ, Hắc Viêm châu; Hàn Lập kinh ngạc vì Thanh Giao kỳ của mình cũng xuất từ lô này, còn cuộc tranh giá gay gắt kết thúc khi một nữ tu sĩ Trúc Cơ kỳ cố ý hơn đúng một khối để thắng nam tử mập mạp đội mũ vàng với tám trăm năm mươi mốt linh thạch. Sau hai mươi vật phẩm vẫn chưa thấy trận kỳ, trận bàn, Hàn Lập sốt ruột định quay lại Tinh Trần các. Nam tử cao gầy tiếp tục rao bán một cặp khôi lỗi cơ quan thú thượng cấp, thực lực ngang tu sĩ Luyện Khí kỳ tầng chín, khiến Hàn Lập rung động vì liên tưởng tới khôi lỗi cung thủ của mình. Nam tử giới thiệu khôi lỗi cơ quan thuật là đạo pháp luyện chế của vùng đất cực tây, có Thiên Trúc giáo khai môn lập phái. Một quái nhân trùm bao vải xám và một người khôi ngô đội mũ xanh biếc đẩy giá bất thường tới mức khó tin, khiến cả sảnh nghi cặp thú ẩn tàng bí mật; cuối cùng người khôi ngô lôi ra món đồ trị giá mấy ngàn linh thạch, ra chín trăm linh thạch kèm bảo vật rồi bước tới trước bàn đòi giao khôi lỗi thú ngay."},{"chuong":225,"tieuDe":"Thiết Tinh, Linh Dược","tomTat":"Tại buổi đấu giá kín của bí điếm, một hán tử khôi ngô đầu đội đấu bồng móc ra khối màu đen mờ như đồng thiết để bán; nam tử cao gầy chủ trì ban đầu xem thường và uy hiếp hắn, nhưng hán tử thấy quái nhân trùm đầu đối lập hả hê nên nén giận quay về chỗ. Ba hắc y nhân ngồi ghế đàn mộc tra xét thận trọng rồi tuyên bố đó là thiết tinh thượng phẩm trị giá hai ngàn linh thạch, khiến cả sảnh chấn động vì chỉ đan hỏa Kết Đan kỳ mới luyện ra nguyên liệu pháp bảo này, không ai dám hô thêm giá. Hán tử khôi ngô thắng được đôi khôi lỗi thú với hơn hai ngàn linh thạch nhưng định rời đi thì cửa đá đã đóng, bị giữ lại theo quy củ giữ khách của bí điếm, rồi đổi thái độ ngông nghênh ngồi chờ. Cuối buổi, nam tử cao gầy đưa ra hộp ngọc xanh biếc chứa gốc Hoàng Tinh chi ngàn năm — linh dược đỉnh cấp gần trăm năm mới hiện thế vài lần — với giá khởi điểm năm trăm linh thạch; dược hương tràn ngập đại sảnh, các tu sĩ tranh nhau hô giá vượt hai ngàn linh thạch. Hàn Lập ngồi xem liền nhận ra gốc Hoàng Tinh chi này chính là một trong hai gốc do chính hắn nuôi dưỡng và từng bán cho Vạn Bảo lâu, thầm tự đắc vì vật do tay mình làm ra khiến người khác khẩn trương như vậy."},{"chuong":226,"tieuDe":"Điên Đảo Ngũ Hành Trận","tomTat":"Trong buổi đấu giá mật điếm, một thanh niên đeo mặt nạ đầu hổ bất ngờ đề nghị dùng khí cụ của kỳ trận trứ danh Điên Đảo Ngũ Hành Trận để đổi thiên niên linh thảo, khiến cả trường lặng đi vì danh tiếng trận pháp. Kỳ trận này còn gọi Tiểu Cấm Đoạn Chi Trận, tuy bao phủ nhỏ và không chủ động giết địch nhưng công hiệu ảo hóa, yểm hộ sơn môn, mê hoặc vây khốn không thua đại trận hộ phái. Khi lộ ra bộ khí cụ chỉ là tàn phẩm phát huy một phần mười uy lực, các tu sĩ thất vọng và nam tử cao gầy chủ trì cứng rắn đuổi khéo thanh niên. Thiên niên dược thảo cuối cùng về tay một tu sĩ Trúc Cơ kỳ ra giá hai ngàn linh thạch cộng một Huyễn Nguyệt Thạch, rồi chuyển sang giao dịch tự do. Hàn Lập ghi nhớ ngoại hình thanh niên, sau đó tiếp cận và bố trí Cách âm trạo để nói chuyện riêng, dùng thành thục nhờ đã Trúc Cơ. Hắn lấy ra thiên niên Tử Quế Hoa nhưng không mở hộp ngay, ép thanh niên nói rõ dùng vật gì trao đổi để moi nhiều lợi ích hơn, khiến đối phương bối rối ấp úng."},{"chuong":227,"tieuDe":"Kết Giao Chi Tâm","tomTat":"Một thanh niên vừa thấp vừa thô ngập ngừng ngỏ ý bán cho Hàn Lập những hiểu biết về luyện khí, nói do vướng tổ huấn chỉ có thể giao lại chứ không đích thân truyền thụ. Hắn tiết lộ gia tổ từng là Luyện khí trưởng lão của Thần Binh Môn, một trong Nguyên Vũ Quốc tam đại chánh phái ngang hàng Thiên Tinh Tông và Vạn Diệu Quan, khiến Hàn Lập động dung. Hàn Lập giữ chặt hộp thiên niên linh dược đòi giao hàng trước, thanh niên luống cuống lấy ra 18 miếng trận bàn, 36 cây trận kỳ, một Ngọc Giản và quyển Vân Tiêu Tâm Thuật, rồi xưng tên thật là Tề Vân Tiêu. Hàn Lập dùng phong ấn thuật khóa quyển sách hóa thành bạc cứng, hẹn năm năm không động và sẽ trả nguyên vẹn nếu bằng hữu trận pháp của Tề Vân Tiêu cải tiến pháp khí thành công, ý đồ kết giao lâu dài. Rời đi với tâm trạng tốt, Hàn Lập về cửa hiệu Luyện khí bán vỏ cứng ngô công cho lão giả tóc bạc, được lão nhận định là tài liệu luyện khí thượng cấp hiếm có thể vươn tới đỉnh cấp pháp khí. Khi lão định cầm đi thì bị Hàn Lập chặn vì còn tài liệu khác chưa lấy ra, thái độ nóng nảy của lão khiến Hàn Lập bắt đầu hoài nghi mình đã tìm nhầm Luyện khí sư."},{"chuong":228,"tieuDe":"Khôi Lỗi Và Tu Sĩ","tomTat":"Hàn Lập bày thêm tài liệu giao long (da, sừng, răng nanh, nhãn châu) lấy từ thân Mặc Giao ra bàn để thử trình độ chủ tiệm luyện khí đầu bạc họ Từ; lão già kinh ngạc phun trà, nhận ra Hàn Lập một mình đồ sát một ác giao tiến hóa cấp hai, tự nhận từng cùng cha luyện chế tài liệu giao long và đồng ý động thủ. Nửa tháng sau Hàn Lập rời cửa hiệu với Thần Phong Châu — thuyền phi hành trắng luyện từ vẩy da Mặc Giao, dùng pháp quyết xanh biến thành thuyền độc mộc chở người bay lên, tốc độ hiếm có thay pháp khí hình lá cũ. Trên đường về hắn cảm nhận linh lực cường đại xông lên từ mặt đất, gia tốc thuyền gấp đôi né kịp một luồng quang trụ vàng cự đại bắn trúng chỗ vừa đứng, nghi bị mai phục. Hàn Lập dùng hai viên cầu xanh đỏ đập vào nhau tạo cụm mây lớn che giấu thân ảnh rồi nhìn xuống. Dưới đất là trận hỗn chiến: bốn năm Trúc Cơ Hậu Kỳ tu sĩ dựng hộ trạo hợp lực chống gần trăm khôi lỗi liên tục bổ sung từ rừng, phun quang trụ và quang tiễn nhiều màu; đạo quang trụ suýt trúng Hàn Lập chỉ là ngộ thương. Một tu sĩ chịu không nổi, dùng pháp khí lá cờ thoát ly hộ trạo bay ra định trốn thì bị siêu cấp quang trụ đường kính mấy trượng từ rừng bắn trúng, hóa quả cầu lửa rớt xuống, sống chết không rõ."},{"chuong":229,"tieuDe":"Cự Hổ","tomTat":"Đám tu sĩ Trúc Cơ hậu kỳ vốn tưởng dễ trốn thoát nay kinh hồn bạt vía sau khi chứng kiến một đồng bọn bị đạo quang trụ siêu cấp bắn chết, tiến lùi đều khó. Hàn Lập ẩn mình trong cụm mây Thanh Hỏa Chướng trên không nhờ Thần Phong Châu vừa tới tay, đưa toàn bộ vân chướng xuyên nhập một tầng mây xám thấp để giấu thân triệt để rồi yên tâm quan sát. Nghe giọng nói cứng rắn quen tai, Hàn Lập nhận ra kẻ điều khiển khôi lỗi chính là nam tử khôi vũ đã mua khôi lỗi cơ quan thú ở hội bán đấu giá, và đám tu sĩ Nguyên Vũ Quốc đã lén theo hắn dò bí mật nên bị vây khốn. Khi tu sĩ lớn tuổi cảnh cáo họa sát thân, nam tử khôi vũ cười lạnh từ chối vì đã lỡ giết một người và tự nhận đến từ Thiên Trúc Giáo Tổng Đàn nên không sợ đắc tội. Một khôi lỗi hổ khổng lồ cao năm sáu trượng vọt ra từ rìa rừng với hắn ngồi trên đầu, phun quang trụ bạch sắc siêu cấp; đám tu sĩ hợp lực dồn linh lực vào hộ trạo chống đỡ đến trắng bệt sắc mặt. Nam tử khôi vũ ném linh thạch bậc trung thuộc tính hỏa vào cửa bí mật trên đầu hổ tái kích hoạt quang trụ; đám tu sĩ hết pháp lực phân tán tháo chạy nhưng bị Cự Hổ bắn chết trước sau, cả hai cháy đen thui thảm khốc."},{"chuong":230,"tieuDe":"Khuyên Sáo","tomTat":"Sau khi hai tu sĩ khác trốn thoát, Hoàng Long không truy đuổi mà lên tiếng mời kẻ đang chờ ngư ông đắc lợi ra tay, khiến Hàn Lập đang trốn trong đám mây tưởng bị lộ; nhưng vũ khí các khôi lỗi lại chỉ về một gò đất nhỏ, nơi quái nhân trùm túi vải bố xám chui ra. Quái nhân gọi thẳng tên đối phương là Hoàng Long, khiến hắn lột áo choàng lộ đại hán tóc vàng hoe — nguyên Hộ Giáo Pháp Vương Thiên Trúc Giáo bỏ chức vì nửa phần Đại Diễn Quyết đồn giấu trong khôi lỗi thú. Quái nhân tự xưng Lâm sư huynh rồi kéo bao vải lộ mặt thật, chính là lão già họ Lâm yêu điêu khắc Hàn Lập từng gặp trong thạch ốc Hoàng Phong Cốc. Hoàng Long giả vui mừng nắm tay để cấy Hắc Ti Cổ cầu từ Cổ Độc Tông vào cổ tay Lâm sư huynh, tiết lộ toàn bộ là bẫy của Kim Giáo Chủ diệt cỏ tận gốc con giáo chủ cũ. Lâm sư huынh kịp bức máu độc, uống bột phấn vàng trong bình ngọc xanh lục để giải, nhận ra tin tức Đại Diễn Quyết là giả và bí điếm đã bán đứng mình. Biết đã sa bẫy, Lâm sư huynh triệu hơn hai trăm khôi lỗi sĩ binh, còn hai hộ pháp vương mới vẩy ra hơn hai trăm khôi lỗi thú, mở màn trận đại chiến khôi lỗi. Hàn Lập suy luận rõ lai lịch Lâm sư huynh, biết trận chiến ngoài tầm Trúc Cơ Sơ Kỳ nên thu hỏa chướng, phát động Thần Phong Châu hóa cầu vồng bỏ trốn, khiến bốn người dưới ngừng chiến rồi lại lao vào nhau."},{"chuong":231,"tieuDe":"Nhạ Họa Thượng Môn","tomTat":"Hàn Lập bay về động phủ, theo ngọc giản Tề Vân Tiêu giao mà bố trí Điên Đảo Ngũ Hành trận, chôn trận kỳ trận bàn và cắn răng gắn nửa số linh thạch bậc trung vào trận nhãn để đại trận phủ hơn mười mẫu quanh động phủ mà ngoài nhìn không khác thường. Lo con đường Kết Đan với tư chất kém và công pháp Thanh Nguyên kiếm quyết yếu, hắn xác định lợi thế nằm ở chiếc bình nhỏ thần bí thúc linh dược để luyện đan, và quyết định về Hoàng Phong cốc tìm sư phụ Lý Hóa Nguyên xin công pháp thượng phẩm. Đang ngủ thì hắn bị chấn động và tiếng nổ đánh thức — Thiên Trúc giáo do Hoàng Long dẫn đầu, cưỡi trúc bài xanh biếc cùng đôi nam nữ và bốn huynh đệ song sinh, công kích đại trận và đòi hắn giao ra kẻ trốn bên trong. Nhìn vào trận, Hàn Lập thấy một người nằm sấp gần cửa động, lật ra nhận là Lâm sư huynh với thần tình đen kịt, thất khiếu đổ máu, đã tuyệt khí. Khi hắn lục túi trữ vật tìm khôi lỗi, một đoàn sáng màu lục như ma quỷ từ áo bay ra lao vào mặt hắn; tay phải Hàn Lập lóe bạch quang, một trảo chộp giữ đoàn sáng — chính là thần hồn Lâm sư huynh định đoạt xá. Thần hồn cầu xin tha mạng, tự xưng bị cừu gia làm hại và hứa ưu đãi, còn Hàn Lập nghiêm mặt vặn hỏi ý đồ đoạt xá."},{"chuong":232,"tieuDe":"Đại Diễn Quyết","tomTat":"Sau khi khống chế nguyên thần Lâm sư huynh, Hàn Lập lạnh lùng cự tuyệt đề nghị đoạt xá và không tin lời hứa của đối phương. Hắn vạch mặt Lâm sư huynh chính là kẻ rình xem trộm hôm qua, ép đối phương khai toàn bộ về Đại Diễn quyết — bí thuật cường hóa thần thức tu kèm Phân Thần thuật để thao túng khôi lỗi, phân tầng khống chế số lượng khác nhau. Lâm sư huynh lộ thân phận thiếu giáo chủ Thiên Trúc giáo, con trai độc nhất giáo chủ tiền nhiệm bị Kim Nam Thiên ám toán soán ngôi, phải giả chết trốn ở Việt quốc. Đối phương còn tiết lộ lời đồn Đại Diễn quyết tăng xác suất kết đan, khiến sắc mặt Hàn Lập biến đổi, dù Lâm sư huynh nói dối gấp đôi con số thật. Bên ngoài trận, người Thiên Trúc giáo điều khiển phần lớn khôi lỗi công kích nhưng đại trận vẫn ngăn được. Sau khi moi đủ thông tin và cân nhắc rằng công pháp không tăng pháp lực, giữ lại tất báo thù, Hàn Lập bóp nát nguyên thần Lâm sư huynh thành tinh quang, độc thoại rằng hắn thống hận nhất kẻ đoạt xá."},{"chuong":233,"tieuDe":"Lôi Vạn Hạc","tomTat":"Lâm sư huynh — tu sĩ thứ hai bị Hàn Lập diệt nguyên thần xuất thể — vốn định vượt qua động phủ về Hoàng Phong cốc tìm cứu binh nhưng xông nhầm vào Điên Đảo Ngũ Hành trận, bị cảnh huyễn hoặc vây khốn, độc phát nên xuất nguyên thần định đoạt xá Hàn Lập, liền bị hắn một tay bắt chế trụ khiến tan thành khói. Hàn Lập cân nhắc giao thi thể để nhóm Thiên Trúc giáo bỏ chạy nhưng vì thi thể có dấu hiệu nguyên thần xuất khiếu rõ ràng nên quyết làm con rùa rụt đầu trong đại trận, ngồi dưỡng thần không dám về động phủ. Sau hơn một canh giờ oanh tạc cuồng bạo bằng khôi lỗi, đại trận lần đầu sinh biến hóa lóe thanh quang khiến Thiên Trúc giáo hưng phấn và sắc mặt Hàn Lập biến đổi. Đúng lúc đó Lôi Vạn Hạc — tu sĩ Kết Đan kỳ trưởng bối Hoàng Phong cốc — từ chân trời bay tới bằng ngân quang dài hơn mười trượng, tách nhiều đạo biến cả nhóm gồm Hoàng Long thành tro bụi bất chấp lời cầu tha. Người béo núc hiện thân tự xưng sư bá Lôi Vạn Hạc, được Hàn Lập cung kính bái kiến; Hàn Lập cắt đầu cắt đuôi kể lại sự tình nhưng giấu chuyện phường thị Thiên Tinh tông và việc diệt nguyên thần. Lôi Vạn Hạc tán dương Điên Đảo Ngũ Hành trận có lai lịch lớn, nhấc thi thể Lâm sư huynh xác nhận trúng cổ độc Cổ Độc tông cực tây, chê Kim đại giáo chủ bụng dạ hẹp hòi, rồi truy hỏi Hàn Lập có thấy nguyên thần Lâm sư huynh đào thoát trước khi thân hoại tử hay không khiến Hàn Lập cả kinh."},{"chuong":234,"tieuDe":"Cấm Chế, Linh Dược","tomTat":"Lôi Vạn Hạc tra hỏi Hàn Lập về nguyên thần Lâm sư huynh; Hàn Lập giả bộ hồ đồ, một mực nói không thấy nguyên thần để giấu việc tiêu diệt nguyên thần đoạt xá của kẻ kia. Lôi sư bá mắt nhắm mắt mở cho qua, nói nguyên thần có thể lạc trong đại trận mà tự tiêu tán, không truy cứu vì ấn tượng ban đầu với Hàn Lập không tệ. Sau khi xong việc, Lôi Vạn Hạc chê động phủ thô sơ; Hàn Lập nhân đó cung kính mời sư bá vào nghỉ, thỉnh giáo và nhờ xem hai gốc dược thảo lâu năm để yên tâm luyện đan. Trước khi lấy thuốc, Hàn Lập chủ động phát động biến hóa cấm đoạn thần thức trong Điên Đảo Ngũ Hành trận để chặn thần thức sư bá dò xét trữ tàng thất và Linh Nhãn chi tuyền. Lôi Vạn Hạc phóng thần thức nhưng cách hơn mười trượng thì đình trệ như nặng ngàn cân, kinh ngạc vì cấm chế xuất hiện ở động phủ đệ tử Trúc Cơ kỳ, song không nối được cấm chế này với đại trận bản giản hóa nên đánh giá sai. Cuối cùng lão bị hai gốc linh dược sáu bảy trăm năm thu hút mạnh, quên hết nghi ngờ và cẩn thận cầm lên xem xét, cho thấy khát vọng linh dược của tu sĩ Kết Đan kỳ lớn hơn nhiều so với Trúc Cơ kỳ."},{"chuong":235,"tieuDe":"Hàn Lập Đích Tâm Tư","tomTat":"Chương mở đầu bằng đoạn luận giải vai trò đan dược với tu sĩ Kết Đan kỳ: đan dược thường vô dụng, chỉ dược tài ngoài mấy trăm năm và linh dược thiên địa mới luyện được linh đan tăng tốc tu luyện, nên tu sĩ Kết Đan kỳ viễn du chủ yếu để cướp đoạt dược tài. Hồi tưởng lại việc năm xưa Lý Hóa Nguyên thu Hàn Lập làm đệ tử ký danh vì thèm khát linh dược mà keo kiệt không chia phần. Lôi Vạn Hạc đang gặp bình cảnh, cần luyện Tăng Nguyên đan nhưng viễn du hơn một năm chỉ thu được dược thảo thứ phẩm bốn trăm năm, nên thèm khát hai gốc linh thảo sáu-bảy trăm năm của Hàn Lập và ngấm ngầm mưu tính cách đoạt lấy. Hàn Lập nửa thật nửa giả kể chuyện từng thấy linh thảo ngàn năm ở bí điếm nhưng vô lực mua, khiến Lôi Vạn Hạc nhảy dựng vì tiếc kỳ ngộ nhưng vẫn kịp bình tĩnh. Lão khuyên Hàn Lập đừng giao dược cho các Luyện Đan sư Hoàng Phong cốc trình độ kém, rồi hào khí đề nghị trao đổi công bình, hỏi Hàn Lập cần pháp khí đỉnh cấp hay đan dược. Hàn Lập tỏ vẻ khó xử, nói mình hứng thú với con đường luyện đan nhưng thiếu phương thuốc thực dụng, và muốn dùng hai gốc linh thảo đổi lấy một phương pháp luyện đan thích hợp cho mình, đúng như hắn đã tính toán từ đầu."},{"chuong":236,"tieuDe":"Cổ Phương","tomTat":"Hàn Lập đề nghị trao đổi phương thuốc với sư bá Kết Đan kỳ Lôi Vạn Hạc, chuyển mục tiêu từ sư phó Lý Hóa Nguyên khó đắc thủ sang vị sư bá dễ tính hơn, với động cơ thầm kín là bí pháp đẩy nhanh trưởng thành dược thảo của mình. Lôi Vạn Hạc ban đầu do dự vì phương thuốc gia tộc là bí truyền, nhưng đưa ra vài phương thuốc cổ tìm được từ di tích và trung thực cảnh báo nguyên liệu cực khó tìm. Vì áy náy chiếm tiện nghi quá lớn, lão chốt chỉ lấy một gốc Chu Linh thảo đổi một cách điều chế; Hàn Lập mừng rỡ chọn Tụ Linh đan và Luyện Khí tán từ mục lục. Lôi Vạn Hạc cáo từ về luyện Tăng Nguyên đan, giật mình khi biết Hàn Lập là ký danh đệ tử của Lý Hóa Nguyên nhưng vẫn tiết lộ nơi động phủ của lão rồi bay đi. Hàn Lập quay sang lục soát thi thể Lâm sư huynh ở động khẩu, tìm được túi trữ vật nhưng không có khôi lỗi nào, chỉ vài linh thạch cùng hai bình đan dược phổ thông. Khi tiện tay đưa thần thức dò xét ngọc giản không ra gì, ba chữ vàng to Đại Diễn quyết bất ngờ hiện ra, mở ra một cơ duyên mới cho hắn."},{"chuong":237,"tieuDe":"Tham Kiến","tomTat":"Hàn Lập xem hết ngọc giản Đại Diễn quyết mà Lâm sư huynh trao, xác nhận đúng chỉ có bốn tầng khẩu quyết, rồi bất ngờ phát hiện phía sau còn ẩn một bộ kinh văn tên Khôi lỗi chân giải, dạy pháp môn chế tác khôi lỗi thú và khôi lỗi nhân cực kỳ tường tận. Hắn nhận ra đây là cặp phối hợp hoàn mỹ có thể dùng nhiều khôi lỗi áp chế tu sĩ Trúc Cơ đồng cấp như Hoàng Long, nhưng lo ngại việc tu luyện làm chậm cơ hội kết đan nên tạm cất ngọc giản vào túi trữ vật chờ xử lý sau. Ra khỏi đại trận, hắn thu hồi khoảng hai mươi mấy khôi lỗi nhân và cơ quan thú còn sót đã co lại bằng lòng bàn tay, số còn lại đã bị kiếm quang Lôi thuộc tính của Lôi Vạn Hạc thiêu rụi. Sáng hôm sau, Hàn Lập cưỡi Thần Phong chu bay tới phía đông Thái Nhạc sơn mạch, tìm động phủ Lý Hóa Nguyên nằm sau một thác nước lớn, rồi dùng Truyền Âm phù báo tin. Đại đệ tử Vu Khôn ra đón, nhiệt tình thái quá khiến hắn bất an, dẫn hắn qua tiểu cốc thiên nhiên và tiết lộ sư phó có sư nương là nữ tu Trúc Cơ trung kỳ tính ôn hòa. Cuối cùng Hàn Lập vào đại sảnh Lục Ba động, bái kiến sư tôn rồi tham kiến sư nương, được Lý Hóa Nguyên khẩu khí ấm áp khen ngợi việc Trúc Cơ thành công."},{"chuong":238,"tieuDe":"Vu Khôn Đích Khả Phạ","tomTat":"Trong Lục Ba động, phu nhân của Lý Hóa Nguyên can chồng đừng giáo huấn Hàn Lập, gọi Hàn Lập là ân nhân cứu mạng. Lý Hóa Nguyên thẳng thắn thừa nhận năm xưa thu Hàn Lập làm đồ đệ chỉ vì tham linh dược thiên địa, lấy đi một nửa nên Hàn Lập chỉ nhận một viên Trúc Cơ đan; nhưng chính số linh dược đó đã cứu mạng phu nhân bị tu luyện sai lầm. Vì đã hứa thu môn khi Hàn Lập Trúc Cơ nên việc thu môn không tính là bồi thường, lão hứa bồi thường thêm trong phạm vi năng lực, còn phu nhân khuyên Hàn Lập nghỉ một ngày đêm rồi sáng mai hãy đề xuất yêu cầu. Sau khi Hàn Lập đi ra, phu nhân tiết lộ động cơ thật: nàng tu Băng Tâm quyết, nếu không báo được ân sẽ tâm trạng bất ổn, không luyện thành đại viên mãn để tiến Kết Đan kỳ, khiến Lý Hóa Nguyên cảm động hứa thỏa mãn yêu cầu. Vu Khôn dẫn Hàn Lập tham quan Lục Ba động, tới Luận Kiếm đường gặp Tứ sư huynh Tống Mông cuồng chiến đấu; Tống Mông muốn khiêu chiến nhưng mất hứng khi biết Hàn Lập mới Trúc Cơ nên lạnh lùng bỏ đi. Cuối cùng Hàn Lập bị Vu Khôn kéo vào phòng nói dông dài mấy canh giờ đến đau đầu, phải viện cớ mệt mỏi để thoát ra nghỉ ngơi, hoàn toàn nể phục khả năng nói của vị Đại sư huynh này."},{"chuong":239,"tieuDe":"Quyết Trạch","tomTat":"Sau khi đợi một ngày trong động phủ, Hàn Lập đứng trước vợ chồng Lý Hóa Nguyên và không do dự chọn phần thưởng là một bộ công pháp thích hợp để tu luyện. Lý Hóa Nguyên bắt cổ tay hắn dò xét, kinh ngạc phát hiện linh căn bốn thuộc tính, trừ Kim thuộc tính thì các thuộc tính khác đều tu luyện được. Lão giảng công pháp tu tiên chia ba loại theo uy lực và hiệu quả: loại một thiên thủ đoạn khắc địch, loại hai tinh tiến pháp lực cực nhanh nhưng thiếu tự bảo vệ, loại ba đỉnh cấp cực hiếm mà cực nguy hiểm. Đáp lời Hàn Lập, lão kiêu ngạo tiết lộ mình tu công pháp đỉnh cấp Chân Dương quyết nhờ là tam dương chi thể gần Thiên Linh căn. Bất chấp vợ chồng sư phụ khuyên chọn loại một an toàn, Hàn Lập kiên định chọn loại pháp quyết thứ hai. Cuối cùng Lý Hóa Nguyên để phu nhân ở lại đại sảnh, dẫn Hàn Lập vào Tàng thư thất có kết giới hỏa hồng, mở kho công pháp năm sáu mươi kiện kèm lời cảnh cáo về cấm chế."},{"chuong":240,"tieuDe":"Thư Hiệt","tomTat":"Trong thạch thất, Lý Hóa Nguyên quơ tay lấy bảy tám kiện đồ vật cho Hàn Lập chọn một loại làm chủ công pháp. Hàn Lập xem qua các công pháp nổi bật như Quy Nguyên công (kèm Quy Nguyên linh giáp) và Huyễn Linh quyết (kèm thần thông Ảo ảnh), nhưng chú ý một quyển sách màu vàng ghi Ngưng Nguyên công có hình dáng giống hệt quyển sách màu bạc trong tay hắn nên chọn nó làm chủ công pháp. Ở đại sảnh, hắn quỳ thề thành tâm và chính thức được Lý Hóa Nguyên thu nhận làm đệ tử chính thức, dù trong lòng vẫn dè chừng. Rời động phủ, Hàn Lập né tránh Vu đại sư huynh quấy nhiễu ma âm rồi ngự khí bay đi, hồi tưởng thái độ sư phụ nay tốt hơn nhiều. Về động phủ, hắn dùng liệt hỏa nung chảy bề mặt sách bạc và phát hiện một quyển sách màu vàng ẩn bên trong không sợ lửa. Thất vọng vì sách chỉ dạy phi kiếm và kiếm quang, hắn tức giận quăng sách lên đánh một đạo kiếm quang xanh, nhưng kiếm quang bị sách nuốt trọn vô ảnh vô tung khiến hắn kinh hãi rồi phấn chấn."},{"chuong":241,"tieuDe":"Tam Chuyển Trọng Nguyên Công","tomTat":"Hàn Lập dùng Huyền phù thuật treo tờ giấy vàng và thử truyền Thanh nguyên kiếm quang vào, sau khi từng suýt làm hỏng nó bằng một mũi tên băng. Tờ giấy hấp thu gần cạn chân nguyên tầng thứ tư của hắn rồi phát kim quang, hiện vô số chữ sáng và cưỡng ép truyền vào thân thể khiến hắn đau đớn đến mức gần như không chịu nổi. Sau ba ngày ba đêm điều tức, Hàn Lập hiểu được nội dung bên trong là Thanh nguyên kiếm quyết đầy đủ từ tầng một đến tầng mười ba, kèm công pháp phụ trợ Tam chuyển trọng nguyên công. Công pháp phụ trợ này mở ra cách tăng cơ hội Kết đan bằng việc tán công rồi trùng tu ba lần để nén chân nguyên, nhưng cái giá là thời gian quá dài và xác suất thành công vẫn chỉ khoảng một nửa. Hàn Lập tiếp tục kích hoạt tờ giấy vàng thứ hai và nhận được phương pháp luyện Thanh trúc phong vân kiếm, một bộ phi kiếm pháp bảo thuộc tính mộc dành cho tu sĩ Kết Đan kỳ. Nhận thấy phi kiếm này có thể phối hợp mạnh với Thanh nguyên kiếm quyết, hắn quyết định trước hết tu kiếm quyết đến tầng sáu và đỉnh Trúc Cơ kỳ rồi thử Kết đan, nếu thất bại mới tính tới việc tán công."},{"chuong":242,"tieuDe":"Chế Phù","tomTat":"Hàn Lập cất kỹ hai tờ giấy vàng ghi phương thuốc cổ rồi suy tính con đường tu luyện Thanh nguyên kiếm quyết và Tam chuyển trọng nguyên công. Hắn quyết định tận dụng chất dịch màu lục trong bình nhỏ thần bí để thúc sinh linh thảo, nhưng cũng nhớ rõ thứ dịch này cực kỳ nguy hiểm với sinh vật sống vì động vật thí nghiệm đều nổ tung dù đã pha loãng. Nhận thấy phù lục trung cấp rất cần cho tranh đấu Trúc cơ kỳ và có thể giúp kiếm linh thạch, hắn chuyển trọng tâm sang chế phù, dùng Kim trúc bút cùng nguyên liệu do bình nhỏ hỗ trợ. Sau khi thu thập nguyên liệu ở khu chợ bản môn và Thiên tinh tông, Hàn Lập đóng chặt động phủ, mở cấm chế và bế quan suốt bốn năm. Bốn năm sau, một nho sinh đồng môn được Lôi sư bá chỉ điểm tìm tới động phủ, ném truyền âm phù vào hộ phủ đại trận rồi rời đi. Hàn Lập trong bế quan thất cảm ứng động tĩnh, thu dọn lượng lớn phù lục đã luyện, xuất quan và dùng cờ nhỏ màu vàng cùng vầng sáng xanh bắt truyền âm phù tới trước mắt."},{"chuong":243,"tieuDe":"Dược Hiệu","tomTat":"Hàn Lập nhận truyền âm phù của Lý Hóa Nguyên yêu cầu lập tức đến Lục Ba động, liền vào phòng ngủ sắp xếp phù lục trong các túi trữ vật rồi rời động phủ bằng Thần phong chu. Trên đường, hắn hồi tưởng bốn năm bế quan: vừa tu luyện, vừa mở vườn thuốc bí mật trong động phủ, dùng bình nhỏ thúc sinh linh dược, còn vườn thuốc lớn bên ngoài chỉ để che mắt. Luyện khí tán do hắn luyện bằng Tiên thiên chân hỏa ban đầu giúp pháp lực tăng mạnh và khiến việc trùng tu Thanh nguyên kiếm quyết ba lần có hy vọng, nhưng từ năm thứ hai dược hiệu giảm dần rồi đến năm thứ tư hoàn toàn vô dụng. Hàn Lập suy đoán thân thể đã sinh kháng dược vì dùng thuốc quá thường xuyên, thử ngừng một năm rồi uống lại vẫn không hiệu quả nên quyết định tìm linh dược và phương thuốc mới, nhất là Tụ linh đơn. Ngoài luyện đan, hắn cũng luyện pháp thuật cấp thấp và chế phù mỗi ngày, đã miễn cưỡng chế được phù lục bậc cao sơ cấp, đồng thời luyện vài viên Định nhan đơn và uống thử một viên. Đến Lục Ba động, người mở cấm chế là Vũ Huyễn, lục đệ tử của Lý Hóa Nguyên, thái độ lạnh nhạt nhưng dẫn hắn vào đại sảnh. Trong đại sảnh có vợ chồng Lý Hóa Nguyên, Hồng Phất, Tống Mông và một thiếu nữ áo hồng; Lý Hóa Nguyên bảo Hàn Lập bái kiến Hồng Phất, còn Hồng Phất quan sát hắn kỹ rồi tỏ ý vừa lòng. Lý Hóa Nguyên nhân đó khen Hàn Lập là tu sĩ Trúc Cơ kỳ ôn hòa cơ trí, khiến Hàn Lập nghe mà hoàn toàn không hiểu nguyên do."},{"chuong":244,"tieuDe":"Song Tu","tomTat":"Hàn Lập được Hồng Phất xem xét trong động phủ của Lý Hóa Nguyên và nhận ra thiếu nữ bên cạnh bà nhiều lần nhìn trộm mình nhưng không vui, còn Vũ Huyễn thì lộ vẻ địch ý. Sau khi Hồng Phất rời đi, vợ chồng Lý Hóa Nguyên vui vẻ báo rằng Hồng Phất muốn Hàn Lập kết thành bạn song tu với nữ đồ đệ họ Đổng, khiến hắn bất ngờ. Lý Hóa Nguyên giải thích song tu có lợi cho tu luyện, đồng thời kết thân với Hồng Phất là cơ hội tốt vì bà là tu sĩ Kết Đan kỳ nổi danh trong Hoàng Phong Cốc. Ông cũng nói Đổng nha đầu tư chất bình thường, từng dùng nhiều Trúc Cơ đan và dược vật mới Trúc Cơ, còn Vũ Huyễn dù hơn Hàn Lập về dung mạo và tư chất lại bị Hồng Phất loại vì bà ghét nam tử đẹp mã phù phiếm. Hàn Lập nghe nhắc Đổng gia thì nhớ đến Lục sư huynh từng đề cập Đổng gia và Hồng Phất sư tổ trong chuyện cũ, từ đó sinh nghi và càng không muốn nhận mối hôn phối này. Hắn khéo léo từ chối với lý do sự việc quá đột ngột, bản thân chưa chuẩn bị và Đổng nha đầu cũng không có vẻ tình nguyện. Lý Hóa Nguyên không muốn thất hứa với Hồng Phất nên trách hắn, nhưng phu nhân Lý Hóa Nguyên bất ngờ hỏi Hàn Lập có từng nghe lời đồn không hay về Đổng nha đầu hay không. Lý Hóa Nguyên lập tức cho Tống Mông và Vũ Huyễn ra ngoài, chỉ giữ Hàn Lập lại để hỏi tiếp."},{"chuong":245,"tieuDe":"Viễn Hành Dữ Ý Ngoại","tomTat":"Sau khi không còn người ngoài, Lý Hóa Nguyên hỏi phu nhân vì sao lo lắng chuyện song tu giữa Hàn Lập và Đổng Huyên Nhi. Phu nhân kể lại các lời đồn về Đổng Huyên Nhi từng dây dưa với nhiều nam đệ tử, từng khiến đồng môn suýt quyết đấu và còn bị đồn có quan hệ với tiểu tử Phong gia, khiến Lý Hóa Nguyên lo chuyện này sẽ ảnh hưởng thanh danh của mình. Hàn Lập cũng càng không muốn dính vào Đổng Huyên Nhi vì nhớ đến quan hệ mờ ám giữa nàng và Lục sư huynh. Sau khi bàn bạc, Lý Hóa Nguyên cho Hàn Lập lui về chờ kết quả, rồi ba ngày sau dùng truyền âm phù báo rằng chuyện song tu đã đổi thành chuyến đi cùng Đổng Huyên Nhi đến Đoạt bảo đại hội của Yến gia. Nửa tháng sau, Hàn Lập và Đổng Huyên Nhi được Lý Hóa Nguyên, phu nhân và Hồng Phất tiễn trước thác nước Lục Ba động; Lý Hóa Nguyên dặn Hàn Lập cẩn thận vì tu tiên giới gần đây bất ổn, còn Hồng Phất nghiêm khắc bắt Đổng Huyên Nhi nghe lời Hàn Lập. Sau khi hai người rời đi, Hồng Phất hé lộ mục đích chính là để Đổng Huyên Nhi gặp thất bại ở Yến gia, nhất là trước tiểu cô nương thiên linh căn, qua đó mài bớt ngạo khí của nàng. Chương cũng giới thiệu Đoạt bảo đại hội là sự kiện do Yến gia, đệ nhất gia tộc tu tiên giới Việt quốc, tổ chức để kết giao đệ tử các cao thủ Kết Đan kỳ, với Càn khôn tháp làm phần thưởng cao nhất. Cuối chương, hồi tưởng cho biết Hồng Phất đã đồng ý đổi điều kiện song tu nhưng giữ phu nhân Lý Hóa Nguyên lại nói riêng, khiến phu nhân trở về báo cho Lý Hóa Nguyên một chuyện làm ông chết điếng."},{"chuong":246,"tieuDe":"Đổng Huyên Nhi","tomTat":"Hồng Phất đưa Đổng Huyên Nhi đi kiểm tra thủ cung sa trước mặt phu nhân Lý Hóa Nguyên, chứng minh nàng vẫn giữ trinh bạch. Bà giải thích lời đồn thất tiết bắt nguồn từ Hóa xuân quyết và thói quen khiến nam đệ tử vây quanh tranh giành, chứ không phải Đổng Huyên Nhi thật sự mất nguyên âm. Lý Hóa Nguyên và phu nhân biết mình đã hiểu lầm, nhưng vì danh tiếng vẫn không muốn Hàn Lập kết thành bạn tình song tu với nàng, nên ông chỉ thuận nước đẩy thuyền để Hàn Lập đi Đoạt bảo đại hội cùng nàng. Vũ Huyễn sau khi gặp Đổng Huyên Nhi thì si mê, xin sư phụ nhắc lại chuyện cầu thân nhưng bị Lý Hóa Nguyên quở trách và phái ra ngoài làm việc. Chương chuyển sang bối cảnh Yến gia, giới thiệu Yến Linh bảo trong Yến Lương sơn là địa điểm Đoạt bảo đại hội. Hàn Lập và Đổng Huyên Nhi rời Lục Ba động đã bảy tám ngày, trên đường thường xuyên xung khắc nhưng Hàn Lập dùng uy danh Hồng Phất để kiềm chế nàng. Khi tới điểm tiếp khách theo thư mời, Hàn Lập không thấy người Yến gia xuất hiện, bèn bắn ba hỏa cầu báo hiệu và chuẩn bị rời đi nếu vẫn không có ai tới đón."},{"chuong":247,"tieuDe":"Yến Thị Huynh Muội","tomTat":"Hàn Lập và Đổng Huyên Nhi chờ trên đỉnh núi cho tới khi Yến Vũ cùng muội muội Yến Linh cưỡi Song thủ vụ đến xin lỗi và tiếp dẫn hai người vào Yến Linh bảo. Đổng Huyên Nhi nhanh chóng dùng vẻ dịu dàng làm Yến Vũ dao động, nhưng Hàn Lập nhận ra nàng có ý vận dụng Hóa xuân quyết nên truyền âm nhắc tới Hồng Phất để buộc nàng dừng lại. Sau khi Hàn Lập hỏi khéo chuyện đón tiếp chậm trễ, hai người xuất trình thiếp mời của Lý Hóa Nguyên và Hồng Phất, rồi theo huynh muội Yến gia bay tới nơi cổ bảo được che giấu. Yến Vũ dùng lệnh bài mở cấm chế ngũ sắc giữa hai ngọn núi nhỏ, để lộ Yến Linh bảo hùng vĩ. Từ ngoài bảo, Hàn Lập và Đổng Huyên Nhi thấy võ trường có đại hán Yến gia đang đối峙 với một quái nhân lục bào tóc vàng mắt xám trong màn hào quang trắng. Yến Linh tức giận kể nhóm lục bào không phải khách mời, đã đánh bị thương Tiểu thập lục và Tiểu thập ngũ rồi đòi chen vào Đoạt bảo đại hội. Yến Vũ bổ sung rằng nhóm này đưa ra thư tín vật khiến các trưởng lão Yến gia phải nén giận mời vào và đồng ý đấu mười trận Trúc Cơ kỳ, trong khi các trận trước đó cho thấy Yến gia đang ở thế hạ phong."},{"chuong":248,"tieuDe":"Tranh Phong","tomTat":"Yến Vũ giải thích với Hàn Lập và Đổng Huyên Nhi rằng nhóm người khiêu chiến Yến gia dùng pháp thuật cùng độc thuật ma đạo khiến nhiều đệ tử thua trận hôn mê, trúng độc khó chữa, nhưng vì còn ở trong Yến Linh bảo nên chưa dám giết người. Yến Linh cho biết các trưởng lão đã gọi tinh anh Diễn Vũ đường tới ứng phó, rồi bị Yến Vũ sai đi báo Lê thúc điều thêm đệ tử đón khách vì cấm chế hộ bảo đã hạn chế truyền âm ở vài nơi. Đổng Huyên Nhi dùng vẻ quyến rũ làm Yến Vũ thất thần, còn Hàn Lập chen vào xin đến gần xem tỷ thí để tránh nàng tiếp tục gây chuyện. Khi đến sân đấu, Hàn Lập thấy hơn trăm tu sĩ vây xem và nhận ra nhiều người không giống tu sĩ Việt quốc bản địa, nên âm thầm nghi ngờ nhưng không tiện hỏi. Phong sư huynh bất ngờ xuất hiện, gọi Đổng Huyên Nhi thân mật và khiến Yến Vũ khó chịu, trong khi Hàn Lập suy đoán hắn có thể liên quan Phong gia từng được sư nương nhắc. Đổng Huyên Nhi nhân lúc Hàn Lập chú ý trận đấu đã gài hắn thừa nhận phải luôn ở cùng nàng, khiến Yến Vũ và Phong sư huynh cùng chuyển địch ý sang Hàn Lập. Trong sân, đường huynh của Yến Vũ dùng đạo thuật thổ thuộc tính và phướn vàng đối đầu người áo lục có hắc khí lưới đen cùng nhiều đầu lâu khô trắng quanh thân. Cuối chương, tinh anh Yến gia ngừng cự thạch thuật, đổi sang cầm quạt giấy màu vàng bằng hai tay, mỗi lần quạt đều hao sức lớn và báo hiệu thế trận sắp biến đổi."},{"chuong":249,"tieuDe":"Bỉ Thí","tomTat":"Đường huynh của Yến Vũ dùng Hóa cốt bảo phiến chém ra độc vụ, ban đầu ép hắc khí quanh lục bào quái nhân co lại khiến người Yến gia tưởng đã chiếm thượng phong. Trong lúc xem đấu, Đổng Huyên Nhi khơi chuyện so sánh Hóa cốt phiến với Phong Lôi phiến, khiến Yến Vũ và Phong sư huynh vì nàng mà tranh chấp, còn Hàn Lập nhận ra Hồ mị công của nàng có sức ảnh hưởng bất thường nhưng lại không tác dụng với mình. Lục bào quái nhân đảo ngược thế trận bằng cách cho khô lâu hút hắc khí, phình lớn rồi nuốt phần lớn lục vụ của Hóa cốt phiến, làm pháp khí của Đường huynh suy tổn. Sau đó các khô lâu phun luồng sáng đen hợp thành cột sáng, xuyên thủng hộ thân hoàng phong khiến Đường huynh hôn mê rơi xuống và được đệ tử Yến gia cứu về. Trưởng lão Yến gia thừa nhận Huyền pháp Quỷ linh môn tinh diệu, Yến gia đã thua bốn trong năm trận. Thiếu môn chủ Quỷ linh môn đeo mặt nạ quỷ bạc không tiếp tục ngay mà đề nghị chờ đệ tử Sinh tử đường Yến gia tới rồi tỷ thí tiếp, và Yến gia chấp nhận tạm dừng. Sau trận, Đổng Huyên Nhi xin nghỉ vì mệt, Yến Vũ đưa nàng tới sương phòng nữ tu, còn Hàn Lập coi nhiệm vụ hộ tống nàng đến Yến linh bảo đã hoàn thành nên một mình rời đi."},{"chuong":250,"tieuDe":"Cố Nhân Ngộ","tomTat":"Hàn Lập không tiếp tục đi cùng Đổng Huyên Nhi, Phong sư huynh và Yến Vũ vì đã được Yến Vũ đưa cho ngọc giản địa đồ Yến linh bảo. Một mình đi trong bảo, hắn quan sát đường sá, cửa hàng và biết thêm rằng nơi đây có rất nhiều người thường bị ràng buộc cả đời, không thể tùy tiện rời đi. Hàn Lập định tới trà lâu để tìm tu sĩ đồng cấp kết giao và trao đổi kinh nghiệm tu luyện. Trên đường, hắn va phải một thiếu phụ vừa bước ra từ cửa hàng, sau đó nhận ra nàng chính là Mặc Thải Hoàn, con gái út của Mặc đại phu. Mặc Thải Hoàn xác nhận thân phận Hàn Lập qua chuyện Oanh hương hoàn năm xưa rồi bật khóc, cầu hắn cứu mẹ mình là Nghiêm thị đang bệnh nặng. Trên đường dẫn Hàn Lập về nhà, nàng tiết lộ Mặc phủ đã bị phá hủy từ bảy năm trước, Kinh Giao hội cũng bị xóa sổ, Nhị nương và Ngũ nương đã chết, còn nhiều người khác không rõ tung tích."},{"chuong":251,"tieuDe":"Hủy Diệt","tomTat":"Mặc Thải Hoàn dẫn Hàn Lập tới tiểu điếm nhỏ trong Yến linh bảo, nơi nàng và Nghiêm thị bán phù lục cấp thấp cùng nguyên liệu rẻ để kiếm linh thạch mua thuốc. Nghiêm thị nhận ra Hàn Lập trong tình trạng già yếu bệnh nặng, còn Hàn Lập vẫn gọi bà là tứ sư mẫu vì danh phận thầy trò với Mặc đại phu vẫn là thật. Hắn bắt mạch, dùng kim châm giúp bà ngừng ho rồi đưa thuốc dặn dùng hơn mười ngày sẽ khỏi hẳn. Sau đó, Nghiêm thị kể rằng sau cái chết của Âu Dương Phi Thiên, Kinh Giao hội bị Ngũ sắc môn đánh bại và nhổ tận gốc, Mặc phủ bị tập kích, Lý thị cùng Vương thị chết khi phá vây, những người còn lại chia nhau chạy trốn. Bà và Mặc Thải Hoàn từng bị truy sát nhưng được Yến Trụ cứu, đưa vào Yến linh bảo; Nghiêm thị về sau gả cho Yến Trụ để báo ơn, còn Mặc Thải Hoàn bị che thân phận bằng lời đồn góa phụ nhằm tránh quấy nhiễu. Khi Yến Trụ chết trong một lần làm nhiệm vụ gia tộc, mẹ con Nghiêm thị mất chỗ dựa, phải mở tiểu điếm sống qua ngày. Gần đây một tu sĩ phụ cận muốn nạp Mặc Thải Hoàn làm thiếp, bị Nghiêm thị từ chối nên ngầm cắt nguồn cung phù lục của họ. Hàn Lập hiểu ý Nghiêm thị thăm dò tu vi của mình và hỏi thẳng có phải bà muốn hắn giải quyết sự quấy nhiễu của tên tu sĩ kia hay không."},{"chuong":252,"tieuDe":"Phân Ly","tomTat":"Hàn Lập hỏi Nghiêm thị và Mặc Thải Hoàn về tu sĩ Yến gia đang quấy nhiễu Mặc gia, biết đối phương chỉ luyện công pháp cơ bản tầng thứ năm và địa vị không cao nên nhận lời ra mặt giải quyết. Nghiêm thị nhân đó nói rõ nỗi khổ của phàm nhân ở Yến linh, còn Mặc Thải Hoàn phản đối chuyện gả cho tu sĩ vì nữ phàm nhân trong bảo thường bị coi rẻ, đánh mắng và ruồng bỏ. Sau khi Hàn Lập áp chế tu sĩ kia, Mặc Thải Hoàn vui mừng kể lại dáng vẻ sợ hãi cung kính của hắn, còn Hàn Lập giải thích đó là quy củ chênh lệch cảnh giới trong tu tiên giới. Mặc Thải Hoàn hỏi liệu không có linh căn thì có thể tu tiên hay không, khiến Hàn Lập đau lòng nhưng chỉ có thể thừa nhận quy luật này không thay đổi được. Trước lúc rời đi, Hàn Lập đưa nàng hơn mười viên linh thạch và cho uống một viên đan màu phấn hồng có thể tăng thọ, giữ dung nhan, rồi biến mất. Hắn lặng nhìn Mặc Thải Hoàn trở về, tự nhận hai người hữu duyên vô phận vì khoảng cách tiên phàm, sau đó đến trà lâu Thiên hạc cư và hướng lên tầng ba để tìm các tu sĩ Trúc Cơ."},{"chuong":253,"tieuDe":"Quỷ Linh Môn","tomTat":"Hàn Lập lên lầu ba trà lâu Yến gia và lập tức bị nhiều thần thức Trúc Cơ kỳ quét qua, qua đó nhận ra đa số tu sĩ tại đây mạnh hơn một tu sĩ mới Trúc Cơ như mình. Hắn quan sát thấy lầu ba chia thành hai nhóm rõ rệt: một bên là tu sĩ thất đại phái, bên kia là nhóm tu sĩ nước ngoài ăn mặc hỗn tạp, nên chọn ngồi cùng phe thất đại phái. Tại bàn, Vô Tử giới thiệu Vô Du Tử, Vũ sư đệ của Linh Thú Sơn, Ba sư huynh của Cự Kiếm Môn và Phương sư muội của Thiên Khuyết Bảo; Hàn Lập cũng xác nhận mình là môn hạ chính thức của Lý Hóa Nguyên sau khi Trúc Cơ. Nhóm tu sĩ bàn về việc nhiều người nước ngoài tới Yến Linh bảo, cho rằng Càn Khôn tháp phù bảo tuy quý nhưng chưa đủ để tạo sức hút bất thường, còn khả năng dị bảo xuất thế cũng không thuyết phục. Vũ sư đệ đặc biệt bất an trước Quỷ Linh Môn vì nhóm này đánh bại nhiều đệ tử Yến gia mà Yến gia vẫn không dám lập tức trở mặt. Vô Du Tử sau đó tiết lộ Quỷ Linh Môn là một trong sáu tông phái ma đạo của Thiên La quốc, am hiểu khu quỷ dịch yêu, độc thuật và ám thuật, dù yếu nhất trong sáu ma tông vẫn mạnh hơn Yểm Nguyệt tông ba phần. Tin này khiến nhóm thất đại phái biến sắc, còn Hàn Lập tự suy xét khả năng ma đạo Thiên La quốc xâm lấn Việt quốc. Sau khi cân nhắc Khương quốc, Xa Kỵ quốc và Chính đạo liên minh nằm giữa, Hàn Lập tạm loại trừ tình huống xấu nhất."},{"chuong":254,"tieuDe":"Yến Gia Lão Tổ","tomTat":"Hàn Lập suy xét việc Quỷ linh môn xuất hiện tại Yến linh bảo nhưng tự nhắc mình chỉ là tu sĩ Trúc Cơ kỳ, không nên can dự vào chuyện của các thế lực lớn. Sau buổi trao đổi kinh nghiệm tu luyện, hắn cùng nhóm tu sĩ đồng ý ngày mai tới Xử thiên tích để tiếp tục luận đạo và giao dịch vật phẩm nhỏ. Hắn theo bản đồ chọn Phong nguyệt khách điếm ở đông nam Yến linh bảo vì nơi này thanh tĩnh, ít người và gần tường thành, tiện thoát thân nếu có biến. Đêm đó, tại Phi vân các, Yến gia lão tổ hỏi Tử Quân về lời hẹn của Thiếu chủ Quỷ linh môn rồi nhận tin đối phương đã tới cùng hai hộ vệ Kết Đan kỳ và còn chế trụ thiết vệ Yến gia. Trong đại sảnh, lão tổ nhận ra hai hộ vệ là Lý thị huynh đệ nổi danh, còn Thiếu chủ Quỷ linh môn đeo mặt nạ ác quỷ vẫn bình thản trình ngọc giản thư của cha. Khi Thiếu chủ truyền âm hai chữ bí mật, Yến gia lão tổ lập tức biến sắc, nhận thư và đưa hắn vào mật thất có cấm chế mạnh để mật đàm suốt đêm."},{"chuong":255,"tieuDe":"Mật Hội","tomTat":"Đến trưa ngày thứ hai ở Yến linh bảo, Hàn Lập tham gia một hội trao đổi nhỏ với hơn chục tu sĩ, nơi nhiều vật phẩm hiếm như Thiên hoa thạch và trứng Phong khiếu ưng lần lượt được đưa ra. Hắn đổi được một loại dược thảo cần cho Tụ linh đan, dù niên đại chưa đủ nhưng có thể mang về bồi dưỡng thêm. Khi đến lượt mình, Hàn Lập dùng lục phù sơ cấp bậc cao để rao đổi nguyên liệu luyện đan hoặc phương thuốc, nhờ vậy Vô Du Tử đưa ra ngọc giản chứa cổ phương Tự Linh Hoàn chuyên nuôi dưỡng linh thú. Hàn Lập nhận ra phương thuốc này vô dụng với người thường nhưng rất có giá trị với mình, nên dùng mười phù lục hoàn tất giao dịch. Cùng lúc, tại Phi vân các, Yến gia mở mật hội tông tộc, nghe Yến gia lão tổ trình bày đề nghị trọng đại của Quỷ linh môn: chia sẻ Vạn linh thực kinh, trao chức Phó môn chủ, nhưng yêu cầu Yến Như Yên cộng tu Huyết linh đại pháp với Thiếu chủ Quỷ linh môn và ràng buộc quyền kế thừa tương lai. Yến gia lão tổ còn tiết lộ ma đạo lục tông Thiên La quốc sau năm ngày sẽ xâm lấn Việt quốc, trong khi Khương quốc và Xa Kỵ quốc đã sụp đổ nửa tháng trước. Trước thế cục sinh tử tồn vong, Huyền Dạ được gọi phân tích và lập tức chất vấn những điểm then chốt về công pháp, động cơ Quỷ linh môn, độ xác thực của tin chiến sự và phản ứng của chính đạo liên minh Phong Đô quốc."},{"chuong":256,"tieuDe":"Mưu Hoa","tomTat":"Yến gia lão tổ giải thích cho các trưởng bối Yến gia rằng Huyết linh đại pháp của Quỷ linh môn cần nam nữ song tu để tránh phản phệ, còn thiên linh căn của Yến Như Yên và ám linh căn của Thiếu chủ Quỷ linh môn là tổ hợp cực thích hợp. Lão cũng nói rõ Yến gia đã bị Quỷ linh môn chú ý từ lâu, trong khi Khương quốc và Xa Kỵ quốc mất liên lạc vì ma đạo lục tông dùng nội ứng phối hợp tập kích, cho thấy Việt quốc sắp bị xâm lấn. Hy vọng trông cậy Chính đạo liên minh cũng bị bác bỏ, vì liên minh này ở Phong Đô quốc đang khuếch trương sang nước khác. Huyền Dạ phân tích rằng theo thất đại phái Việt quốc chưa chắc có lợi, còn cự tuyệt Quỷ linh môn sẽ rước họa, nên đề nghị Yến gia gia nhập Quỷ linh môn nhưng phải dùng Sinh tử chú để ràng buộc Thiếu chủ Quỷ linh môn và hai tu sĩ Kết Đan. Yến gia lão tổ chấp thuận, phái Yến Như Yên, Yến Văn và Yến Kì đến phòng khách hạ Sinh tử chú, đồng thời chuẩn bị đại trận để vây giết nếu đàm phán thất bại. Yến Như Yên tự tin nhờ Tử vân kỳ hộ thân, sau đó truyền âm phù báo việc trao đổi Sinh tử chú đã thành công. Khi người Quỷ linh môn muốn đến Nghị sự đường gặp lão tổ, Yến gia lão tổ cho các trưởng lão và quản sự rời đi, chỉ giữ Huyền Dạ lại hỗ trợ ứng đối."},{"chuong":257,"tieuDe":"Huyết Tế Dữ Diễm Lệ Nam Tử","tomTat":"Yến gia lão tổ tiếp Vương Thiền và Yến Như Yên sau khi Yến gia đã đáp ứng quy phụ Quỷ Linh môn, nhưng vẫn giữ thái độ dè dặt trước Thiếu chủ. Vương Thiền thông báo ma đạo lục tông sắp chính thức tiến công Việt quốc, buộc Yến gia phải nhanh chóng di dời lực lượng cốt lõi và che giấu hành tung trước bảy đại phái. Hắn đề xuất dùng Âm Hỏa đại trận luyện hóa hơn hai trăm tu sĩ Trúc Cơ trong Yến gia bảo, giữ hồn phách để giúp Yến Như Yên Trúc Cơ và tu luyện Huyết Linh đại pháp, khiến Yến gia lão tổ và Huyền Dạ lạnh người. Huyền Dạ và Yến gia lão tổ từ chối để Yến gia tự tay giết toàn bộ khách mời, nhưng đồng ý gom đệ tử bảy phái lại cho Quỷ Linh môn xử trí, còn Vương Thiền coi số hồn phách ấy là sính lễ dành cho Yến Như Yên. Sau phần thương lượng, Hàn Lập đi đường tắt về khách điếm thì bắt gặp Yến Vũ, Phong sư huynh, Đổng Huyên Nhi và một nam tử áo tím cực kỳ diễm lệ đang giằng co trong ngõ nhỏ. Đổng Huyên Nhi gần như nằm trong ngực nam tử lạ và mê say nhìn hắn, còn Yến Vũ cùng Phong sư huynh vội cầu Hàn Lập giúp tách nàng ra vì sợ mất nàng. Dù muốn tránh phiền phức, Hàn Lập nhớ lời Hồng Phất từng dặn phải quản thúc Đổng Huyên Nhi nên không thể làm ngơ."},{"chuong":258,"tieuDe":"Mê Hồn","tomTat":"Hàn Lập nhận ra Đổng Huyên Nhi cư xử khác thường, mê luyến nam tử diễm lệ và xem mình như người xa lạ, trong khi đối phương có tu vi Trúc Cơ trung kỳ. Hắn công khai chất vấn nam tử kia dùng phương pháp mê hồn với người của bảy đại phái, khiến Yến Vũ và Phong sư huynh lập tức lấy pháp khí chuẩn bị ra tay. Cảm thấy đối thủ nguy hiểm, Hàn Lập truyền âm nhắc tới Hồng Phất sư bá để đánh thức Đổng Huyên Nhi, khiến nàng hoảng sợ thoát khỏi nam tử diễm lệ và chạy đến nấp sau lưng hắn. Nam tử diễm lệ thấy khó đoạt lại nàng và không muốn giao chiến gây chú ý nên ghi nhớ diện mạo ba người rồi dùng hào quang ngũ sắc rời đi. Tại Phong Duyệt khách điếm, Đổng Huyên Nhi kể rằng chỉ nhìn đối phương một lần đã mất ý chí phản kháng và toàn tâm muốn lấy lòng hắn. Hàn Lập suy luận Mê Tâm thuật tuy lợi hại nhưng nhiều khả năng chỉ hữu hiệu với nữ tử, nếu không đối phương đã không dễ dàng bỏ qua ba người. Đổng Huyên Nhi tạm an tâm khi được Yến Vũ và Phong sư huynh hứa bảo hộ, nhưng Hàn Lập cũng nhận thấy Hồ mị thuật của nàng là một dạng mê thuật nguy hiểm không kém."},{"chuong":259,"tieuDe":"Phong Động","tomTat":"Hàn Lập suy xét việc Đổng Huyên Nhi bị nam tử diễm lệ khống chế sau khi đối mắt, đối chiếu với Thiên Nhãn thuật và Mê hồn thuật rồi nhận ra chuyện này rất bất thường nếu đối phương chỉ là Trúc Cơ trung kỳ. Bên ngoài khách điếm, đại hội đoạt bảo được thông báo chia làm hai tổ: tu sĩ Việt quốc đến núi phía tây, tu sĩ nước khác đến núi phía đông. Trong bóng tối, Quỷ Linh môn bố trí Âm Hỏa đại trận tại ngọn núi phía tây Yến Linh Bảo, còn Vương Thiền cùng Lý thị huynh đệ tính dùng trận pháp vây phần lớn tu sĩ và để Quỷ Linh thập nhị vệ xử lý người thoát. Cùng lúc, Hoàng Phong Cốc và sáu phái còn lại chuyển sang trạng thái khẩn cấp, các đội tu sĩ xuất phát trong đêm và bảy đại phái ép các gia tộc giao đệ tử kiệt xuất. Sáng hôm sau Hàn Lập tới trường đấu, gặp Ba Tính của Cự Kiếm môn, quan sát đại pháp trận và vì cảm thấy khí tức bất an nên tránh xa đám đông. Đổng Huyên Nhi và Phong sư huynh sau đó mới tới, còn Yến Vũ vắng mặt bất thường. Khi thuộc hạ báo còn thiếu hai người, Vương Thiền không chờ thêm mà ra lệnh mở trận, đồng thời phái số tám và số mười hai trong Quỷ Linh thập nhị vệ đi truy sát hai tu sĩ không đến."},{"chuong":260,"tieuDe":"Quyển Sáo","tomTat":"Thuộc hạ Quỷ Linh môn báo với Vương Thiền rằng còn ba tu sĩ đứng quá xa nên chưa thể bị Âm Hỏa đại trận khống chế, gồm đôi nam nữ Yểm Nguyệt tông và Hàn Lập. Vương Thiền sai người giả làm người Yến gia hô gọi khách tham dự đại hội tới báo danh, khiến phần lớn tu sĩ và đôi nam nữ Yểm Nguyệt tông bước vào phạm vi cấm chế, còn Hàn Lập vẫn đứng ngoài quan sát. Hàn Lập nhận ra móng tay xanh biếc của kẻ giả trang giống quái nhân tóc vàng Quỷ Linh môn từng gặp, liền đoán đây là bẫy và lấy Thần Phong Chu chuẩn bị thoát thân. Vương Thiền xuất hiện trên cự xoa xanh biếc tỏa hắc khí, chặn Hàn Lập và tuyên bố hắn đã vào trận, còn Âm Hỏa đại trận cũng hiện màn đen bao phủ khu vực pháp trận. Hàn Lập tự xét không thể đối đầu Vương Thiền cùng nhiều thuộc hạ, nên quyết định chạy về Hoàng Phong Cốc báo tin Quỷ Linh môn cấu kết Yến gia, còn an nguy Đổng Huyên Nhi và Phong sư huynh phải trông vào sư phụ họ. Vương Thiền thi triển Huyết Linh Đại pháp hóa huyết vụ thành mây máu truy sát, khiến Hàn Lập phát hiện tốc độ độn thuật của đối phương còn nhanh hơn Thần Phong Chu khi toàn lực bỏ chạy."},{"chuong":261,"tieuDe":"Huyết Linh Đại Pháp","tomTat":"Hàn Lập dùng Thần Phong Châu hóa bạch quang bỏ chạy, nhưng Vương Thiền điều khiển Huyết Vân bằng Huyết Linh Đại Pháp bám sát phía sau và không ngừng rút ngắn khoảng cách. Hàn Lập ném Liên Châu Hỏa Cầu Phù để nổ tan một phần Huyết Vân, song Vương Thiền lập tức phóng Bích Âm Thoa truy kích, buộc hắn phải đổi sang phòng thủ. Khi Huyết Vân phình to và bao vây cả người lẫn pháp khí, Hàn Lập lấy Ô Long Đoạt đối kháng, phá Âm Ma Ti và bóp nát nhiều Huyết Quỷ. Hắn nhanh chóng phát hiện Huyết Quỷ bị diệt vẫn tái sinh từ Huyết Vân, còn Linh Huyết trong đó có thể khiến Ô Long Đoạt mất khống chế. Hàn Lập tiếp tục dùng linh thạch bậc trung, sơ cấp phù lục và hỏa xà để thử mở đường, nhưng hắc sắc khô lâu đầu của Vương Thiền phun hắc khí chặn pháp thuật. Cuối chương, một luồng mê vụ xanh đỏ dày đặc bùng ra quanh Hàn Lập, che khuất thân hình và hành động của hắn trong lúc Vương Thiền bắt đầu nghi ngờ thủ đoạn mới này."},{"chuong":262,"tieuDe":"Thoát Thân","tomTat":"Vương Thiền mất kiên nhẫn khi tiểu quỷ không tìm được Hàn Lập trong Huyết Vân, bèn hao tinh huyết thúc Huyết Linh Đại Pháp làm mây máu xoay xiết và hấp thu mê vụ. Hàn Lập lộ thân trong màn sáng Lân Thuẫn nhưng đã kịp khởi dụng tiểu đao Phù Bảo, phối hợp phù lục hỏa long phá tan Huyết Vân để thoát ra. Vương Thiền dùng Huyết Độn truy kích, lấy kim khô lâu đầu Phù Bảo giữ vệt sáng vàng của Hàn Lập, nhưng Mạc Giao chi Độc từ mê vụ Thanh Hỏa Chướng phát tác khiến hắn phải bỏ chạy. Hàn Lập thu được kim khô lâu đầu Phù Bảo, sau đó nhận ra độc đã cứu mình và hối hận vì không nhân cơ hội giết Vương Thiền. Vương Thiền gặp hai trưởng lão họ Lý và được bức độc, nhưng hiểu lầm Hàn Lập cố ý đặt bẫy nên hận hắn thấu xương. Khi trở về nơi mai phục, Vương Thiền biết nhóm Hợp Hoan Tông do Điền Bất Khuyết cầm đầu đã cướp hai nữ tu sĩ bị chế phục, nên đưa cả Hàn Lập lẫn Điền Bất Khuyết vào danh sách phải giết và ra lệnh báo Yến gia lão tổ rút lui. Hàn Lập vội bay về Hoàng Phong Cốc, nhưng giữa đường gặp nhóm tu sĩ Hóa Đao Ổ và Yểm Nguyệt Tông rồi bị một tu sĩ Trúc Cơ Hậu Kỳ cầm đầu điều động."},{"chuong":263,"tieuDe":"Thực Lực","tomTat":"Hàn Lập kiểm tra Trưng Điệu Lệnh do Tuyên Nhạc đưa ra, biết Ma Đạo Lục Tông đã xâm nhập Việt quốc và hiểu bản thân khó thoát khỏi cuộc sát phạt vì là đệ tử bảy phái. Tuyên Nhạc yêu cầu hắn báo danh, nhận ra hắn từ lần Huyết Sắc Thí Nghiệm khi đi theo Nghê Thường, rồi buộc hắn gia nhập đội chi viện. Hàn Lập nhân đó thuật lại biến cố Yến Linh Bảo, khiến Tuyên Nhạc và mọi người kinh sợ, lập tức phái hai đệ tử Luyện Khí Kỳ đi báo tin cho các phái. Đội chi viện tiếp tục nhiệm vụ tăng cường phòng thủ một linh thạch khoáng trữ lượng lớn, sau vài ngày đến hoang nguyên trong lãnh nội Việt quốc và vào hiệp cốc được trận pháp che phủ. Tại đó, họ gặp Từ Hưng của Thiên Khuyết Bảo, biết lực lượng thủ vệ cũ rất mỏng nên Tuyên Nhạc bố trí thêm Tứ Sát Trận và chia nhóm tuần tra. Hàn Lập nhận ra nhiệm vụ không phải chính diện liều mạng với Ma Đạo nên tạm yên tâm, đồng thời tự đánh giá lại điểm yếu sau trận với thiếu chủ Quỷ Linh Môn. Trong bối cảnh chiến loạn, hắn tạm gác Thanh Nguyên Kiếm Quyết, ưu tiên tu luyện Đại Diễn Quyết để tận dụng cơ quan khôi lỗi và bắt đầu thử chế tác cơ quan thú sơ cấp."},{"chuong":264,"tieuDe":"Cơ Quan Khôi Lỗi Và Đại Diễn Quyết","tomTat":"Trên hoang nguyên cách linh thạch khoáng gần trăm dặm, Hàn Lập dùng cơ quan thú hình thằn lằn săn thằn lằn rồi thi triển Khiên Hồn Thuật rút hồn phách, thu quang cầu xanh lục vào bình ngọc nhỏ. Qua việc nghiên cứu Khôi Lỗi Chân Kinh, hắn hiểu rằng khôi lỗi muốn có linh tính phải dung luyện hồn phách sinh linh, nên ba thuật Khiên Hồn, Ngưng Hồn và Luyện Hồn trở thành khâu quan trọng trong luyện chế. Sau khi tu luyện Đại Diễn Quyết và phân ra thần niệm độc lập, Hàn Lập đã tự luyện thành cơ quan thú đầu tiên, có thể ký gửi phân thần lên khôi lỗi để cảm ứng điều nó thấy nghe và ra lệnh như chỉ huy bộ hạ. Hắn cũng nhận ra khôi lỗi có nhược điểm là chỉ hoạt động quanh bản thể trong phạm vi khoảng ba dặm và phản ứng có độ trễ, nhưng nếu có nhiều khôi lỗi cấp thấp thì vẫn rất hữu dụng khi đối phó biển người, nhất là huyết quỷ của thiếu chủ Quỷ Linh Môn. Nhớ đến cự hổ khôi lỗi uy lực lớn của Hoàng Long từng bị Lôi sư bá phá hủy, Hàn Lập càng hứng thú với khôi lỗi cao cấp và quyết định thử luyện khôi lỗi cấp hai bằng thiết mộc lâu năm cùng hồn phách thằn lằn. Sau ba bốn tháng khổ luyện, hắn nhận định Đại Diễn Quyết mới là mấu chốt của khôi lỗi thuật vì vừa nuôi lớn nguyên thần vừa giúp phân thần niệm an toàn, qua đó hiểu vì sao Thiên Trúc Giáo xem pháp quyết này là căn bản lập giáo."},{"chuong":265,"tieuDe":"Chiến Huống","tomTat":"Hàn Lập dựa vào Đại Diễn Quyết để suy tính khả năng phân thần điều khiển khôi lỗi, nhận ra Khôi Lỗi Thuật có thể tăng mạnh chiến lực Trúc Cơ kỳ nhưng khó uy hiếp Kết Đan kỳ nếu thiếu khôi lỗi cấp cao, tài liệu và hồn phách khổng lồ. Trong thời gian trấn thủ linh khoáng Đại Hiệp Cốc, hắn dần nắm được toàn cảnh chiến tranh giữa Ma Đạo lục tông và Việt Quốc thất phái: Linh Thú Sơn vốn là phân nhánh cũ của Ngự Linh Tông nhưng đã phối hợp với lục phái còn lại để lừa Ma Đạo vào mai phục. Sau thất bại ban đầu, Ma Đạo phát động đại công khiến hai bên đánh liên tiếp ở ranh giới Việt Quốc với Khương Quốc và Xa Kỵ Quốc, thương vong cực lớn, cho đến khi viện quân Nguyên Vũ Quốc, Tử Kim Quốc và các nước lân cận đến giúp thế cục chuyển thành tiêu hao chiến. Linh khoáng nơi Hàn Lập đóng giữ yên ổn bất thường nên thất phái phái thêm hai mươi tu sĩ do Lỗ Thiên Mông dẫn đầu tới tăng viện, trong đó có Trung Ngô, người từng biết Hàn Lập ở Huyết Sắc Thí Luyện và nay phải gọi hắn là tiền bối. Một tháng sau, Hàn Lập gần viên mãn tầng một Đại Diễn Quyết và luyện thành con khôi lỗi thú cấp hai đầu tiên sau hơn mười lần thất bại. Đúng lúc hắn đang tĩnh tọa, báo động Ma Đạo tập kích vang lên, buộc toàn bộ tu sĩ ra ngoài chuẩn bị tiếp chiến. Hàn Lập thấy Tuyên Nhạc và Lỗ Thiên Mông đứng dưới Tứ Sát Trận quan sát khoảng hai ba mươi địch nhân phía trên Đại Hiệp Cốc, rồi nhận định đối phương dám đánh sâu hậu phương thì hẳn có thực lực cao, khiến phe phòng thủ rơi vào thế bất lợi."},{"chuong":266,"tieuDe":"Kích Đấu","tomTat":"Trước hạp cốc, phe thất phái dựa vào chín tu sĩ Trúc Cơ trung kỳ, hơn sáu mươi tu sĩ Luyện Khí kỳ và bốn sát trận để phòng thủ linh quáng, còn Tuyên Nhạc dẫn Hàn Lập cùng các tu sĩ tới quan sát địch tình. Lữ Thiên Mông nhận ra đội áo hồng và áo vàng là Ma Diễm môn cùng Thiên Sát tông, khiến Hàn Lập lập tức đề phòng. Hoàng sam lão giả phái mười hoàng y tu sĩ dùng pháp khí oanh kích tứ sát trận từ ngoài trận, còn Tuyên Nhạc chia quân vừa chống phá trận vừa canh chừng Ma Diễm môn. Hàn Lập dùng Kim nhận giao thủ với tu sĩ trung niên Thiên Sát tông, vẫn giữ thế khá nhẹ nhàng và tranh thủ quan sát toàn cục. Nhóm hồng y nhân Ma Diễm môn bày trận với đại kỳ đỏ rực để phóng Thanh dương ma hỏa, khiến Lữ Thiên Mông kinh hãi thả hai phi thiên ngô công ngăn cản nhưng cả hai đều bị bóng trắng ẩn thân chém nát. Sau khi dùng Linh quang thuật, Hàn Lập nhìn ra các bóng trắng đang thả ngân ti khống chế pháp khí và bảo vệ đội hồng y nhân. Đối thủ Thiên Sát tông tức giận vì Hàn Lập phân tâm nên tung viên châu trắng phóng lớn đánh xuống, buộc Hàn Lập dùng kiếm quang rồi Ô long đoạt chống đỡ. Cuối chương, Thanh dương ma hỏa đã thi pháp thành công, ngọn lửa xanh hướng về Lữ Thiên Mông trong khi lớp bóng trắng vẫn chưa bị phá, khiến thế trận thất phái trở nên nặng nề."},{"chuong":267,"tieuDe":"Ma Hỏa Sính Uy","tomTat":"Lữ Thiên Mông nhận ra đại kỳ của Hồng y nhân là mối nguy lớn nên hô toàn bộ tu sĩ thất đại phái rút về Tứ sát trận, Tuyên Nhạc cũng ra lệnh triệt tiêu. Nhiều người còn bị địch thủ dây dưa ngoài trận, riêng Hàn Lập dùng Bạch lân thuẫn mượn thế công của tu sĩ Thiên Sát Tông để thoát vào đại trận. Các Hồng y nhân phóng Thanh dương ma hỏa, tách hỏa cầu xanh đánh vào tu sĩ ngoài trận khiến pháp khí, phù lục và hộ thuẫn tan rã, phe thất đại phái mất nhiều Luyện khí kỳ cùng một Trúc Cơ kỳ. Ma hỏa tiếp tục hợp lại công kích Tứ sát trận, làm cấm chế dần ảm đạm, trong khi Lữ Thiên Mông giải thích loại hỏa này cần Thanh dương ma hỏa quyết và tiêu hao tu vi rất lớn. Khi phe phòng thủ không muốn đầu hàng vì sợ ma đạo luyện hồn phách, Dư Hưng tiết lộ một thông đạo cũ trong linh quáng có thể thoát ra ngoài mấy chục dặm. Tuyên Nhạc và Lữ Thiên Mông xác nhận rồi dẫn hơn năm mươi tu sĩ rút vào đường hầm, dự định hủy động khẩu để trì hoãn ma đạo khai thác mỏ. Không lâu sau Tứ sát trận bị phá, đường hầm rung chuyển bởi tiếng nổ lớn và sụp xuống trong bóng tối. Vài canh giờ sau, Hàn Lập dùng khôi lỗi thằn lằn dò đường rồi thoát ra một hang động thiên nhiên trên vách đá, may mắn sống sót sau đại nạn."},{"chuong":268,"tieuDe":"Bạch Tri Thù","tomTat":"Hàn Lập sống sót sau khi đường hầm dưới linh quáng sụp đổ nhờ kịp tạo vòng bảo hộ, rồi dùng Khôi lỗi thú thằn lằn dò đường vì không biết Thổ độn thuật. Trên mặt đất, Liên Phi Hoa đã dùng Hám địa phù để khiến người thất đại phái khó thoát, trong khi ma đạo tiếp tục phá linh quáng, tập kích dược viên bí mật và khiến chiến sự với thất đại phái leo thang. Hàn Lập lần theo luồng gió trong động thạch nhũ, gặp nhóm Tuyên Nhạc, Lữ Thiên Mông, Chung Ngô và cùng họ đi về phía tiếng kêu thảm. Trong nhũ động lớn, cả nhóm phát hiện Bạch tri thù đang ăn xác một đệ tử Yểm Nguyệt Tông; phía sau yêu thú là quặng linh thạch, lục giác truyền tống trận cổ, năm hài cốt và các lệnh bài màu lam. Một đệ tử Yểm Nguyệt Tông phẫn nộ tấn công trước nhưng không làm yêu thú bị thương, buộc mọi người hợp lực công kích. Bạch tri thù thể hiện phòng ngự cực mạnh, chỉ chịu vài vết thương nhỏ trong khi pháp khí của nhóm bị hao tổn, khiến Tuyên Nhạc và Lữ Thiên Mông quyết định rút lui. Đúng lúc đó, yêu thú phun chất lỏng trắng hóa thành mạng nhện phong kín cửa động duy nhất, đẩy toàn bộ nhóm tu sĩ vào thế bị nhốt trong nhũ động."},{"chuong":269,"tieuDe":"Huyết Sắc","tomTat":"Chung Ngô lo Bạch tri thù muốn bắt trọn nhóm tu sĩ, còn Tuyên Nhạc thử dùng hỏa cầu phá mạng nhện ở cửa động nhưng không để lại dấu vết, khiến đường lui gần như bị khóa. Tuyên Nhạc tiếp tục dùng phù lục màu vàng điều động đá lớn ép Bạch tri thù vào đỉnh động, tạo cơ hội cho Lữ Thiên Mông dùng Túi nhật nguyệt thu yêu thú vào trong. Túi nhật nguyệt nhanh chóng biến dạng rồi nổ tung, Bạch tri thù phá pháp khí thoát ra, thân thể chuyển đỏ và trở nên cuồng bạo thành Huyết tri thù. Yêu thú dùng tốc độ kinh người phá vòng bảo hộ, giết Chung Ngô cùng nhiều tu sĩ khác, khiến trong động cuối cùng chỉ còn Hàn Lập, Tuyên Nhạc và Lữ Thiên Mông. Lữ Thiên Mông chặn được một trảo nhờ vật giống xác rùa, Hàn Lập né yêu thú bằng thân pháp biến mất, còn Tuyên Nhạc nhân cơ hội dùng Già thiên chung giam Huyết tri thù và Hàn Lập thả Ô long đoạt canh phòng bên ngoài. Khi tình thế vừa tạm lắng, Lữ Thiên Mông tế phù bảo tiểu thước xanh rồi lộ ý định giết Hàn Lập và Tuyên Nhạc để độc chiếm bảo vật. Nhưng trước khi hắn ra tay trọn vẹn, Huyết tri thù đã thoát khốn từ dưới đất sau lưng và chém Lữ Thiên Mông làm hai."},{"chuong":270,"tieuDe":"Trảm Sát","tomTat":"Sau khi Lữ Thiên Mông đột tử, tiểu thước phù bảo mất linh lực duy trì và rơi xuống giữa Hàn Lập, Tuyên Nhạc cùng Huyết tri thù. Tuyên Nhạc thừa nhận đã cố ý thả yêu thú, dùng lụa mỏng đỏ che giấu khí tức để khiến Huyết tri thù chỉ truy kích Hàn Lập. Hàn Lập lập tức tế lân thuẫn và khôi lỗi, lao thẳng về phía Tuyên Nhạc, dùng khôi lỗi kéo giãn yêu thú, rồi lấy Thanh ngưng kính khắc chế Già thiên chung. Trong địa hình nhũ động chật hẹp, hắn né Băng vũ thuật, áp sát Tuyên Nhạc, dùng pháp khí tự bạo luyện từ sừng Mặc giao phá hủy hỏa hồng hộ giáp và chém đầu đối phương bằng thanh nguyên kiếm quang. Sau đó Hàn Lập chuyển sang đối phó Huyết tri thù, dùng Ô long đoạt cùng khôi lỗi thú kéo dài tiêu hao đến khi yêu thú cạn chân nguyên, rồi lấy ngân kiếm chém đầu nó. Nhìn thi thể tu sĩ đầy nhũ động, hắn cảm nhận rõ sự mong manh của sinh mệnh người tu tiên. Nghỉ lại một lúc, Hàn Lập thu tiểu thước phù bảo và túi trữ vật từ các thi thể, cuối cùng tiến gần Truyền tống trận, chú ý năm bộ hài cốt cùng các lệnh bài và nhớ lại tên Đại na di lệnh do Lữ Thiên Mông từng nhắc."},{"chuong":271,"tieuDe":"Đại Na Di Lệnh Hòa Cổ Truyện Tống Trận","tomTat":"Hàn Lập nhận ra Đại na di lệnh là vật cực kỳ trân quý nên thận trọng dùng Kim nhận thăm dò hài cốt ngũ sắc rồi mới lấy lệnh bài xanh lam vào tay. Hắn phát hiện Truyền tống trận trong hang bị hư một góc, liền sao chép dạng thức và hoa văn vào ngọc giản để sau này tìm người sửa, đồng thời thu được hai trứng nhện yêu thú. Trước khi rời đi, Hàn Lập thiêu hủy thi thể Tuyên Nhạc, Lữ Thiên Mông và hài cốt ngũ sắc, thu thêm hạt châu nhiều màu rồi dùng Thanh Nguyên kiếm quang phá kín cửa động để che giấu bí mật. Sau bảy tám ngày, hắn trở về Hoàng Phong cốc, biết đợt đại chiến thứ hai đã bắt đầu và môn phái thời chiến xử phạt rất nghiêm những kẻ trốn nhiệm vụ. Trong động phủ, Hàn Lập đặt trứng nhện vào Linh nhãn chi tuyền, luyện thành tầng thứ nhất Đại Diễn quyết, đồng thời Thanh Nguyên kiếm quyết đột phá tầng năm khiến hắn tiến vào Trúc Cơ trung kỳ. Tại Thiên Tri các, hắn tra ra Đại na di lệnh là pháp khí bảo vệ tu sĩ cổ khi truyền tống siêu xa, từ đó suy đoán trận trong hang là cổ Truyền tống trận có thể giúp mình rời xa chiến cuộc. Dù không tìm được tư liệu sửa trận trong sách, cuối chương Hàn Lập nhớ tới một người có lẽ có khả năng giúp mình sửa chữa trận pháp này."},{"chuong":272,"tieuDe":"Một Năm","tomTat":"Hàn Lập ở Thiên Tri các suy nghĩ cách sửa Truyền tống trận pháp thượng cổ và nhớ tới Tề Vân Tiêu cùng vị bằng hữu Trận pháp sư tinh thông Điên Đảo Ngũ Hành trận. Trở về động phủ, hắn phát hiện hai trứng nhện lớn lên nhờ Linh nhãn chi tuyền nên vẽ pháp trận khống thần, nhỏ tinh huyết cho chúng hấp thu rồi nhận phù truyền âm gọi tới Nghị Sự điện. Một năm sau, Hàn Lập đã bị giữ lại tại chiến trường Kim Cổ nguyên giữa thất phái và lục tông, thường xuyên tham gia đại chiến và các cuộc săn giết tu sĩ Trúc Cơ kỳ. Trong một lần giao chiến, hắn dùng hai đạo hắc quang cùng kim nhận giết một đệ tử Trúc Cơ sơ kỳ Quỷ Linh môn, lấy túi trữ vật rồi lập tức rút lui trước khi trời tối vì sợ tu sĩ Kết Đan kỳ hai phe xuất chiến. Chiến trường trong năm qua tiêu hao nặng tu sĩ Trúc Cơ của cả hai bên, còn lực lượng Kết Đan và Luyện Khí được giữ lại khiến quyết chiến ngày càng gần. Hàn Lập về doanh trại bằng Thần Phong chu, phong bế thạch ốc, kiểm kê chiến lợi phẩm rồi đem vật không dùng được tới khu giao dịch đổi linh thạch. Tại quầy của Trần mập, hắn dùng đủ năm trăm linh thạch đổi Long Ngâm thảo, đồng thời tiếp tục hỏi về đan phương hữu dụng cho Trúc Cơ kỳ nhưng chưa có tin mới. Dù vậy, chợ giao dịch tiền tuyến đã giúp hắn gom dược tài cho Tụ Linh đan và từng mua được hai phương thuốc cổ, mở ra cơ hội tăng mạnh pháp lực."},{"chuong":273,"tieuDe":"Xảo Ngộ","tomTat":"Hàn Lập đã vét sạch linh thạch, lấy cả dược thảo bốn trăm năm và chiến lợi phẩm từ nhiệm vụ liệp sát ma đạo để đổi tài nguyên, nhờ đó gom đủ phần lớn nguyên liệu còn thiếu cho các phương thuốc cổ. Trong một năm giao tranh, hắn dựa vào phù bảo và Đại Diễn quyết nhiều lần giết tu sĩ ma đạo Trúc Cơ sơ kỳ, trung kỳ, gặp Trúc Cơ hậu kỳ cũng có thể thoát thân, vì vậy bắt đầu nổi danh trong giới Trúc Cơ thất phái. Tại sở giao dịch, Hàn Lập gặp lại Trần sư muội khi nàng mang túi trữ vật giao cho Trần mập, còn Trần mập sau đó giải thích với nàng về chiến tích hiện tại của Hàn Lập và muốn tiến cử hắn với Trần thị. Hàn Lập tiếp tục đến chỗ ở của Lý Hóa Nguyên để vấn an, trong lúc hồi tưởng lại việc sư phụ từng tra xét tốc độ tu luyện bất thường của mình nhưng không phát hiện nguyên nhân. Ngoài cửa, Tống Mông báo sư phụ đang tiếp khách rồi lại muốn luận bàn với Hàn Lập vì công pháp tiến triển. Khi bảy tu sĩ Kết Đan rời phòng, một nữ tu đeo khăn che mặt được gọi là Nam Cung tiên tử nhìn thấy Hàn Lập thì chấn động dừng bước, khiến Hàn Lập cũng kinh động trong lòng."},{"chuong":274,"tieuDe":"Phó Ước","tomTat":"Nam Cung Uyển phủ nhận quen biết Hàn Lập trước mặt mọi người, chỉ nói hắn giống một cố nhân rồi rời đi, khiến các tu sĩ hiện diện vẫn khó hoàn toàn tin tưởng. Sau khi khách khứa tản đi, Lý Hóa Nguyên gọi Hàn Lập vào hỏi riêng; Hàn Lập thừa nhận từng ngẫu nhiên quen Nam Cung Uyển nhưng lấy lời hứa giữ bí mật để không kể rõ chuyện riêng của nàng. Lý Hóa Nguyên không ép đệ tử thất tín, song cảnh báo hắn nên ít tiếp xúc Nam Cung Uyển vì lo Nhân Mị công của Yểm Nguyệt tông có thể ảnh hưởng thần trí. Sau đó, ông giao Hàn Lập làm bảo tiêu cho hậu nhân phàm tục của một sư huynh từng cứu mạng mình, do ma đạo lục tông có thể phái đệ tử cấp thấp vào thế tục thanh tẩy những phàm nhân được thất phái trợ giúp. Hàn Lập nhận ngọc giản tư liệu và được tính là ra ngoài chấp hành nhiệm vụ, nhưng trước khi đến Việt đô, hắn dùng thời gian tự do rẽ sang Nguyên Vũ quốc để phó ước Tề Vân Tiêu, nhằm xem có thể sửa pháp trận hư hỏng nghi là cổ truyền tống trận hay không. Sau bảy tám ngày đêm dùng Thần Phong chu phi hành, hắn tới Kim Mã thành, thu pháp khí ngoài thành, đổi sang dáng vẻ nho sinh rồi vào thành hỏi đường đến Thanh Tuyền trà quán."},{"chuong":275,"tieuDe":"Trà Hương","tomTat":"Hàn Lập đi vào một quán trà nhỏ ở Kim Mã thành vì nhận ra hương trà có linh khí nhàn nhạt, lại thấy quán có quy định mỗi người mỗi ngày chỉ được một ấm nên càng chú ý. Hắn gặp chưởng quầy, đưa ra ngọc bội xanh làm tín vật và được nhận ra là Hàn tiền bối mà Tề Vân Tiêu đã dặn chờ. Chưởng quầy dẫn hắn rời thành, đi qua vùng đồi núi phía tây tới thung lũng có thạch ốc, trúc xanh và cấm chế bảo vệ. Tề Vân Tiêu xuất hiện sau một lần thử luyện thất bại, vui mừng mời Hàn Lập vào phòng. Hàn Lập trả lại Vân Tiêu tâm đắc còn nguyên cấm chế, còn Tề Vân Tiêu giao bộ pháp khí bố trận Điên Đảo Ngũ Hành trận đã cải tiến, uy lực đạt khoảng một phần ba trận pháp nguyên bản. Hàn Lập kiểm tra trận kỳ, trận bàn và rất hài lòng vì bộ trận đủ giá trị làm thủ đoạn phòng thân. Cuối chương, Hàn Lập uống trà linh khí do chưởng quầy dâng lên và được Tề Vân Tiêu cho biết lá trà không phải do hắn chế ra, mà là quà của một người bạn đã mất mười năm nghiên cứu ở thế gian."},{"chuong":276,"tieuDe":"Xuất Thủ","tomTat":"Hàn Lập nhân chuyện linh trà mà dẫn dắt Tề Vân Tiêu nói về chí hữu tinh thông trận pháp, biết người ấy từng nhờ linh thảo ngàn năm của mình giữ mạng nhưng thương thế vẫn chưa khỏi. Tề Vân Tiêu muốn dùng các loại trận kỳ đổi linh thảo lâu năm, còn Hàn Lập nhận ra đây là cơ hội tạo nhân tình để nhờ đối phương chữa Truyền tống trận. Đúng lúc ấy, nha hoàn của Âm nhi chạy tới báo tiểu thư gặp nạn ở Bích Vân sơn, nơi nàng lên hái lá trà chế linh trà rồi bị nhóm tu sĩ Luyện Khí kỳ nhận ra là trận pháp sư và truy bắt. Tề Vân Tiêu xác nhận Âm nhi chính là người cùng hắn chế tạo Điên Đảo Ngũ Hành, nên khẩn cầu Hàn Lập cứu viện. Hàn Lập dùng Thần Phong chu chở hai người tới rừng cây, thấy nhóm truy đuổi đang công kích trận pháp phòng hộ của Âm nhi. Vì lo để lại hậu hoạn, hắn quyết định diệt sạch đối phương, phóng hai đạo hắc quang cùng sáu đạo kim quang giết toàn bộ trong khoảnh khắc. Khi pháp khí còn chưa hạ hẳn, Tề Vân Tiêu đã lao vào rừng và khẩn trương gọi Âm nhi."},{"chuong":277,"tieuDe":"Tân Như Âm","tomTat":"Hàn Lập nhìn Tề Vân Tiêu vội vã vào rừng và nhận ra đối phương có tình cảm nam nữ sâu nặng với nữ trận pháp sư được cứu. Tề Vân Tiêu, nha hoàn và Tân Như Âm ra gặp hắn, Tân Như Âm tự xưng tên và cảm tạ ân cứu giúp. Vì lo nhóm bị giết có lai lịch hoặc trưởng bối ở gần, Hàn Lập dùng hỏa cầu thiêu sạch thi thể rồi để nha hoàn thu nhặt các túi trữ vật còn lại. Trên đường rời đi, Tân Như Âm mời Hàn Lập và Tề Vân Tiêu đến chỗ ở để đáp tạ, còn Hàn Lập thuận theo vì muốn nhờ nàng xử lý việc Truyền tống trận. Tại nhà trúc giữa núi, Hàn Lập nhận thấy nơi ở của nàng có thể có trận pháp phòng bị, đồng thời trêu Tề Vân Tiêu về sự si tình. Tân Như Âm thay y phục trắng ra kính trà, khéo léo dò xét lai lịch Hàn Lập nhưng bị hắn né tránh. Cuối chương, Hàn Lập không nhận ngay trận kỳ, trận bàn mà đề nghị dùng một gốc linh thảo tám trăm năm chữa bệnh cho Tân Như Âm để đổi lấy việc nàng giúp hắn một việc riêng."},{"chuong":278,"tieuDe":"Bán Niên Chi Ước","tomTat":"Tân Như Âm vì chứng bệnh lâu năm mà động tâm trước linh thảo của Hàn Lập nhưng vẫn cảnh giác, chỉ chịu giúp nếu yêu cầu không trái đạo nghĩa. Hàn Lập nói rõ hắn chỉ cần nàng chữa trị một món đồ liên quan đến trận pháp, rồi đưa ra ngọc giản chứa bản vẽ phục chế của trận pháp không thể di chuyển. Tân Như Âm xem ngọc giản thì nhận ra đó là cổ truyền tống trận, đồng thời phán đoán phần hư hại không lớn và thuộc loại nàng từng học qua nên có hy vọng phục hồi. Nàng cần nửa năm nghiên cứu, Hàn Lập chấp thuận và hẹn sau nửa năm quay lại lấy bản vẽ đã chữa trị. Trước khi rời đi, Hàn Lập nhắc Tề Vân Tiêu và Tân Như Âm nên đổi nơi ở vì việc mấy tu sĩ bị giết có thể kéo người tới điều tra. Sau đó hắn ngự pháp khí bay về Việt quốc, mạch truyện chuyển sang giới thiệu Việt Kinh, đô thành lớn nhất của Việt quốc, cùng cách phân chia Đông, Tây, Nam, Bắc trong kinh thành."},{"chuong":279,"tieuDe":"Đại Phú Tần Trạch","tomTat":"Việt Kinh được phác họa qua sự đối lập giữa khu phía Tây nghèo nàn và khu phía Đông giàu sang, nơi các phú thương đại hộ dựng trạch viện nguy nga. Trong đó, Tần trạch của Tần gia nổi bật với quy mô hơn mười mẫu, tài lực lớn nhờ sinh ý quặng đồng và có quan hệ trong triều. Hàn Lập giả làm thanh niên áo vải quê mùa tới cửa Tần trạch, bị Tần Quý khinh miệt cho là dân quê xin việc nhưng khiến hắn đổi thái độ khi đưa phong thư gửi Tần Ngôn. Sau khi phu nhân trong phủ cho phép, Hàn Lập được tiểu nha hoàn dẫn tới sương phòng chờ gia chủ hồi phủ. Khi ở một mình, hắn bỏ lớp ngụy trang, xác nhận đã toàn lực ngự khí hơn mười ngày tới Việt Kinh theo lệnh Lý Hóa Nguyên để bảo vệ Tần trạch và trà trộn bằng thân phận hậu nhân chi phụ Tần gia. Đêm xuống, Hàn Lập kết thúc một vòng luyện khí, lại giả dáng vẻ quê mùa rồi theo phó dịch tới phòng khách, nơi Tần Ngôn và phu nhân đang bàn cách xử lý người mang tín thư."},{"chuong":280,"tieuDe":"Tiếp Kiến","tomTat":"Tam phu nhân bàn với Tần Ngôn rằng Tần gia không thiếu tiền nhưng không thể để mất thanh danh, đồng thời đã sai người đưa vị khách mang thư tới. Hàn Lập được Tần Bình dẫn vào phòng khách, cố ý giả làm thanh niên quê mùa ngơ ngác và chỉ chịu giao thư tận tay “Tần thúc”. Tần Ngôn cẩn trọng gọi lão giả áo xanh tóc bạc kiểm tra phong thư, sau khi xác nhận an toàn mới mở đọc và kinh ngạc nhận ra thư liên quan đến một vị trưởng bối có đại ân với Tần gia. Ông lập tức đổi thái độ, kéo Hàn Lập sang phòng bên, mở mật thất bằng cơ quan bình cổ và cung kính gọi hắn là tiên sư. Trong mật thất, Hàn Lập bỏ lớp ngụy trang, xác nhận Lý tiên sư là gia sư của mình và nói rõ nguy cơ ma đạo lục tông có thể xuống tay với Tần gia. Tần Ngôn hoảng sợ trước chuyện tu sĩ ngoại quốc, còn Hàn Lập trấn an rằng nhóm tiềm nhập Việt quốc pháp lực không cao và hắn sẽ tọa trấn Tần phủ để không cho đối phương dễ dàng đắc thủ."},{"chuong":281,"tieuDe":"Tần Trạch Chúng Nhân, Biểu Tiểu Thư","tomTat":"Sau cuộc nói chuyện trong mật thất, Tần Ngôn đưa Hàn Lập ra ngoài và lập tức sai Tam phu nhân thu xếp chỗ ở để hắn lưu lại Tần phủ lâu dài dưới danh nghĩa báo ân. Tam phu nhân hiểu chồng đã quyết ý, ngoài mặt thân thiết với Hàn Lập nhưng trong lòng nghi ngờ giữa hai người có bí mật. Tần Bình đổi thái độ sang cung kính, dẫn Hàn Lập tới một tam hợp viện yên tĩnh dành cho khách quý và hầu hạ bữa ăn. Sau đó Hàn Lập được gọi về phòng khách, nơi hơn hai mươi đến ba mươi người Tần gia đã tụ họp để Tần Ngôn giới thiệu. Một thiếu gia Tần gia chất vấn thân phận Hàn Lập, liền bị Tần Ngôn quát lui và công khai xác lập địa vị đặc biệt của Hàn Lập trước gia quyến. Hàn Lập giả vờ bất an nhưng âm thầm ghi nhớ các thành viên trực hệ cần bảo vệ. Cuối chương, Tần Ngôn phát hiện Biểu tiểu thư chưa đến, sai Tiểu Liên đi gọi nàng và kể cho Hàn Lập nghe lai lịch đáng thương của cô gái từng mất trí nhớ, đầy thương tích, được cứu về rồi trở thành góa phụ trên danh nghĩa sau khi hôn phu mất tích."},{"chuong":282,"tieuDe":"Cải Biến","tomTat":"Sau khi Tần Ngôn nhắc đến Biểu tiểu thư, các nam tử Tần gia đều lộ vẻ mong chờ, khiến Hàn Lập đoán nàng hẳn có dung mạo nổi bật. Khi nàng bước vào phòng khách, Hàn Lập lập tức nhận ra đó là Mặc Phương Vũ của Mặc phủ năm xưa, nhưng cả hai đều giả vờ như không quen biết. Tần Ngôn giới thiệu Hàn Lập với nàng rồi công khai tuyên bố Hàn Lập sẽ ở lại Tần phủ một thời gian và có địa vị như một trong số ít chủ nhân của phủ. Đêm xuống, Mặc Phương Vũ che mặt bí mật đến gặp Hàn Lập; sau khi kiểm tra không có người theo dõi, Hàn Lập để nàng vào phòng nói chuyện. Nàng cầu Hàn Lập vì tình thầy trò với Mặc đại phu mà giúp giết kẻ thù, còn Hàn Lập đoán mục tiêu chính là Môn chủ Ngũ Sắc môn. Hàn Lập giải thích mình không hề biết trước đại nạn Mặc phủ, rồi tiết lộ Mặc Thải Hoàn và Tứ Sư mẫu còn sống ở một nơi bí ẩn, khiến Mặc Phương Vũ xúc động mạnh. Cuối chương, Hàn Lập nhớ lại sau khi thoát khỏi Yến Linh Bảo từng dò hỏi tình hình, biết thành bảo bị phá hủy, phàm nhân chạy tán loạn, còn mẹ con Mặc Thải Hoàn không thấy bóng dáng."},{"chuong":283,"tieuDe":"Cựu Tình","tomTat":"Hàn Lập kể cho Mặc Phương Vũ biết mẹ con Mặc Thải Hoàn vẫn còn sống, khiến nàng vui mừng đến suýt rơi lệ vì đây là tin tốt hiếm hoi sau nhiều năm. Mặc Phương Vũ sau đó nhắc đến Đại tỷ và các Di nương hạ lạc không rõ, cầu xin Hàn Lập giúp báo thù cho Mặc phủ. Hàn Lập cân nhắc thế cục Việt Quốc, nhận ra các thế lực thế tục lâu đời đều có tu sĩ và đại phái chống lưng, riêng Ngũ Sắc môn ở Lam Châu có khả năng liên quan Linh Thú Sơn, nên việc giết Môn chủ Ngũ Sắc môn không đơn giản. Nhân thời cơ Ma đạo lẻn vào Việt Quốc gây loạn, hắn hứa nếu có cơ hội sẽ thử ra tay, nhưng nếu không thành thì Mặc Phương Vũ phải buông bỏ thù hận. Lời hứa ấy khiến nàng cảm kích, hôn nhẹ lên mặt Hàn Lập rồi rời đi, còn hắn nhận ra đây là lần đầu mình động đến tình yêu nam nữ. Sáng hôm sau, Tần Bình phụng mệnh Tần Ngôn đến hầu hạ Hàn Lập, ngoài mặt cung kính nhưng trong lòng khinh khi và suy đoán Hàn Lập là con tư sinh của lão gia. Tần Bình dẫn Hàn Lập đi khắp Tần trạch rồi ra Việt kinh dạo chơi, mệt mỏi đến mức bắt đầu nghi ngờ mình có chọn sai chủ hay không."},{"chuong":284,"tieuDe":"Tư Ngữ","tomTat":"Tần Bình theo hầu Hàn Lập dạo phố trong kinh thành, đi bộ lâu đến mệt nhưng vẫn cố phục vụ chu đáo. Khi Hàn Lập muốn ăn trưa, Tần Bình dẫn hắn vào một tửu lâu hai tầng, gọi món và mượn danh Tần phủ khiến điếm tiểu nhị càng thêm cung kính. Trên lầu hai, Hàn Lập phát hiện một bàn gồm ba nam hai nữ đều là tu sĩ Luyện Khí kỳ cao cấp, bèn dùng Dẫn khí thuật thu liễm linh khí để che giấu thân phận Trúc Cơ kỳ. Hắn giả vờ ăn uống, nhưng thật ra âm thầm thả thần thức quan sát và nghe lén nhóm này. Lão già mặt đen trong nhóm mở Cách âm tráo rồi nói Mông Sơn Ngũ Hữu đã rơi sinh tử vào tay người khác, chỉ có thể tạm thời thuận theo. Lam y nhân muốn cầu viện Thất đại phái, song bị lão già mặt đen bác bỏ vì chính đạo đang khó chống Ma Đạo, còn kẻ địch có Trúc Cơ kỳ, đeo mặt nạ, không lộ tung tích và đã gieo cấm chế cổ quái trên người họ. Nữ nhân áo trắng không muốn giúp kẻ xấu hãm hại tu sĩ khác, nhưng hán tử cao gầy chỉ có thể khuyên cả nhóm đi bước nào tính bước đó. Cuối cùng Mông Sơn Ngũ Hữu đều hiểu đó chỉ là lời tự an ủi và chìm vào im lặng buồn bã."},{"chuong":285,"tieuDe":"Lãnh Mạc Dữ Dao Ngôn","tomTat":"Hàn Lập nghe nhóm tu sĩ bàn về việc nhiều tu sĩ Việt Quốc mất tích, bị khống chế rồi thả ra để làm việc hại người, nhưng nhanh chóng phán đoán việc này nguy hiểm và có thể liên quan đến cao thủ khó đối phó. Hắn lạnh lùng thu thần thức, không can dự, vì Thất đại phái đang bận đối kháng Ma Đạo và bản thân hắn còn có nhiệm vụ bảo vệ Tần gia. Sau bữa ăn, Tần Bình dùng yêu bài Tần phủ ghi sổ tiền cơm rồi đưa Hàn Lập đi xe ngựa khảo sát các nơi trọng yếu của Việt kinh. Tối về Tần phủ, Hàn Lập bỏ qua thái độ ân cần của Tần Quý, bàn riêng với Tần Ngôn trong mật thất và từ hôm sau luôn kề cận ông để bảo vệ. Hơn hai tháng sau, lời đồn Hàn Lập là con riêng Tần Ngôn lan rộng, khiến một số hậu bối Tần gia ganh ghét và vài thiếu gia bên ngoài thử khích bác nhưng đều thất bại. Hàn Lập dùng thần thức nghe được lời xấu sau lưng và âm thầm hạ mức ưu tiên bảo vệ những người đó nếu Ma Đạo tập kích. Cuối chương, Tần gia nhận thiếp dự tiệc của Hinh Vương mừng ái phi khỏi bệnh, còn Hàn Lập chỉ tạm ghi nhận thanh danh tốt của vị vương gia này và quyết định phải tận mắt xác nhận."},{"chuong":286,"tieuDe":"Vương Phủ","tomTat":"Hàn Lập theo Tần Ngôn và người Tần gia tới nam khu Việt Kinh, nơi quy mô phủ trạch thể hiện rõ quan tước của chủ nhân. Hinh Vương phủ hiện ra rộng lớn hơn Tần trạch, cửa bọc đồng vàng, có tượng sư tử đồng và cấm binh canh giữ, trước phủ đã tụ tập nhiều xe ngựa cùng tân khách. Hàn Lập nhận thấy rất nhiều khách nhân dẫn theo con cháu trẻ tuổi, nên nghi việc này có liên quan đến Tiểu Vương gia, còn Tần Ngôn cũng cau mày vì tình huống ngoài dự liệu. Tổng quản Hinh Vương phủ ra mặt đón tiếp, nói năng khéo léo và nhiệt tình dẫn đoàn Tần gia vào trong, nhưng Hàn Lập lại sinh trực giác nguy hiểm dù không cảm nhận được linh lực trên người lão. Trong đại sảnh, Tần Ngôn chủ động dẫn Hàn Lập đi gặp Hoa lão ca, một đại thần y Việt Kinh đến dự vì muốn xem cao nhân chữa được quái bệnh cho sủng cơ của Hinh Vương. Hoa lão ca gọi Hoa Nam và Hoa Phương tới chào Tần Ngôn, hai người nhận ngọc bội làm lễ gặp mặt. Sau khi Tần Ngôn giới thiệu Hàn Lập là hậu nhân của một vị trưởng bối, Hoa lão ca nhớ tới lời đồn gần đây và tặng hắn một bình Hộ Tâm Hòan, khiến đám tiểu bối hai nhà chú ý vì danh tiếng của thuốc này không nhỏ."},{"chuong":287,"tieuDe":"Tiên Sư","tomTat":"Hàn Lập nhận Hộ Tâm Hoàn do Hoa lão ca tặng vì nể mặt Tần Ngôn, tuy bản thân không coi trọng đan dược phàm tục. Hinh Vương cùng Thanh nhi bước vào đại sảnh và nói rõ yến hội lần này vừa để mừng Thanh nhi khỏi bệnh, vừa để ban cho khách khứa một cơ duyên đặc biệt. Ông kể quái bệnh của Thanh nhi được một cao nhân chữa khỏi, người ấy biết pháp thuật, tự nhận là người tu tiên và còn nhìn ra con út của Hinh Vương có tiên căn. Tin tức Ngô tiên sư nhập thế thu đồ đệ khiến đám quyền quý phấn khích, ai cũng muốn đưa con cháu tới thử tiên duyên. Hàn Lập ban đầu nghi chuyện này liên quan ma đạo, nhưng khi Ngô tiên sư xuất hiện thì nhận ra đối phương chỉ là tiểu tu sĩ Luyện khí kỳ tầng năm, sáu và không phải mục tiêu đáng ngại. Cuối chương, Tần Ngôn do dự trước cơ hội bái sư cho con cháu, còn Hàn Lập truyền âm cho ông rằng việc ấy tùy Tần gia quyết định, nhiệm vụ của hắn chỉ là bảo hộ an nguy Tần gia."},{"chuong":288,"tieuDe":"Mê Hồn Giao Phong","tomTat":"Tại Tần phủ, Tần Ngôn nghe Hàn Lập nhắc nhở nhưng vẫn quyết định đưa con cháu đến chỗ Ngô tiên sư để thử cơ hội tu tiên, vì nhớ chuyện Lý Hóa Nguyên từng đến Tần gia mà không thu được hậu bối có tiên duyên. Hàn Lập lạnh nhạt không can thiệp, đồng thời quan sát đại sảnh và phát hiện một thanh bào lão giả cùng một thiếu niên mi thanh mục tú đều là tu sĩ đang che giấu linh khí. Hắn nhận ra thiếu niên thực ra là thiếu nữ giả trai, khiến nàng đỏ mặt và trừng mắt với hắn, từ đó làm thanh bào lão giả chú ý. Thanh bào lão giả tưởng Hàn Lập là công tử phàm tục vô lễ nên dùng Mộng yểm thuật định giáo huấn, nhưng lập tức bị Hàn Lập áp chế ngược do chênh lệch tu vi quá lớn. Hàn Lập không phản kích mạnh vì động tâm với pháp môn che giấu linh khí của hai người già trẻ. Nhờ thiếu nữ kéo tay áo và vì Hàn Lập cố ý lưu tình, thanh bào lão giả thoát khỏi nguy cơ phản phệ rồi kinh hãi đoán Hàn Lập là tu sĩ Trúc Cơ kỳ, nghiêm khắc cảnh cáo cháu gái không được trêu chọc hắn."},{"chuong":289,"tieuDe":"Tiên Thuật","tomTat":"Sau khi răn đe thiếu nữ mặt cười, Hàn Lập không tiếp tục làm nàng bị thương mà truyền âm cho thanh bào lão giả, buộc hai ông cháu sau khi rời Hinh vương phủ phải chờ hắn ở cửa sau để hỏi chuyện. Thanh bào lão giả hoảng sợ nhưng cũng tự trấn an rằng nếu có thể liên hệ với một tu sĩ Trúc Cơ kỳ thì gia tộc mình có lẽ còn cơ hội khôi phục. Trong sảnh, Ngô tiên sư tiếp tục kiểm tra tiên duyên cho đám con cháu quyền quý và bất ngờ xác nhận Đồng Cảnh có tiên căn, nhận hắn làm môn hạ, khiến cha con Đồng Cảnh vui mừng còn nhiều người khác khó tin. Vì việc một kẻ vốn bị xem là vô dụng được chọn khiến đám khách bắt đầu nghi ngờ, Hinh Vương đành mềm mỏng mời Ngô tiên sư biểu diễn tiên thuật để mọi người mở rộng tầm mắt. Ngô tiên sư ra khu đất trống trước sảnh, thi triển Hỏa đạn thuật rồi điều khiển ngọn lửa biến thành chim, chó, rắn, người tí hon và ngựa lửa. Hàn Lập ban đầu thoáng tưởng đó là Hỏa điểu thuật trung cấp, nhưng nhanh chóng nhận ra chỉ là biến hình của Hỏa đạn thuật vì pháp lực không tăng. Cuối cùng, ngựa lửa lao vào cây anh đào nhỏ và đốt cây thành tro, khiến đám phàm nhân đang nghi ngờ lập tức tin phục Ngô tiên sư."},{"chuong":290,"tieuDe":"Tiểu Vương Gia","tomTat":"Hinh Vương hãnh diện sau khi Ngô tiên sư thi triển pháp thuật khiến khách khứa trong phủ kinh sợ, đồng thời chương giải thích vì sao người tu tiên ngày nay hiếm khi công khai xuất hiện ở thế tục. Ngô tiên sư trở lại đại sảnh và kiểm tra toàn bộ những người còn lại, nhưng cả con cháu Tần gia lẫn Hoa gia đều không có linh căn, khiến Đồng Cảnh càng trở nên nổi bật vì có tiên căn. Tần Ngôn dẫn đám con cháu thất vọng trở về, quát một tiểu thư Tần gia đang bất bình, rồi cùng lão giả họ Hoa cười khổ về vận may của Đồng Cảnh. Hinh Vương sai người chuẩn bị yến tiệc, mừng Thanh nhi khỏi quái bệnh và mừng con trai cùng Đồng Cảnh bái sư, trong khi Ngô tiên sư lặng lẽ rời đi khiến nhiều khách muốn kết giao thất vọng. Sau đó Tiểu vương gia Minh nhi, một thanh niên áo trắng ôn nhã, xuất hiện và được Hinh Vương dẫn tới chào Tần Ngôn, lão giả họ Hoa cùng con cháu hai nhà. Khi Minh nhi lịch sự chào Hàn Lập, Hàn Lập vẫn giả vờ lúng túng ngốc nghếch nhưng trong lòng chấn động vì cảm nhận từ Minh nhi một mối nguy hiểm giống tổng quản vương phủ."},{"chuong":291,"tieuDe":"Tiêu Gia","tomTat":"Sau yến hội tại Hinh Vương phủ, Tiểu vương gia lịch sự tiếp chuyện đệ tử Tần gia, khiến vài tiểu thư rung động, nhưng Hàn Lập lại âm thầm nhận định người này rất có vấn đề. Khi Tần Ngôn đưa con cháu cáo từ, Hàn Lập hỏi ông về hai người già trẻ thuộc Tiêu gia và biết lão giả là chủ Nhàn Vân tửu lâu. Hàn Lập dặn Tần Ngôn về trước, còn mình đi dọc tường Hinh Vương phủ tới cửa sau để chờ hai người kia. Lão giả tự xưng Tiêu Chấn, dẫn thiếu nữ nam trang tới tạ lỗi Hàn Lập vì chuyện ở vương phủ. Hàn Lập chất vấn vì sao Tiêu Chấn không bế quan tu luyện mà ở kinh thành, và nghe ông khai mình là người Tiêu gia Phong Hà giản, Duẫn Châu, tuổi cao vô vọng Trúc Cơ nên phụ trách tài chính gia tộc. Khi Hàn Lập thử dọa giết người đoạt bảo, Tiêu Chấn ngoài miệng cam chịu nhưng âm thầm vận pháp lực, còn thiếu nữ họ Tiêu căng thẳng rồi tỏ vẻ muốn cùng gia gia chống trả. Nhờ thần thức tăng mạnh từ Đại Diễn Quyết, Hàn Lập nhìn thấu tâm cơ và phản ứng nhỏ của hai ông cháu, đồng thời vẫn nghi ngờ lai lịch Tiêu gia. Cuối chương, trước sự im lặng và ánh mắt nhìn chằm chằm của Hàn Lập, thiếu nữ không chịu nổi nên trực tiếp hỏi hắn rốt cuộc muốn thế nào."},{"chuong":292,"tieuDe":"Cường Thế","tomTat":"Hàn Lập đối mặt hai ông cháu họ Tiêu sau biến cố trong đại sảnh, dùng khí thế và linh áp mạnh mẽ bức thiếu nữ lùi xa, khiến Tiêu Chấn phải lập tức hạ mình cầu xin. Sau khi thu lại uy thế, hắn không giết người hay cướp trắng mà nói rõ muốn giao dịch thứ hai ông cháu đang nắm giữ. Mục tiêu của Hàn Lập là pháp môn che giấu linh khí từng khiến đạo sĩ Luyện Khí kỳ không nhận ra thân phận tu tiên của họ, và Tiêu Chấn buộc phải khai rằng pháp môn này đến từ một quyển sách vô danh không đầy đủ do cháu gái tìm được trong sơn động núi hoang. Để bảo đảm hai người không bỏ trốn, Hàn Lập bắn hai đạo lục quang vào người họ, gọi đó là dấu hiệu truy tung và hứa sẽ xóa sau khi giao dịch hoàn tất. Tiêu Chấn tuy lo sợ bị giết người diệt khẩu nhưng không còn cách nào khác ngoài việc nhận lời trở về chờ. Hàn Lập hẹn tối sẽ đến lấy sách rồi thi triển thân pháp biến mất trước mắt hai ông cháu, nhưng thực ra ẩn trên một thân cây gần đó lạnh lùng quan sát họ rời đi. Thiếu nữ họ Tiêu dù vừa bị áp chế vẫn không giấu được vẻ hâm mộ trước thân pháp của Hàn Lập."},{"chuong":293,"tieuDe":"Tiềm Nhập","tomTat":"Hàn Lập nhớ lại ánh mắt hâm mộ của tiểu cô nương trước đó, liên tưởng tới lần đầu mình thấy Lý Hóa Nguyên sử dụng Cự Giao, rồi quyết định lẻn vào vương phủ. Hắn đồng thời thi triển Ẩn hình thuật và Dẫn khí quyết, vô thanh vô tức tiến vào khu phía sau, đánh ngất một tiểu nha hoàn từng được Hinh Vương sai đi tìm Tiểu vương gia. Sau đó, Hàn Lập dùng Khống thần thuật thẩm vấn nàng, biết trong phủ có nhiều tổng quản, trong đó Vương tổng quản là người quyền lực nhất và có quan hệ lâu năm với Hinh Vương. Qua lời nha hoàn, hắn phát hiện Tiểu vương gia sau mười tuổi đổi tính rõ rệt, trở nên cung kính khác thường với Vương tổng quản, nên đoán hai người có bí mật và không phải phàm nhân bình thường. Tuy vậy, Hàn Lập tạm cho rằng chuyện này không giống bố cục của ma đạo lục tông nên không muốn tự chuốc phiền nếu không cần thiết. Hắn sai nha hoàn dẫn tới nơi ở Ngô tiên sư, giải thuật cho nàng rồi lẻn vào phòng trước. Khi lão đạo quay vào thấy Hàn Lập ngồi sẵn bên bàn, lão kinh hãi gọi ra hỏa cầu, còn Hàn Lập bình tĩnh cảnh cáo rằng nếu là lão thì không nên tùy tiện ra tay."},{"chuong":294,"tieuDe":"Lộng Diễm Quyết","tomTat":"Lão đạo đầu bạc phát hiện Hàn Lập đột nhập phòng mình, ban đầu định dùng hỏa cầu đối phó nhưng sau khi thi triển Thiên Nhãn thuật thì kinh hãi nhận ra đối phương là tu sĩ Trúc Cơ kỳ. Hàn Lập nhìn ra lão đạo không chỉ sợ hãi mà còn hưng phấn vì gặp được tu sĩ cao cấp, rồi hỏi rõ lai lịch tu luyện của ông. Lão đạo kể mình khi trẻ tình cờ lấy được Liệt Dương quyết từ một tu tiên giả sắp chết, nhưng do tư chất kém và thiếu chỉ điểm nên chỉ đạt Luyện Khí tầng sáu. Khi Hàn Lập hỏi đến thuật điều khiển lửa, lão đạo trình ra Lộng Diễm quyết do mình tự cải biến hơn mười năm, khiến Hàn Lập ban đầu xem nhẹ nhưng sau đó nhận ra phần cuối sách có giá trị lớn trong cách vận dụng pháp thuật. Hàn Lập không muốn lấy không nên cho lão đạo chọn đạo thư, pháp khí hoặc đan dược, và cuối cùng trao hai bình Hoàng Long Đan để đổi lấy quyển sách. Sau khi tạo được ràng buộc lợi ích, Hàn Lập giao lão đạo theo dõi tiểu Vương gia cùng Vương tổng quản trong vài tháng, lấy lý do ma đạo đang xâm lấn Việt quốc và hai người có thể liên quan đến ma đạo. Thực ra Hàn Lập chưa có chứng cứ chắc chắn, nhưng trực giác cho rằng hai người rất nguy hiểm nên cố ý che giấu nguyên nhân thật và dùng lão đạo làm tai mắt trong vương phủ."},{"chuong":295,"tieuDe":"Phó Ước","tomTat":"Hàn Lập nói với lão đạo tóc bạc rằng Vương tổng quản và Tiểu vương gia có thể liên quan ma đạo, yêu cầu lão âm thầm giám thị chứ không được dò xét để tránh bại lộ mất mạng. Khi lão đạo chần chừ vì sợ nguy hiểm, Hàn Lập lấy Tử Quang châu ra cho mượn phòng thân, hứa thêm Hoàng Long đan, đồng thời đặt tiêu ký linh lực trong người lão để tiện ứng cứu và khống chế. Rời vương phủ, Hàn Lập không về Tần Trạch mà vào trà lâu ngồi nửa ngày tự kiểm điểm các việc gần đây, thể hiện thói quen thận trọng của hắn. Trước giờ hẹn với ông cháu họ Tiêu, hắn cảm ứng được hai người không ở Đông khu mà đổi sang Tây khu nên tức giận dùng Thần Phong Chu truy theo. Chương làm rõ nhờ Đại Diễn Quyết, phạm vi cảm ứng truy tung của Hàn Lập vượt xa tu sĩ Trúc Cơ kỳ bình thường, đạt hơn trăm dặm. Tại một trang viện cũ ở Tây khu, Hàn Lập nghe lén lão giả họ Tiêu giải thích việc đổi chỗ là để thử khả năng truy tung của hắn, đồng thời bàn với cháu gái về rủi ro dùng quyển sách thâm ảo để giao dịch. Khi cô gái nói Hàn Lập có thể là lão yêu quái, hắn từ ngoài phòng lên tiếng, bước vào ngồi ghế chủ tọa và bình tĩnh nhìn hai người."},{"chuong":296,"tieuDe":"Bái Sư","tomTat":"Hàn Lập nghe được lời nói trước đó của hai ông cháu họ Tiêu, khiến cả lão giả và cô gái đều kinh hoảng. Để làm dịu tình thế, lão giả giao cho hắn một quyển sách da màu vàng đã đen, nói công pháp thu liễm hơi thở của hai ông cháu học được từ đó. Hàn Lập phát hiện phần đầu sách là thượng cổ văn tự không hiểu được, còn hai trang cuối có khẩu quyết vô danh bằng văn tự hiện dùng, nên đọc xong liền thu sách vào hộp ngọc trong túi trữ vật. Hắn cho phép hai ông cháu nêu yêu cầu trao đổi, nhưng họ không đòi vật ngoài thân mà xin cho cô gái bái Hàn Lập làm sư phụ. Hàn Lập thấy mình còn chưa đủ tự bảo vệ trong tu tiên giới nên không muốn nhận đồ đệ, song vẫn kiểm tra linh căn của cô gái. Sau khi xác nhận nàng có song linh căn, hắn khen tư chất rất tốt và nghĩ đến việc giới thiệu nàng cho Mã sư huynh ở Bách Dược viên, nhưng vẫn nói thẳng rằng mình không thu đồ đệ, khiến hai ông cháu thất vọng."},{"chuong":297,"tieuDe":"Liệt Ngân Hung Tấn","tomTat":"Hàn Lập không nhận cô gái họ Tiêu làm đồ đệ, nhưng giao Truyền Âm phù và ngọc bài để nàng đến Bách Dược viên Hoàng Phong cốc tìm Mã sư huynh thử cơ hội bái sư. Vì việc này chưa chắc thành công, hắn tặng thêm hai kiện thượng cấp pháp khí là dải lụa thêu kim tuyến và tiểu kiếm màu lam cho hai ông cháu họ Tiêu, rồi thu lại linh khí tiềm phục trên người họ và rời đi. Trở về Tần phủ, Hàn Lập tu luyện khẩu quyết vô danh thu liễm hơi thở và nhờ pháp lực thâm hậu nên gần một đêm đã lĩnh hội phần lớn. Sáng hôm sau, Tử Quang Cảm Ứng châu trong túi trữ vật của hắn nứt vỡ, khiến hắn nhớ tới viên châu cùng loại từng đưa cho lão đạo đầu bạc. Hàn Lập dùng Thần Phong chu đến ngoại thành Việt Kinh, tìm dưới gốc dương liễu trên một ngọn đồi hẻo lánh và thu được viên Tử Quang châu thứ hai cũng bị nứt. Sau khi phá cây kiểm tra mà không có thu hoạch, hắn kết luận lão đạo đầu bạc hơn phân nửa đã gặp độc thủ. Khi Hàn Lập rời đi, bốn người áo đen che mặt từ dưới đất chui lên, lộ ra việc họ được lệnh bắt sống hoặc giết hắn nhưng không dám ra tay vì hắn là tu sĩ Trúc Cơ kỳ. Người cầm đầu còn cảm thấy từng gặp Hàn Lập ở đâu đó, nhưng lập tức ra lệnh cả nhóm rời khỏi hiện trường."},{"chuong":298,"tieuDe":"Sanh Cầm","tomTat":"Bốn người bịt mặt còn chưa kịp rời đi bằng pháp khí phi hành thì Hàn Lập đã xuất hiện trên không, đứng trên Thần Phong chu và chặn đường họ. Biết khó chống lại tu sĩ Trúc Cơ kỳ, tên đại ca lập tức ra lệnh phân tán, nhưng Hàn Lập đã bố trí khôi lỗi đón sẵn các hướng. Nữ tử bịt mặt dùng Băng Thương phù và phi đao màu lam chống lại hai con rối một cung một đao, song vẫn bị ép quay về nơi cũ. Tại đó, nàng thấy ba nam tử cùng nhóm đã cúi đầu ủ rũ như trúng cấm chế nên tuyệt vọng buông pháp khí, để Hàn Lập phong tỏa chân nguyên và đưa cả bốn lên Thần Phong chu rời xa Việt Kinh. Sau khi Hàn Lập đi khỏi, hai người áo đỏ xuất hiện ở hiện trường, nhận định Mông thị huynh đệ đã thất bại và có thể bị bắt sống. Người trẻ tuổi áo đỏ tiết lộ hắn đã bí mật hạ thủ nhóm này khiến họ chỉ còn sống được nửa ngày, còn lão giả áo đỏ nhắc tới kế hoạch kim thiền thoát xác qua việc dùng Ngô lão đạo làm sư phụ bù nhìn. Chương kết lại bằng việc lão giả chất vấn người trẻ tuổi vì sao hút tinh huyết Ngô lão đạo, trong khi đối phương chỉ đáp rằng mình bất đắc dĩ."},{"chuong":299,"tieuDe":"Các Hoài Tâm Tư","tomTat":"Tiểu vương gia thú nhận với Vương tổng quản rằng mình bị pháp lực phản phệ nên đã hút tinh huyết Ngô lão đạo để áp chế chân nguyên. Vương tổng quản cho rằng nguyên nhân nằm ở việc Tiểu vương gia nóng vội tu luyện Tu La công, đồng thời nhận định người bắt Mông sơn ngũ hữu nhiều khả năng là tu sĩ Trúc Cơ kỳ. Thay vì lẩn tránh, hắn muốn bẩm báo giáo chủ để xin Huyết thị hỗ trợ bắt sống mục tiêu, vì giáo chủ đang cần huyết tế tu sĩ Trúc Cơ kỳ để luyện công. Ở nơi cách ngọn đồi hơn trăm dặm, Hàn Lập hạ Thần Phong chu, buộc bốn tù binh tháo khăn bịt mặt và xác nhận họ chính là bốn người còn lại của Mông sơn ngũ hữu. Hàn Lập suy đoán Tiểu vương gia cùng Vương tổng quản là hắc thủ đứng sau những vụ tu sĩ mất tích, nhưng lại khó rời Việt Kinh vì nhiệm vụ bảo hộ Tần gia do Lý Hóa Nguyên giao. Khi hắn dọa giao bốn tù binh cho các gia tộc có tu sĩ mất tích, ngũ muội hoảng sợ suýt lộ rằng nhóm họ chưa từng trực tiếp bắt cóc tu sĩ, nhưng đại ca Mông sơn ngũ hữu lập tức quát ngăn."},{"chuong":300,"tieuDe":"Huyết Chú","tomTat":"Bốn người bị Hàn Lập bắt giữ bắt đầu rạn nứt khi Tứ ca nhận ra Lão Nhị cố ý chọc giận Hàn Lập để cả nhóm bị giết. Lão Nhị thú nhận Tam muội là đạo lữ đang mang cốt nhục của hắn và đang nằm trong tay đối phương, nên hắn sợ nàng bị tra tấn nếu nhóm tiết lộ cơ mật. Hàn Lập lạnh lùng cắt ngang tranh cãi, khẳng định sinh tử của họ đã nằm trong tay hắn và buộc họ khai tin về người đứng sau. Lão giả mặt đen khuất phục, nói cả nhóm bị hạ huyết chú cấm chế, nếu tiết lộ chuyện trọng yếu thì trái tim sẽ vỡ tan mà chết. Sau khi kiểm tra thân thể lão giả và hỏi về chú ngữ, phù hiệu máu đen cùng người hạ chú, Hàn Lập nhận ra huyết chú thực chất là ngôn chú mà hắn từng đọc khi tra tư liệu Đại na di lệnh. Hắn nêu hai cách giải chú, hoặc biết khẩu quyết, hoặc dùng thần thức cưỡng ép xóa ấn ký trong Thần thức hải, nhưng cách sau nếu thất bại sẽ lập tức kích phát chú. Trước thế cược mạng ấy, Lão Nhị cao gầy chủ động xin Hàn Lập giải chú cho mình trước, khiến nữ tử trẻ tuổi lo lắng can ngăn."},{"chuong":301,"tieuDe":"Khu Độc, Giải Chú","tomTat":"Lão nhị cao gầy muốn tự làm vật thí nghiệm giải huyết chú, nhưng Hàn Lập lạnh lùng phủ nhận việc từng hứa giải chú miễn phí, khiến Mông Sơn ngũ hữu hiểu rằng họ phải trả thêm giá. Sau khi lão giả mặt đen hỏi điều kiện, Hàn Lập yêu cầu nhóm giao hết tin tức, tạm thời nghe lệnh hắn và cùng đối phó địch nhân sắp tới, đồng thời công khai thân phận tu sĩ Hoàng Phong cốc đến Việt Kinh xử lý việc môn phái. Lão giả mặt đen đại diện nhóm chấp nhận vì biết sau khi thoát huyết chú họ vẫn có thể bị thế lực sau lưng truy sát, rồi xin Hàn Lập cứu Tứ muội đang ở trong một nhà dân tại Việt Kinh thành. Hàn Lập phát hiện ngoài huyết chú, trong người họ còn có kịch độc sắp phát tác; lão nhị cao gầy nhớ ra chén rượu bị ép uống trước lúc xuất phát và hiểu nguồn độc nằm ở đó. Hàn Lập lấy hai bình đan dược trắng và xanh từ túi trữ vật, cho bốn người uống để xua phần lớn độc tính, khiến họ đau bụng dữ dội và phải tách ra bài tiết độc vật. Khi chuẩn bị thử giải huyết chú, lão nhị muốn lên trước nhưng lão giả mặt đen giành phần nguy hiểm vì mình đã già, không còn hy vọng Trúc Cơ, còn lão nhị phải chăm sóc Tam muội và đứa nhỏ trong bụng. Hàn Lập quyết định để lão giả mặt đen thử trước, nhưng trước khi ra tay thả sáu bảy khôi lỗi binh sĩ cảnh giới trong phạm vi mười trượng quanh mình."},{"chuong":302,"tieuDe":"Đối Sách","tomTat":"Buổi chiều tại phòng khách Tần phủ, Tần Ngôn sốt ruột vì Hàn Lập vắng mặt cả đêm, lo Tần gia mất chỗ dựa trước sự uy hiếp của ma đạo. Ông sai Tần Bình đi dò tin, trong khi Tam phu nhân ngoài miệng nói đỡ Hàn Lập nhưng trong lòng ghen tức vì Tần Ngôn quá thiên vị hắn. Tần Bình trở về báo Hàn Lập đã hồi phủ cùng mấy khách nhân, và Tần Ngôn lập tức cho phép bố trí họ ở Thanh Âm viện phụ cận. Hàn Lập lúc này đã cứu đủ Mông Sơn ngũ hữu, giải trừ huyết chú cho cả năm người rồi đưa họ về Tần trạch để tiện giám sát và dùng vào kế hoạch đối phó Hắc sát giáo. Nhóm tán tu thuật lại rằng họ chỉ biết đối phương là Hắc sát giáo, bắt người để luyện tà công, còn hai kẻ phát hiệu thi lệnh thì chưa thấy mặt. Hàn Lập cho biết mình đã gửi thư cầu viện Lý Hóa Nguyên nhưng không định ngồi chờ, vì Thất phái đang bận chống ma đạo. Sau khi nghe đề nghị và lo ngại của Mông Sơn ngũ hữu, hắn khẳng định đã đoán ra hai kẻ phát lệnh là ai và quyết định đêm nay sẽ chủ động ra tay bắt sống chúng."},{"chuong":303,"tieuDe":"Khiếp Sợ","tomTat":"Mông Sơn ngũ hữu chấp nhận sắp xếp của Hàn Lập, còn trung niên nữ tử tò mò hỏi thân phận thật của hai người Hắc sát giáo nhưng chỉ được trả lời rằng đến đêm hành động sẽ rõ. Tần Bình theo lệnh Tần Ngôn đưa năm người đến một đình viện gần đó, trong khi Hàn Lập nhìn theo với vẻ khác thường. Tối đến, Mông Sơn ngũ hữu tụ tại Thanh Âm viện chờ thời điểm hành động, rồi lão Tứ nói mình thấy Hàn Lập rất quen mặt. Từ chuyện Thăng Tiên đại hội và lần ghé tửu lầu Gia Nguyên thành, lão Tứ xác nhận Hàn Lập chính là tiểu tu sĩ Luyện Khí kỳ từng bị họ xem nhẹ năm xưa, khiến cả nhóm khiếp sợ vì hắn nay đã là tu sĩ Trúc Cơ kỳ. Lão giả mặt đen nhắc mọi người dù nghi hoặc thế nào cũng phải giữ lễ với Hàn Lập và không hỏi điều không nên hỏi. Sau khi trời tối hẳn, Ngũ muội lén rời sương phòng, lấy một hộp nhỏ ra định mở thì bị Hàn Lập phát hiện. Lão giả mặt đen cùng những người khác cũng xuất hiện, chất vấn nàng và cuối cùng lạnh giọng ra lệnh nàng giao thứ trong tay cho Hàn Lập."},{"chuong":304,"tieuDe":"Nội Ứng","tomTat":"Lão giả mặt đen yêu cầu Ngũ muội tự mở chiếc hộp để chứng minh không có thứ gây hại, nhưng nàng kích động vì bị các huynh muội nghi ngờ. Nàng cất hộp vào người, lấy Thiên Lôi tử ra uy hiếp mọi người và thừa nhận đã gia nhập Hắc Sát giáo từ hai năm trước. Trước câu hỏi của Hàn Lập, Ngũ muội còn khai chính nàng đã báo hành tung Mông Sơn ngũ hữu cho Hắc Sát giáo, cho rằng mình chỉ muốn họ có cơ hội Trúc Cơ. Hàn Lập lập tức dùng thân pháp cực nhanh xuất hiện sau lưng, đoạt Thiên Lôi tử, phong cấm chân nguyên của nàng, lấy chiếc hộp rồi giao người cho Mông Sơn ngũ hữu xử lý. Lão giả mặt đen sai Tứ đệ đưa Ngũ muội về Thanh Âm viện, nhưng vì Tứ đệ nặng tình với nàng nên việc canh giữ trở thành sơ hở. Khi lão giả và Lão Nhị chạy tới, Ngũ muội đã biến mất, còn Tứ đệ ngồi thẫn thờ như mất hồn. Lão giả sai Lão Nhị truy bắt, thậm chí cho phép hạ sát nếu nàng không chịu theo hoặc có người tiếp ứng, rồi đến thỉnh tội với Hàn Lập. Hàn Lập nghe tin Ngũ muội trốn khỏi Tần trạch lại rất bình thản, không tỏ ra kinh hoảng trước nguy cơ nàng báo tin cho Hắc Sát giáo."},{"chuong":305,"tieuDe":"Hậu Thủ","tomTat":"Sau khi được thả khỏi Tần trạch, Ngũ muội dùng Ẩn Nặc phù tránh Lão Nhị rồi chạy về Nam khu Việt Kinh, định đến cứ điểm bí mật của Hắc Sát giáo để báo vị trí Hàn Lập và tình báo Tần trạch, mong đổi lấy cơ hội Trúc Cơ. Khi gần tới nơi, hậu thủ Hàn Lập để lại phát tác, khiến nàng thất khiếu chảy máu đen, mất hết sức lực và chết lặng lẽ trong đêm. Hàn Lập sau đó giải thích rằng hắn đã nghi Ngũ muội là nội ứng từ lúc giải huyết chú, nên âm thầm đặt cấm chế để dược lực Vô Thường đan còn sót lại có thể hóa thành kịch độc nếu nàng bỏ trốn. Hắn không giết Ngũ muội ngay trước mặt Mông Sơn ngũ hữu vì còn xét đến tình cảm cũ của họ, nhưng vẫn bảo đảm nàng không thể tiết lộ quan hệ giữa nhóm và Tần trạch cho Hắc Sát giáo. Đến đêm, Hàn Lập tới Thanh Âm viện, dẫn bốn người còn lại của Mông Sơn ngũ hữu dùng pháp thuật ẩn thân đột nhập Hinh Vương phủ. Trong phủ, hắn dùng Khống Thần thuật tra hỏi thủ vệ canh đêm, biết nơi ở của Tiểu vương gia và Vương tổng quản, rồi quyết định bắt Tiểu vương gia trước vì tu vi mục tiêu này thấp hơn. Nhóm chế trụ thủ vệ quanh tiểu lâu, Hàn Lập dựng cách âm kết giới rồi lên tầng ba, nhưng phát hiện Tiểu vương gia không có mặt, trong phòng chỉ còn một con rối do huyễn thuật biến hóa."},{"chuong":306,"tieuDe":"Nguy Cơ","tomTat":"Sau khi nghi ngờ Ngũ muội có thể báo tin hoặc đối phương đặt bẫy, Hàn Lập phủ định khả năng phục kích đã sẵn sàng từ đầu và quyết định chuyển mục tiêu sang Vương tổng quản. Tại tiểu viện của Vương tổng quản, hắn dùng pháp quyết che giấu khí tức để áp sát nghe lén, phát hiện tiểu vương gia cũng đang ở trong phòng. Tiểu vương gia rời viện rồi nhanh chóng đổi thành bộ đồ bịt mặt đỏ máu, lộ ra chính là kẻ từng điều động Mông Sơn tứ hữu truy giết Hàn Lập. Hàn Lập sai Mông Sơn tứ hữu truy theo tiểu vương gia, còn mình giám thị Vương tổng quản một lúc rồi dùng Thần Phong Chu đuổi tới miếu hoang ngoài kinh thành. Tại đó, hắn nhận ra cấm chế quanh miếu chỉ là Lạc Thạch trận Thổ thuộc tính đơn giản và dùng khôi lỗi cùng Ô long đoạt phá vỡ màn hào quang. Khi nhóm chuẩn bị lao xuống miếu, tiểu vương gia cùng người gầy gò áo đỏ, hơn chục hắc y che mặt và một đại hán áo đỏ Trúc Cơ kỳ xuất hiện phía sau. Phe Hắc Sát giáo cho biết miếu chỉ là nơi ở tạm và hiện không có ai bên trong, khiến Hàn Lập cùng Mông Sơn tứ hữu rơi vào tình thế bị phục kích ngược đầy nguy hiểm."},{"chuong":307,"tieuDe":"Huyết Thị","tomTat":"Hàn Lập bị Tiểu vương gia nhận ra là người từng ở Tần gia, đồng thời bị Huyết Thị xác định là tu sĩ Trúc Cơ trung kỳ, có giá trị lớn để dâng cho Giáo chủ Hắc Sát giáo huyết tế luyện công. Tiểu vương gia lập tức hạ lệnh cho Hắc y nhân bày Hắc Phong trận, nhưng Hàn Lập bình tĩnh giao Mông Sơn tứ hữu phòng thủ rồi dùng thân pháp cực nhanh giết nhiều người bày trận, khiến trận thế bị gián đoạn. Huyết Thị nổi giận truy kích, dùng huyết quang cuốn giữ và bóp hủy Tam Lăng thứ của Lão Nhị cao gầy, làm Hàn Lập nhận ra đối thủ tu luyện ma công rất bất thường. Khi Huyết Thị dùng quyền huyết sắc ép sụp phòng hộ của Mông Sơn tứ hữu, Hàn Lập tế Bạch Lân thuẫn chặn đòn, nhưng mặt thuẫn vẫn bị lõm nhẹ. Hàn Lập tiếp tục phóng hai đạo ô quang và sáu đạo kim quang vây đánh, song Huyết Thị hóa thành khối huyết quang lớn khiến các pháp khí khó tiến sâu. Nhìn quanh, Hàn Lập phát hiện Tiểu vương gia và người che mặt giống Vương tổng quản đang tổ chức lại Hắc y nhân để tiếp tục bày Hắc Phong trận, cảnh tượng khiến hắn liên tưởng tới nghi thức Thanh dương ma hỏa. Hàn Lập tạm giao Bạch Lân thuẫn cho lão giả mặt đen bảo vệ Mông Sơn tứ hữu, rồi thu pháp khí chuẩn bị chuyển sang xử lý nhóm bày trận."},{"chuong":308,"tieuDe":"Đại Triển Thân Thủ","tomTat":"Hàn Lập tung nhiều pháp khí cùng lúc, dùng Đại Diễn quyết khống chế Hỏa diễm liên hoàn phi xoa, hai đạo ô quang và sáu đạo kim quang để áp đảo nhóm tu sĩ áo đen. Các tu sĩ Luyện Khí kỳ không chống nổi, nhiều người bị phá pháp khí, phá vòng bảo hộ rồi chết hoặc bỏ chạy, khiến Hắc Phong trận tan vỡ trước khi phát huy. Tiểu vương gia và người bịt mặt giống Vương tổng quản nhận ra thực lực Hàn Lập vượt xa dự tính, chỉ có thể dùng hắc quang hộ thân và lùi lại. Mông Sơn tứ hữu đứng ngoài chứng kiến Hàn Lập một mình đánh tan hơn mười tu tiên giả cùng cấp với họ, từ đó hoàn toàn tâm phục khẩu phục. Khi Huyết Thị hóa thành huyết quang lao ra, Hàn Lập lập tức dùng Già Thiên chung chụp kín đối phương. Sau đó hắn phóng mưa cầu lửa để nghi binh, bắt sống người bịt mặt, chặt mất một tay và xé khăn che mặt, xác nhận đó là Vương tổng quản của Hinh Vương phủ. Tiểu vương gia phản kích bằng mười tia đen nhưng bị mai rùa đen chặn lại, rồi bùng hắc quang bỏ chạy. Hàn Lập chặn trước mặt bằng cự kiếm màu xanh, còn tiểu vương gia tin hộ thể sát khí có thể ăn mòn pháp khí nên định mượn đòn để vượt qua."},{"chuong":309,"tieuDe":"Yêu Hóa","tomTat":"Vương tổng quản dù đang bị Hàn Lập khống chế vẫn cố cảnh báo Tiểu Vương gia tránh Thanh Nguyên kiếm, nhưng lời nhắc đã muộn. Tiểu Vương gia né theo bản năng vẫn bị kiếm xanh phá hắc khí hộ thân, chém đứt hai bắp chân rồi hôn mê và bị Hàn Lập bắt sống. Hàn Lập giao hai tù binh cho Mông Sơn tứ hữu cầm máu để tra khẩu cung, còn các hắc y tu sĩ ngoại vi thấy thế bại liền bỏ chạy. Đúng lúc đó, Già Thiên chung giam đại hán đầu bóng lưỡng liên tục biến dạng, suy yếu rồi vỡ tan, để lộ một quái vật hình người đã yêu hóa. Hàn Lập bố trí thêm khôi lỗi thú, dùng mười cột sáng đánh ngã đối thủ, nhưng pháp khí của Mông Sơn tứ hữu không gây thương tổn và nhanh chóng bị phá nát. Lão giả mặt đen dùng Bạch Lân thuẫn chống lợi trảo, rồi bốn người Mông Sơn tứ hữu hợp lực truyền linh lực mới tạm giữ được phòng tuyến. Nhận ra pháp khí thông thường khó đối phó thân thể yêu hóa, Hàn Lập giao nhóm tán tu và khôi lỗi thú cầm chân đại hán, còn mình lấy phù lục màu xanh ra vận công thi triển phù bảo."},{"chuong":310,"tieuDe":"Hoàng Thất","tomTat":"Hàn Lập dùng tu vi Trúc Cơ trung kỳ nhanh chóng kích hoạt phù bảo thước ngọc màu xanh, khiến phù lục hóa thành thước ngọc rồi phân ra hàng trăm thước nhỏ công kích đại hán đầu bóng lưỡng yêu hóa. Đại hán nhận ra nguy hiểm, dùng hồng quang bỏ chạy cực nhanh; Hàn Lập không truy đuổi vì uy lực phù bảo còn lại không nhiều. Sau trận, Hàn Lập cho Mông Sơn tứ hữu đan dược trị thương, rồi cùng họ đưa Tiểu vương gia và Vương tổng quản lên Thần Phong Chu rời miếu hoang về Tần trạch. Tại Tần trạch, hắn dùng dược vật và Mê hồn Huyễn sắc nhãn khống chế Tiểu vương gia để thẩm vấn, sau đó cho hắn uống Đoạn hồn đan vì tội tu luyện ma công và huyết tế nhiều tu sĩ. Mông Sơn tứ hữu thẩm vấn Vương tổng quản tại Thanh Âm Viện, biết Hắc Sát giáo chủ đang ẩn trong hoàng cung, thao túng hoàng đế Việt quốc, và thân phận ngoài sáng là đại nội tổng quản Lý Phá Vân. Hàn Lập vì thế rơi vào thế khó xử: muốn diệt Hắc Sát giáo nhưng lại e ngại quy định bất thành văn của bảy phái cấm đệ tử bước vào hoàng thành."},{"chuong":311,"tieuDe":"Huyết Tế Bí Ẩn","tomTat":"Hàn Lập bác bỏ nỗi lo Giáo chủ Hắc Sát giáo là tu sĩ Kết Đan, khẳng định đối phương nhiều nhất chỉ ở Trúc Cơ hậu kỳ vì vẫn phải dựa vào Huyết tế. Hắn giải thích Huyết tế là tà pháp hấp thu tinh huyết và tu vi của người khác để tăng pháp lực, nhưng người tu cả đời không thể Kết Đan và dễ bị phản phệ; Hồn tế về sau cũng chỉ là biến thể nhắm vào hồn phách nguyên thần với giới hạn tương tự. Từ tin tức lấy được nơi Tiểu Vương gia, Hàn Lập suy đoán Giáo chủ đang bế quan ở thời điểm mấu chốt và phải dựa vào Âm huyệt trong Hoàng Cung để thu công, nên Hắc Sát giáo khó bỏ sào huyệt chạy trốn. Hắn quyết định để mọi người tạm thời ẩn trong phủ, hạn chế ra ngoài và chờ viện binh đến. Đêm canh ba, Thiết La khoác áo choàng, cầm Kim bài vượt qua các trạm canh trong Đại nội Hoàng Cung rồi vào một tòa điện âm lãnh, lộ rõ tình trạng nguyên khí đại thương sau khi thoát khỏi Hàn Lập. Trong điện, Băng Yêu châm chọc thương thế của Thiết La, nghe hắn nói đã phải dùng Sát Yêu hóa thân để giữ mạng và lo bị phạt vì ký danh đệ tử của Giáo chủ rơi vào tay đối thủ. Băng Yêu cho rằng họ có quan hệ đồng tâm dị thể với Giáo chủ nên sẽ không bị trách phạt quá nặng, rồi cho biết Thanh Văn và Diệp Xà đang ở Huyết lao luyện công, trong đó Thanh Văn đã là Trúc Cơ trung kỳ còn Diệp Xà sắp tiến giai."},{"chuong":312,"tieuDe":"Bình Tĩnh Dữ Viện Binh","tomTat":"Thiết La sau khi bị thương trở về Hắc Sát giáo, bị Băng Yêu châm chọc rồi vào Lãnh cung bái kiến giáo chủ đang bế quan dưới hòn giả sơn. Hắn thú nhận nhiệm vụ thất bại, để Thiếu chủ và Vương hộ pháp rơi vào tay đối thủ, nhưng giáo chủ không trách phạt mà phân tích Hàn Lập có thể liên hệ Khôi Lỗi thuật của Thiên Trúc giáo. Giáo chủ cho rằng Sát Yêu hóa thân của Thiết La khó chống nổi phù bảo của Hàn Lập, đồng thời bác đề nghị điều Tứ đại huyết thị ra tay vì việc bế quan đã tới thời điểm then chốt. Ông ta ra lệnh giáo đồ ở lại Hoàng Cung, chờ công pháp đại thành rồi mới xử lý các tu sĩ Trúc Cơ Kỳ, khiến Hắc Sát giáo tạm thời án binh đúng như Hàn Lập dự liệu. Hơn nửa tháng sau, Hàn Lập cũng giữ thế co rút ở Tần phủ, yên tâm phần nào vì Ma Đạo không xuất hiện và khuyên Tần Ngôn tránh ra ngoài. Một sáng sớm, Hàn Lập cảm ứng được vài tu sĩ Trúc Cơ Kỳ ẩn khí tức ngoài cửa nên tưởng địch đến, lập tức gọi Bạch Luân Thuẫn, cầm Hỏa Vân phù và chuẩn bị đào tẩu. Sau đó tiếng cười vang lên, hắn nhận ra Tống Mông dẫn Tam sư huynh, Thất sư tỷ và một nam tử trẻ tuấn mỹ đến làm viện binh. Các đồng môn khen Hàn Lập đã đạt Trúc Cơ trung kỳ, còn Hàn Lập vui mừng hành lễ, để lại ấn tượng tốt với Tam sư huynh."},{"chuong":313,"tieuDe":"Quyết Định","tomTat":"Hàn Lập tiếp bốn đồng môn gồm Lưu Tĩnh, Tống Mông, Vũ Huyễn và Chung Vệ Nương đến hỏi chuyện Hắc Sát giáo, đồng thời nhận ra Vũ Huyễn vẫn không ưa mình vì chuyện Đổng Huyên Nhi và kinh ngạc trước việc hắn đã lên Trúc Cơ trung kỳ. Theo yêu cầu của Lưu Tĩnh và Chung Vệ Nương, Hàn Lập kể lại tình hình Hắc Sát giáo bắt tu sĩ để Huyết tế luyện công, có nhiều cao thủ Trúc Cơ kỳ và hành sự độc ác, khiến Lưu Tĩnh nổi sát khí. Khi Hàn Lập thuật lại chuyện Hinh Vương phủ, hắn cố che giấu bí mật riêng nhưng bị Lưu Tĩnh truy vấn nhiều chi tiết nên suýt lộ sơ hở. Sau khi biết Hắc Sát giáo có bốn Huyết thị, các đàn chủ và giáo chủ khó lường, lại ẩn trong Hoàng Cung Việt Kinh là cấm địa của Thất đại phái, Vũ Huyễn đề nghị xin ý sư phụ và gọi thêm người. Lưu Tĩnh phản đối việc bỏ qua tà tu, cho biết có thể nhờ ký danh đệ tử của Huy Minh sư bá ở Nam Ô thành hỗ trợ và tuyên bố tự gánh trách nhiệm nếu bị trách phạt. Tống Mông và Chung Vệ Nương lập tức ủng hộ Lưu Tĩnh, còn Vũ Huyễn từ chối tham gia nếu không có lệnh trực tiếp của sư phụ. Cuối cùng Hàn Lập cân nhắc lợi hại rồi quyết định đi cùng, vì chuyện vốn do hắn khơi ra và hắn cũng muốn tận mắt kiến thức giáo chủ Hắc Sát giáo thần bí."},{"chuong":314,"tieuDe":"Hội Hòa","tomTat":"Hàn Lập nhận lời cùng Lưu Tĩnh, Chung Vệ Nương và Tống Mông đối phó Hắc Sát giáo, khiến mọi người phấn chấn, trong khi Vũ Huyễn không muốn bị liên lụy nên rời Tần phủ và nói sẽ báo lại cho Lý Hóa Nguyên. Lưu Tĩnh cho rằng phải hành động trước khi giáo chủ Hắc Sát giáo xuất quan, bèn phân công Chung Vệ Nương đến Nam Ô thành mời Trần Xảo Thiến, nhờ Hàn Lập sắp xếp nơi tĩnh tu trong Tần phủ và để Tống Mông ở lại phòng tập kích. Ba ngày sau, Chung Vệ Nương đưa Trần Xảo Thiến cùng bốn đồng môn khác về, khiến Hàn Lập bất an vì từng quen biết nàng. Một nữ sư tỷ của Trần Xảo Thiến nhắc chiến tích Hàn Lập từng một mình giết hơn mười tu sĩ Ma Đạo Trúc Cơ kỳ, làm Lưu Tĩnh và Chung Vệ Nương thay đổi cách nhìn về hắn. Sau bữa cơm, Lưu Tĩnh tự nguyện gánh hậu quả vi phạm cấm lệnh của Thất đại phái, nhờ vậy nhóm viện binh yên tâm tham gia. Dựa trên tình báo của Hàn Lập, cả nhóm thống nhất đêm hôm sau lẻn vào Hoàng cung để ra tay trước với Hắc Sát giáo. Hàn Lập ngoài mặt mỉm cười nhưng trong lòng không xem nhẹ nguy hiểm, bởi lý do thật khiến hắn mạo hiểm là bí mật từ Tiểu Vương gia có thể giúp ích cho Kết Đan và một hậu thủ bảo mệnh đã chuẩn bị sẵn."},{"chuong":315,"tieuDe":"Hậu Thủ, Hoài Nghi","tomTat":"Trong đêm yên tĩnh, Hàn Lập lặng lẽ rời Tần phủ, dùng Thần Phong Chu bay vào Hoàng thành dù Thất đại phái đã cấm đệ tử tiến vào khu vực này. Hắn lợi dụng khẩu quyết vô danh đã đại thành và thông tin từng lấy được từ Tiểu vương gia để tránh trạm gác của Hắc Sát giáo, rồi chọn rừng trúc hoang vắng trong Ngự hoa viên làm nơi bố trí hậu thủ. Sau khi thi triển Cách âm kết giới, Hàn Lập lấy trận kỳ và trận bàn Điên đảo ngũ hành trận do Tề Vân Tiêu tặng ra bố trí, xem đây là lá bài bảo đảm bất bại trước giáo chủ Hắc Sát giáo. Vì thời gian gấp, hắn chỉ hoàn thành được một phần nhỏ trận pháp nhưng vẫn cho là đủ, rồi rời Hoàng cung mà không bị phát hiện trong lúc Hắc Sát giáo chỉ tập trung canh phòng quanh Lãnh cung. Trở về Tần phủ trước bình minh, Hàn Lập vẫn bình thản gặp đồng môn Hoàng Phong cốc và giữ kín chuyện trận pháp, đồng thời thầm đánh giá nhiều người thiếu kinh nghiệm giao thủ với tu sĩ Trúc Cơ kỳ. Sau đó Trần Xảo Thiến bất ngờ mời Hàn Lập đi riêng, khiến đồng môn kinh ngạc và Chung Vệ Nương trêu chọc làm nàng đỏ mặt. Trong hoa viên, Trần Xảo Thiến chất vấn Hàn Lập về chuyện hắn che giấu thực lực trong Huyết sắc thí luyện rồi chuyển sang hỏi chuyện cứu người nhiều năm trước. Hàn Lập nhận ra nàng có thể vẫn để tâm tới người từng cứu mình, nhưng vì ký ức về sự thân thiết giữa nàng và Lục sư huynh, hắn tự loại bỏ khả năng tiếp nhận nàng về mặt tình cảm."},{"chuong":316,"tieuDe":"Thất Tung","tomTat":"Trần Xảo Thiến dò hỏi Hàn Lập về chuyện bảy tám năm trước, nghi hắn chính là người từng ra ngoài vào thời điểm gần Huyết sắc thí luyện. Hàn Lập bình tĩnh phủ nhận, nói mình chỉ mua pháp khí và phù lục để chuẩn bị thí luyện, khiến nàng thất vọng nhưng vẫn không từ bỏ nghi ngờ. Sau đó nhóm tu sĩ Hoàng Phong cốc chuyển sang chuẩn bị đánh Hắc Sát giáo, vừa tự tin vì có ưu thế Trúc Cơ kỳ vừa thận trọng trước nguy cơ mất mạng. Hàn Lập kiểm tra khôi lỗi thú, khuyên Mông Sơn tứ hữu không tham chiến vì tu vi Luyện Khí kỳ quá yếu, rồi tặng họ thượng giai pháp khí và đưa ra khỏi Việt Kinh. Trước lúc chia tay, lão giả mặt đen hé lộ rằng các huynh đệ đều hiểu Ngũ muội đã lún quá sâu và có lẽ sẽ không xuất hiện. Tối đến tại Tần phủ, Lưu Tĩnh trở về sau khi tìm Vũ Huyễn không gặp, báo rằng Vũ Huyễn đã rời khách điếm từ sáng hôm trước, đồ đạc vẫn còn, không giống đã về cốc. Mọi người không rõ nguyên nhân, còn Hàn Lập thầm nghi Vũ Huyễn có thể bị Hắc Sát giáo bắt. Lưu Tĩnh quyết định gác chuyện này lại, lập tức dẫn đội xuất phát với mục tiêu tiêu diệt hoàn toàn Hắc Sát giáo."},{"chuong":317,"tieuDe":"Tứ Tượng Trận","tomTat":"Đêm xuống, nhóm tu sĩ Hoàng Phong Cốc do Lưu Tĩnh dẫn đầu ngự khí tiến vào Hoàng thành và Hoàng cung Việt Quốc. Hàn Lập cố ý bay sau cùng để âm thầm cảm ứng Điên đảo ngũ hành trận đã bố trí từ đêm trước, xác nhận đại trận cùng dấu hiệu linh khí vẫn nguyên vẹn. Lưu Tĩnh chia đội thành hai mũi: Chung Vệ Nương và Trần Xảo Thiến đi cứu Hoàng đế Việt Quốc, còn hắn cùng những người còn lại đánh thẳng Lãnh cung để diệt Tứ đại huyết thị rồi đối phó giáo chủ Hắc Sát giáo. Khi đội đánh Lãnh cung bị đệ tử Hắc Sát giáo phát hiện, Lưu Tĩnh dùng khăn tay tơ tằm hóa lá chắn chống đỡ, còn Tống Mông dùng Lam Ti kiếm thi triển Vạn Ti thiên hạ đánh tan phần lớn lực lượng phòng thủ. Băng Yêu xuất hiện trước cửa Lãnh cung, ra lệnh khởi động Tứ Tượng trận, khiến cảnh vật biến đổi và cả nhóm bị vây trong vùng băng tuyết. Trong lúc mọi người chưa biết cách phá trận, Hàn Lập lấy Thủy Tinh cầu quan sát rồi nói mình có thể tìm được sơ hở trận pháp, khiến nhóm đang lo lắng trở nên vui mừng."},{"chuong":318,"tieuDe":"Thanh Văn Trọng Hiện","tomTat":"Hàn Lập dùng Thủy Tinh cầu phát hiện một phía của Tứ tượng trận có linh khí dao động yếu hơn, rồi đưa cho Lưu Tĩnh kiểm tra để xác nhận sơ hở. Lưu Tĩnh lập tức chỉ huy mọi người tập trung pháp khí công kích điểm yếu, khiến trận pháp nổ tung và nhóm Hoàng Phong cốc thoát khỏi sương trắng trước Lãnh cung. Băng Yêu lâm vào thế bị động vì Diệp Xà đáng lẽ cùng canh cửa lại lẻn vào Huyết Lao luyện công, trong khi giáo đồ giữ trận đã tổn thất khiến trận pháp càng khó duy trì. Khi Thanh Văn đạo sĩ và Thiết La xuất hiện tiếp viện, Tống Mông công khai thân phận Hoàng Phong cốc, còn Thanh Văn dùng cấm lệnh Thất đại phái để chất vấn việc xông vào Hoàng cung ban đêm. Thiết La nhận ra Hàn Lập là người từng biết Khôi Lỗi thuật và nghi hắn thuộc Thiên Trúc giáo, nhưng Hàn Lập phủ nhận rồi nhận ra Thanh Văn chính là đạo sĩ từng mời hắn đồng hành ở Thái Nam hội năm xưa. Nhờ đó Hàn Lập liên hệ được nguyên nhân mình từng bị Hoàng y nhân truy sát và nổi sát ý với Thanh Văn. Lưu Tĩnh nhìn ra đối phương đang kéo dài thời gian nên ra lệnh khai chiến, kéo hai phe vào hỗn chiến pháp khí. Hàn Lập cùng Vương sư huynh giáp công Thanh Văn, nhưng Thanh Văn triển khai Thanh Mộc chân tráo bằng năm pháp khí màu xanh và tự tin nói tu sĩ Trúc Cơ kỳ không thể phá được."},{"chuong":319,"tieuDe":"Tứ Đại Huyết Thị","tomTat":"Hàn Lập thu các pháp khí đang vây đánh Thanh Văn lên không, chuẩn bị thi triển Cự Kiếm thuật trong Thanh Nguyên kiếm quyết. Thanh Văn dùng Tỏa Kim hoàn đánh úp nhưng bị Vương sư huynh dùng ba đạo lục mang chặn lại, giúp Hàn Lập hoàn tất pháp thuật. Cự kiếm ba màu của Hàn Lập phá Đồng thuẫn do Hoàng Đồng kính tạo ra rồi tiếp tục ép xuống Thanh Mộc chân tráo, khiến Thanh Văn phải dốc linh lực chống đỡ. Vương sư huynh nhân cơ hội đánh nát Kim hoàn và định kết liễu Thanh Văn, nhưng Ngô Cửu Chỉ bất ngờ xuất hiện bằng hào quang vàng cứu Thanh Văn khỏi đòn chí mạng. Hàn Lập nhận ra Ngô Cửu Chỉ là thiếu niên móc túi năm xưa nay đã thành Trúc Cơ sơ kỳ và đứng ở phe đối địch. Thanh Văn gọi Băng Yêu và Thiết La rời vòng vây của nhóm Lưu Tĩnh, bốn Huyết thị tụ lại rồi cùng phát hào quang đỏ máu, bắt đầu biến thân Yêu hóa."},{"chuong":320,"tieuDe":"Phá Kiển","tomTat":"Nhóm tu sĩ Hoàng Phong cốc theo lời nhắc trước đó của Hàn Lập, lập tức dồn pháp khí và đạo thuật công kích bốn quang kén Huyết thị, nhưng đợt đầu không làm chúng tổn hại. Lưu Tĩnh yêu cầu mọi người dùng tuyệt chiêu, bản thân kích phát kim phù thi triển Thiên Nhận thuật, còn Tống Mông và sư tỷ của Trần Xảo Thiến cũng khởi động phù bảo. Hàn Lập không dùng phù bảo hay Cự Kiếm thuật mà thả bốn Khôi lỗi thú tấn công để vừa gây sức ép vừa hồi phục pháp lực, vì giáo chủ Hắc Sát giáo vẫn chưa lộ diện. Theo chỉ huy của Lưu Tĩnh, mọi người tập trung hỏa lực vào quang kén bên trái của Băng Yêu, khiến lớp huyết quang bị trường thương phù bảo của Tống Mông xuyên thủng. Băng Yêu bị ép xuất hiện trong hình dạng nửa yêu hóa màu trắng, vết thương nhanh chóng khép lại và hắn đe dọa sẽ kéo dài thời gian chờ đồng bọn hoàn tất biến thân. Hàn Lập lập tức sai Khôi lỗi thú đánh phủ đầu, nhưng Băng Yêu dùng sương lạnh biến mất, khiến mọi người tưởng là Độn thuật. Hàn Lập nhận ra đối phương đang ẩn trốn, vội gọi Bạch Lân thuẫn cùng pháp khí hộ thân và cảnh báo đồng môn. Ngay sau đó, sư tỷ của Trần Xảo Thiến đang khống chế phù bảo bị Băng Yêu ẩn thân xuyên ngực, bóp nát tim và chết trong vũng máu."},{"chuong":321,"tieuDe":"Ẩn Đấu","tomTat":"Tuyết Hồng sư tỷ chết thảm vì thu pháp khí phòng ngự trong lúc kích phát phù bảo, tạo sơ hở cho Băng Yêu ẩn hình đánh lén. Cái chết của nàng khiến đồng môn Hoàng Phong Cốc hoảng sợ, còn đạo lữ song tu của nàng đau đớn dùng ô quang quét quanh thi thể để tìm Băng Yêu. Băng Yêu tiếp tục dùng thuật ẩn thân và tốc độ cao áp chế cả nhóm, khiến các pháp thuật dò tìm và pháp khí phòng ngự đều khó phát huy hiệu quả. Vương sư huynh trở thành mục tiêu tiếp theo, Thanh Đồng tiểu thuẫn đỡ được đòn đầu nhưng bị băng phong, khiến hắn suýt chết ở đòn thứ hai. Hàn Lập kịp thời cứu Vương sư huynh rồi trực tiếp giao chiến với Băng Yêu trong trạng thái người ngoài chỉ nghe tiếng va chạm mà khó thấy tung tích. Băng Yêu kinh hãi khi nhận ra Hàn Lập nhìn thấu thuật ẩn thân và theo kịp tốc độ của mình. Trận chiến lan rộng khiến Lưu Tĩnh, Tống Mông và những người còn lại phải lùi khỏi khu vực, trong khi mặt đất dần bị đóng một tầng băng dày dưới ánh trăng. Lưu Tĩnh nhận định Hàn Lập chưa rơi vào hạ phong nhưng vẫn nặng lòng vì đội đã mất Tuyết Hồng."},{"chuong":322,"tieuDe":"Lưu Tĩnh Dữ Chân Bảo","tomTat":"Hàn Lập vừa cứu Vương sư huynh vừa bị Băng Yêu cuốn lấy, nhưng điều khiến hắn bất mãn là nhóm đồng môn bỏ lỡ thời cơ công kích ba Huyết thị còn đang biến thân. Hắn nhanh chóng nhìn ra năng lực ẩn thân của Băng Yêu thực chất dựa vào thân thể trong suốt, tốc độ cực nhanh và ưu thế cận chiến dưới mặt đất, nên yêu cầu mọi người bay lên không trung và dùng pháp thuật diện rộng khắc chế. Trong lúc Hàn Lập dùng ngân kiếm giữ chân Băng Yêu, Lưu Tĩnh bị đặt trước lựa chọn rút lui hay tiếp tục đánh Hắc Sát giáo. Chương hé lộ quá khứ Lưu Tĩnh từng bị tà tu bắt đi ngược đãi, sau được gia tộc cứu ra và bái nhập môn hạ Lý Hóa Nguyên, từ đó căm hận tà tu nhưng cũng dần mê luyến danh vọng diệt tà. Vì không muốn thanh danh sụp đổ, Lưu Tĩnh quyết định để mọi người hộ pháp trên không và tự mình xử lý ba Huyết thị còn lại. Hắn lấy ra hộp ngọc đỏ lửa, phá hộp để lộ phù lục hỏa điểu tỏa nhiệt dữ dội, khiến Tống Mông tưởng là phù bảo còn Vương sư huynh kinh hãi nhận ra đó là Chân bảo. Chương cuối cùng giải thích Chân bảo là phù bảo đặc biệt chứa một phần ba uy lực pháp bảo bản thể, chỉ hậu nhân huyết mạch trực hệ sử dụng được, dùng một lần và khiến pháp bảo gốc tổn thất vĩnh viễn."},{"chuong":323,"tieuDe":"Trảm Yêu","tomTat":"Lưu Tĩnh biết Chân bảo khó kích phát hơn phù bảo thường nên cần đồng môn hộ pháp, sau đó phóng viên hoàn màu vàng bảo vệ quanh thân và dốc pháp lực vào Hỏa điểu Chân bảo. Trên mặt đất, Hàn Lập nhận ra La Yên bộ không thể kéo dài với thân thể Trúc Cơ trung kỳ, bèn âm thầm dùng ti tuyến quấn vào lợi trảo Băng Yêu rồi phối hợp ngân kiếm chém nát thân thể băng hóa của đối thủ. Hắn bỏ lại nửa băng trảo vì ghê sợ nguồn gốc từ tay người, chỉ thu túi trữ vật của Băng Yêu rồi bay lên hội hợp đồng môn. Trong mật thất dưới hòn giả sơn, trung niên nhân mắt đỏ của Hắc Sát giáo cảm nhận Băng Yêu đã chết nhưng tỏ ra thờ ơ, bên cạnh là thi hài tu sĩ Hoàng Phong cốc bị hút sạch huyết nhục. Tống Mông và các đồng môn kính sợ Hàn Lập sau trận chém Băng Yêu, còn đạo lữ song tu của Tuyết Hồng sư tỷ vô cùng cảm kích. Cuối chương, Lưu Tĩnh kích phát thành công Hỏa điểu Chân bảo, thả chim lửa xuống đúng lúc yêu vật mang khuôn mặt Thanh Văn đạo sĩ phá kén; Thanh Văn hoảng sợ bỏ chạy nhưng bị hỏa diễm cự điểu lao tới phía sau."},{"chuong":324,"tieuDe":"Hắc Sát Giáo Chủ","tomTat":"Chân bảo hỏa điểu tiếp tục phát uy sau khi thiêu Thanh Văn, cuốn cả hai Huyết thị vừa phá kén vào biển lửa và luyện hóa sạch, khiến Hàn Lập kinh hãi trước uy lực pháp bảo của tu sĩ Kết Đan kỳ. Nhóm Hoàng Phong cốc tưởng thế cục đã thuận lợi, Lưu Tĩnh dẫn mọi người chuẩn bị tiến vào lãnh cung để tiêu diệt Hắc Sát giáo chủ, trong khi Hàn Lập chú ý thấy Vương sư huynh đang che giấu một phát hiện trên mặt đất. Chung Vệ Nương và Trần Xảo Thiến bắt Việt hoàng đem tới, đồng thời cho biết hai đệ tử Hắc Sát giáo Luyện Khí kỳ định ngăn cản cũng đã bị xử lý. Tin Tuyết Hồng sư tỷ đã chết khiến Trần Xảo Thiến và Chung Vệ Nương chấn động, còn đạo lữ song tu của Tuyết Hồng phải cố nén bi thống báo tin. Ngay sau đó, một Lam bào nhân bất ngờ hiện thân, giết Vương sư huynh để lấy lại hạt châu màu xanh rồi thừa nhận mình là người sáng lập Hắc Sát giáo. Khi Lưu Tĩnh chuẩn bị lấy pháp khí giao chiến, một kẻ không thể tưởng tượng được từ phía phe tu sĩ bất ngờ đánh lén, xuyên thủng ngực Lưu Tĩnh và một sư huynh của Trần Xảo Thiến. Lưu Tĩnh chết trong tiếng hét thảm của Chung Vệ Nương, còn Trần Xảo Thiến vừa bảo vệ nàng vừa phẫn nộ nhìn kẻ đánh lén đã đứng về phía Hắc Sát giáo chủ."},{"chuong":325,"tieuDe":"Quỷ Dị","tomTat":"Sau khi thi thể Lưu Tĩnh cùng một sư huynh Hoàng Phong cốc đổ xuống trước mặt Hàn Lập, Việt hoàng bỏ vẻ kinh hoảng và lộ tu vi Trúc Cơ hậu kỳ, tuyên bố cần thêm tu sĩ Trúc Cơ để huyết tế. Lam bào nhân lấy viên châu màu lam từ thi thể Băng Yêu, còn Việt hoàng lấy hai viên châu kim và hoàng từ nơi Huyết thị chết, khiến Hàn Lập đoán đây là Ngũ hành huyết ngưng đan liên quan Kết đan và nhận ra vẫn còn thiếu một viên. Trước sát khí của đối phương, Hàn Lập dùng Thần Phong chu bay lên và gọi mọi người rời mặt đất; Tống Mông cùng đạo lữ song tu của Tuyết Hồng sư tỷ theo ngay, Trần Xảo Thiến kéo Chung Vệ Nương bay lên sau. Việt hoàng sau đó đâm tay vào ngực Lam bào nhân, hấp nạp huyết quang và sinh cơ của hắn, khiến bản thân trẻ lại và mạnh hơn. Hàn Lập tung hơn trăm Hỏa hệ phù lục để che mắt rồi giấu Thiên Lôi tử trong đó, tạo vụ nổ bạch quang đánh thẳng vào Việt hoàng. Tuy nhiên Việt hoàng vẫn sống sót sau đòn này; Hàn Lập lập tức gọi Khôi lỗi thú và Khôi lỗi binh sĩ ra chuẩn bị tiếp chiến. Khi Tống Mông cùng những người còn lại dùng pháp khí tập kích, một luồng hồng quang quét qua khiến họ mất liên hệ với pháp khí, còn Việt hoàng đầy máu và oán độc bước ra nhìn chằm chằm Hàn Lập."},{"chuong":326,"tieuDe":"Huyết Linh Toản","tomTat":"Hàn Lập nhận ra pháp khí của nhóm Tống Mông bị huyết quang của Việt Hoàng giữ lại và gần như mất linh tính, từ đó suy đoán ma quang hộ thể của đối phương chuyên ăn mòn pháp khí thông thường. Chàng lập tức lệnh hơn mười khôi lỗi công kích, còn nhóm Tống Mông chuyển sang dùng phù lục để tránh mất thêm pháp khí. Việt Hoàng chống đỡ bằng quang thuẫn rồi nuốt Tu tủy đan, nhanh chóng hồi phục thương thế và pháp lực khiến mọi người kinh hãi. Chung Vệ Nương tỉnh lại, giải thích lai lịch Tu tủy đan và tuyên bố muốn giết Việt Hoàng để báo thù cho Lưu sư huynh. Sau đó Việt Hoàng thu viên châu đỏ rực, khiến Hàn Lập liên tưởng đến Ngũ hành huyết ngưng đan và lợi ích cho việc Kết đan. Trong cuộc đối đáp, Việt Hoàng bất ngờ thi triển Huyết Linh Toản, xuyên thủng Bạch Lân thuẫn, Quy xác pháp khí và Thanh Nguyên kiếm thuẫn, làm Hàn Lập trọng thương ở vai phải. Nhận thấy chỉ nhờ La Yên bộ mới thoát chết, Hàn Lập lập tức ra lệnh rút chạy bằng Thần Phong chu, còn các khôi lỗi được dùng để vây chặn Việt Hoàng truy kích."},{"chuong":327,"tieuDe":"Nhập Trận","tomTat":"Việt Hoàng dùng huyết quang phá hủy toàn bộ đám khôi lỗi cản đường rồi lập tức truy kích nhóm Hàn Lập. Hàn Lập cảm ứng khôi lỗi bị hủy nhưng không dừng lại, dẫn Tống Mông, Chung Vệ Nương, Trần Xảo Thiến và đồng môn đáp xuống rừng trúc đã bố trí trận pháp. Việt Hoàng dùng hộ thể ma quang hóa thành huyết quang bao phủ rừng trúc, định thúc bí pháp luyện hóa toàn bộ người bên trong, khiến màn phòng hộ trắng xanh ban đầu bị ép đến mức lung lay. Trong lúc nhóm đồng môn hoang mang, Trần Xảo Thiến nhìn ra Hàn Lập vẫn còn hậu thủ, còn Hàn Lập lấy trận kỳ màu tím cùng trận bàn màu vàng để phát động Điên Đảo Ngũ Hành trận. Đại trận biến màn phòng hộ thành màn sáng năm màu vững chắc, chặn huyết quang và khiến Việt Hoàng không thể bay khỏi phạm vi trận dù thử nhiều lần. Khi xác định đối phương đã bị khốn, Hàn Lập phóng Bạch Lân thuẫn và Quy xác pháp khí hộ thân, rồi yêu cầu mọi người kích phát Phù bảo để chuẩn bị hợp lực tiêu diệt Việt Hoàng."},{"chuong":328,"tieuDe":"Hắc Huyết Đao","tomTat":"Trong Điên Đảo Ngũ Hành Trận, Hàn Lập lấy phù lục màu xanh ra khởi phát, còn Trần Xảo Thiến và Chung Vệ Nương cũng lấy phù bảo đỏ, vàng để chuẩn bị phối hợp công kích Việt Hoàng. Tống Mông và sư huynh Trần Xảo Thiến không có phù bảo thích hợp nên đứng hộ pháp bên cạnh. Bị vây trên không, Việt Hoàng dừng chạy loạn, tự rạch hai cổ tay cho máu dung nhập vào huyết quang rồi lấy ra một chuôi đao đen nhỏ và niệm chú cổ xưa. Hắn tiếp tục phun tinh huyết để trấn áp khối hắc huyết bất ổn, khiến chuôi đao biến thành Hắc Huyết Đao tỏa huyết khí nặng nề. Hàn Lập dùng thần thức quan sát thì phát hiện thanh đao có thể cắn nuốt thần thức, nhưng vẫn tin Điên Đảo Ngũ Hành Trận đủ sức cầm chân Việt Hoàng trong thời gian ngắn. Việt Hoàng cầm Hắc Huyết Đao lao xuống rừng trúc, bổ rách tầng phòng hộ ngũ sắc đầu tiên làm Tống Mông hoảng sợ, song Hàn Lập truyền âm trấn an rằng đó mới chỉ là tầng ngoài. Cuối chương, Việt Hoàng tiến sâu hơn vào tầng ngũ sắc, thấy nhóm Hoàng Phong Cốc đang khu động phù bảo và vung Hắc Huyết Đao chém một đạo hắc mang dài hơn mười trượng xuống đỉnh đầu Hàn Lập."},{"chuong":329,"tieuDe":"Diệt Địch","tomTat":"Tống Mông cùng đồng môn Hoàng Phong Cốc cố dùng hỏa cầu và phù lục cự thạch cản đao mang của Việt hoàng nhưng đều bị nghiền nát. Khi Việt hoàng chém xuống Hàn Lập, đối thủ biến mất còn chính hắn bị Cấm đoạn đại trận chuyển dời về chỗ cũ; hắn thử phá trận bằng huyết quang và Hắc huyết đao nhưng công kích bị nuốt, bị dịch chuyển hoặc bắn ngược, tâm thế từ tự tin chuyển sang kinh hoảng. Hàn Lập kích phát Phù bảo tiểu thước xanh, Trần Xảo Thiến và Chung Vệ Nương hợp kích bằng tiểu kiếm đỏ và tinh cầu vàng, ép Việt hoàng chống đỡ trong huyết phong. Hắc huyết đao đồng quy vu tận hủy hai Phù bảo của hai nữ tu khiến họ phải dùng dược hoàn hồi phục, Chung Vệ Nương nghi yêu đao là pháp bảo tàn phế. Cuối cùng Hàn Lập dốc toàn bộ uy năng còn lại của Phù bảo phá tan huyết quang, đánh chết Việt hoàng dù Phù bảo cũng hóa tro bụi. Nhắm tới Huyết ngưng ngũ hành đan, hắn thả hai Khôi Lỗi thú lục soát thi thể, đồng thời đề nghị các đồng môn đi kiểm tra Hoàng cung tìm tàn dư Hắc Sát giáo, thực chất nhường phần chiến lợi phẩm trong cung cho họ."},{"chuong":330,"tieuDe":"Sát Đan","tomTat":"Hàn Lập lấy năm khỏa Huyết ngưng ngũ hành đan từ miệng Khôi Lỗi thú, kiểm tra linh lực xác nhận không giả rồi cất vào hộp ngọc, tin rằng đan hữu dụng cho việc Kết đan. Hắn thận trọng dùng thanh quang bảo hộ hai tay rồi đưa thần thức vào ngọc giản Hắc Sát giáo, đọc được các công pháp như Hắc Sát Tu La công, Sát Yêu quyết, Huyết Luyện thần quang cùng nhiều lần nhắc tới quyển Huyền Âm Kinh chưa rõ hạ lạc. Ngọc giản giải thích Huyết ngưng ngũ hành đan là nội đan do người tu Sát Yêu quyết ngưng luyện, giúp tứ đại huyết thị biến thân sát yêu và vào Trúc Cơ kỳ mà không cần Trúc Cơ đan, song các công pháp Hắc Sát giáo đều khuyết hãm không thể Kết đan thật. Hàn Lập bị Sát Đan thuật hấp dẫn vì cho một phần ba cơ hội kết thành Ngụy kim đan có uy lực gần kim đan và tăng thọ, nhưng khi biết Sát Đan sẽ phóng thích sát yêu chi khí ăn mòn thần trí khiến đầu óc trì độn ngu dốt, hắn dứt khoát chặt đứt ý niệm tự dùng. Hắn chuyển hướng khi tìm thấy bí pháp Thân ngoại hóa thân, mừng rỡ vì có chỗ dùng đan, đồng thời suy đoán Việt hoàng vốn định dùng đan cho hóa thân và Lam bào nhân chính là hóa thân do Việt hoàng tế luyện. Cuối cùng hắn ghi nhớ phương pháp ngưng luyện Huyết Linh Toản, nhận ra tiêm trùy đỏ là Huyết Linh Toản còn bát đen là Tụ Hồn Bát chứa hồn phách nguyên thần nên lập tức thu vào túi trữ vật."},{"chuong":331,"tieuDe":"Mệnh Lệnh","tomTat":"Sau khi kết thúc giao chiến, Hàn Lập thu hồi toàn bộ trận bàn và trận kỳ của Điên đảo ngũ hành trận trong rừng trúc. Khi xử lý thi thể Việt hoàng, hắn phát hiện trong tro tàn có một tấm bản đồ không trọn vẹn, chất liệu cổ xưa và không giống địa hình Việt quốc, nên cất vào hộp ngọc. Trở lại lãnh cung, Hàn Lập biết Vũ Huyễn đã bị hút hết tinh huyết trong Huyết tế và chết trong mật thất của Hắc Sát giáo chủ. Hắn về Tần gia thì gặp Mã sư điệt mang thủ lệnh và ngọc giản của Lý Hóa Nguyên, qua đó biết đệ tử Trúc Cơ kỳ trở lên phải tới đại doanh Thất phái ở biên giới vì Ma đạo lục tông sắp quyết chiến. Lý Hóa Nguyên đồng thời hủy nhiệm vụ bảo hộ Tần gia, khiến Hàn Lập cảm thấy uất nghẹn vì những tổn thất trước đó trở nên vô nghĩa. Sáng hôm sau, nhóm Hoàng Phong Cốc bàn chuyện chia đường rời kinh đô: Trần Xảo Thiến về gia tộc, Chung Vệ Nương đưa di vật Lưu sư huynh về Lưu thị, còn Tống Mông đi cùng vị sư huynh sống sót. Buổi chiều Hàn Lập cáo biệt Tần Ngôn, rồi gặp Trần Xảo Thiến cố ý chờ mình và đồng ý cùng nàng đi Bạch Cúc sơn."},{"chuong":332,"tieuDe":"Cựu Địa","tomTat":"Hàn Lập nhận lời đưa Trần Xảo Thiến đến Bạch Cúc Sơn bằng Thần Phong Chu, dù trong lòng đã hối hận vì không muốn dây dưa tình cảm. Trên núi, Trần Xảo Thiến nói sau đại chiến nàng có thể phải gả cho một trực hệ đệ tử Tần gia thuộc Thiên Khuyết Bảo, nhưng Hàn Lập chỉ khách sáo chúc mừng, khiến nàng thất vọng tự rời đi. Trở lại Tần gia, Hàn Lập biết nàng đã đi trước, rồi trước khi rời Việt kinh hắn nhìn thấy Mặc Phượng Vũ sống bình tĩnh trong dáng thiếu phụ nên quyết định không quấy rầy. Hắn rời Việt quốc, bay về Gia Nguyên thành để thực hiện lời hứa báo thù cho Mặc phủ và kiểm tra Tứ Bình bang do Tôn Nhị Cẩu kinh doanh dưới sự hiệp trợ của Khúc Hồn. Tại Hương gia tửu lâu, Hàn Lập ngồi lại vị trí cũ mười năm trước và phát hiện phủ cũ của Mặc phủ đã đổi bảng thành Lý phủ, khiến hắn nghi môn chủ Ngũ Sắc môn họ Lý đã chiếm nơi này. Sau đó nhóm Hạ thiếu gia lên tửu lâu, sai chưởng quầy đuổi khách lầu ba để đãi khách quý; Hàn Lập vốn không để ý, nhưng khi nghe một người trong đoàn mới lên lầu bước rất nhẹ như có khinh công, hắn bắt đầu tò mò quan sát."},{"chuong":333,"tieuDe":"Tôn Bang Chủ","tomTat":"Hàn Lập ngồi trong tửu lâu ở Gia Nguyên thành, nghe lén cuộc trò chuyện giữa nhóm công tử địa phương và thanh niên họ Lý thuộc Ngũ Sắc môn. Từ lời họ, hắn biết nhóm công tử từng bị bắt cóc, được người Ngũ Sắc môn cứu, đồng thời biết Lý môn chủ đang ở Lý phủ chuẩn bị đại thọ sáu mươi. Hàn Lập quyết định chờ đến tối sẽ tới Lý phủ, nếu không có tu sĩ Trúc Cơ kỳ ở gần thì giết môn chủ Ngũ Sắc môn để hoàn thành việc đã định. Ban ngày, hắn chuyển sang xử lý tuyến Tứ Bình bang, nơi nay đã phát triển thành bang phái trung đẳng mạnh, tổng đà dời tới khu phố giàu và Tôn Nhị Cẩu đã trở thành Tôn bang chủ sống xa hoa. Hàn Lập lẻn vào hậu viện tổng đà, chờ trong phòng tiểu thiếp được sủng ái của Tôn Nhị Cẩu rồi gặp lại người cũ. Tôn Nhị Cẩu nhận ra Hàn Lập nhờ dung mạo không đổi do Định nhan đan, lập tức cung kính hành lễ và vẫn hết sức kiêng sợ ân nhân năm xưa. Khi trò chuyện, Hàn Lập phát hiện cơ thể Tôn Nhị Cẩu khác thường, rót linh lực kiểm tra kinh mạch và kết luận hắn đã trúng ẩn độc mãn tính. Chương kết lại bằng biến cố sinh tử của Tôn Nhị Cẩu khi Hàn Lập nói hắn nhiều nhất chỉ còn sống thêm một tháng."},{"chuong":334,"tieuDe":"Dị Biến","tomTat":"Hàn Lập gặp Tôn Nhị Cẩu và lập tức chỉ ra hắn đã bị trúng độc lâu ngày, rồi dùng Chân Linh quyết khiến độc tố hiện ra trên mặt khiến Tôn Nhị Cẩu kinh hãi cầu cứu. Hàn Lập lấy một viên giải độc đan màu lam cho hắn, đồng thời nhắc loại độc này phải tích lũy nhiều tháng nên kẻ hạ độc có thể nằm ngay quanh Tôn Nhị Cẩu. Khi Hàn Lập định mang Khúc Hồn đi, Tôn Nhị Cẩu báo Khúc Hồn đã sớm rời Tứ Bình bang và quanh quẩn trong vùng núi gần Gia Nguyên thành. Tôn Nhị Cẩu kể sáu năm trước Khúc Hồn từng giúp Tứ Bình bang đại thắng, sau đó bỗng mở miệng nói chuyện rồi phá tường bỏ chạy khi hắn mang Dẫn Hồn chung tới. Hàn Lập suy đoán cấm chế từng hạ trên Khúc Hồn vẫn còn tác dụng, vì Khúc Hồn luôn tránh người mang Dẫn Hồn chung, nên thu lại pháp khí này và quyết định tự đi xem xét. Cuối chương, Hàn Lập hỏi kỹ tình báo về môn chủ Ngũ Sắc môn, gia quyến và Lý phủ; khi Tôn Nhị Cẩu đoán chuyện này liên quan Mặc phủ năm đó, Hàn Lập lạnh giọng cảnh cáo hắn không được hỏi loạn hay suy đoán bừa."},{"chuong":335,"tieuDe":"Kinh Ngạc","tomTat":"Hàn Lập sau khi tra hỏi Tôn Nhị Cẩu liền cho hắn tiếp tục làm bang chủ Tứ Bình bang, đồng thời xé một lá Không Bạch phù làm hai nửa để lập tín vật cho hậu nhân Tôn gia. Tôn Nhị Cẩu mừng rỡ quỳ thề cả tộc đời đời cung phụng Hàn Lập làm chủ, còn được Hàn Lập ban hai bình đan dược trị thương và giải độc. Tối đến, Hàn Lập đột nhập Lý phủ, dùng định thần phù và Khống thần thuật tra ra nơi ở của môn chủ Ngũ Sắc môn, rồi giết người bịt miệng. Hắn tiếp tục hạ sát bốn thị vệ áo trắng bằng băng trùy và hỏa cầu để tránh để lại dấu vết. Khi vào viện, Hàn Lập bất ngờ gặp một thiếu phụ đang ôm con hát ru, nhận ra nàng chính là Mặc Ngọc Châu, đại tỷ của ba tỷ muội họ Mặc. Thanh niên họ Lý và môn chủ Ngũ Sắc môn sau đó bước ra, một người tức giận vì Hàn Lập gọi thẳng vợ mình, một người bình tĩnh nhận ra kẻ xâm nhập không đơn giản. Hàn Lập đánh giá lão môn chủ tâm cơ sâu, nhưng vì đối phương chỉ là phàm nhân nên không đặt nặng trong lòng."},{"chuong":336,"tieuDe":"Anh Trữ","tomTat":"Môn chủ Ngũ Sắc môn thấy Hàn Lập có thể đứng trước mặt mình thì đổi giọng dò hỏi, còn Hàn Lập thừa nhận từng học nghệ dưới môn hạ Mặc cư nhân và xem Mặc Ngọc Châu là sư tỷ. Khi phụ tử Ngũ Sắc môn nhận ra hắn là người Mặc phủ và định động thủ, Hàn Lập dùng hỏa cầu áp chế, khiến họ kinh hãi vì biết hắn là tu tiên giả. Đúng lúc Hàn Lập định giết hai người để báo thù Mặc phủ, Mặc Ngọc Châu ôm con gái lao ra chắn trước mặt, xin tha cho cha đứa nhỏ và biện hộ rằng phụ tử Ngũ Sắc môn chỉ nhận lệnh chứ không phải chủ mưu. Hàn Lập nói rõ mình biết Linh Thú Sơn đứng sau Ngũ Sắc môn, nhưng vì không muốn vì Mặc phủ mà kết thêm đại địch, hắn chuyển việc báo thù cho các tỷ muội Mặc phủ tự giải quyết. Hắn truyền âm địa chỉ Mặc Phượng Vũ và Mặc Thải Hoàn cho Mặc Ngọc Châu, đồng thời ép môn chủ Ngũ Sắc môn cam đoan không để nàng chịu ủy khuất. Cuối cùng, Mặc Ngọc Châu đưa con gái Anh Trữ cho Hàn Lập ôm để kết thiện duyên, còn Hàn Lập lấy một mảnh Thông Linh ngọc tặng đứa bé làm kỷ niệm."},{"chuong":337,"tieuDe":"Ám Thủ, Khúc Hồn","tomTat":"Hàn Lập cảnh cáo Ngũ Sắc môn chủ không được để Linh Thú Sơn biết chuyện đêm nay, nhưng nhận ra lão ngoài mặt phục tùng mà trong lòng chưa chắc yên phận. Để tránh trực tiếp giết người trước mặt Mặc Ngọc Châu, hắn âm thầm cấy Toàn tâm trùng vào người lão, khiến lão về sau sẽ chết như bệnh tim phát tác. Rời khỏi nơi đó, Hàn Lập dùng Thần Phong Chu bay về phía tây Gia Nguyên thành để xử lý dị biến của Khúc Hồn. Trong vùng núi rừng hoang vắng, hắn kích hoạt Dẫn Hồn chung, dựa vào tinh huyết Khúc Hồn trộn trong lúc luyện chế để truy tung, đồng thời che giấu khí tức chuông vì biết Khúc Hồn có thể cảm ứng được. Khi lặng lẽ áp sát bãi loạn thạch, Hàn Lập phát hiện thân thể Khúc Hồn đang có linh khí cỡ Luyện Khí kỳ tầng năm, sáu, từ đó nảy sinh nghi vấn mới về linh căn của Trương Thiết. Khúc Hồn sau đó mở mắt, tự nói chỉ cần bốn tháng nữa sẽ không còn sợ pháp khí khắc chế thân thể này, khiến Hàn Lập xác định trong thân thể bạn cũ có ý thức khác. Hàn Lập hiện thân chất vấn kẻ chiếm thân thể Khúc Hồn và đưa Dẫn Hồn chung ra, làm đối phương hoảng sợ lùi lại."},{"chuong":338,"tieuDe":"Bức Cung","tomTat":"Hàn Lập dùng chiếc chuông nhỏ trong tay để hóa giải thanh quang quanh Dẫn Hồn chung, khiến Khúc Hồn đang định bỏ chạy lập tức ngã quỵ. Trước sức ép của Hàn Lập, kẻ đang chiếm thân Khúc Hồn tự xưng từng là tu sĩ Trúc Cơ kỳ, thân thể bị hủy khi tranh đấu với cừu gia nên mới chiếm thân thể hiện tại. Khi đối phương mạo nhận là người Linh Thú Sơn, Hàn Lập nhận ra vẻ kinh hoảng và dùng Hạm Vân Chi cùng tên đệ tử trong môn để thử, khiến lời nói dối lộ rõ. Hàn Lập liền dán Định thần phù lên ngực Khúc Hồn, lấy Tụ Hồn Bát ra uy hiếp. Khúc Hồn tưởng Hàn Lập định dùng Luyện Hồn thuật nên càng khiếp sợ, còn Hàn Lập thuận thế giả vờ đe dọa bằng thủ đoạn ấy. Âm hàn khí từ Tụ Hồn Bát khiến nguyên thần Khúc Hồn đau đớn như bị đóng băng và kim đâm, cuối cùng hắn phải xin thu hồi Hồn khí và đồng ý khai thật. Sau đó Hàn Lập tiếp tục cảnh cáo rằng mình có pháp thuật kiểm tra thật giả, buộc đối phương không được nói dối nếu không muốn hồn phi phách tán."},{"chuong":339,"tieuDe":"Khiếp Sợ","tomTat":"Hàn Lập tiếp tục ép hỏi người trong thân Khúc Hồn, không để đối phương dùng cớ tán tu để lấp liếm, buộc hắn thừa nhận mình là tu sĩ Ngự Linh tông của Thiên Đô quốc. Tu sĩ này nói thân thể cũ bị một tu sĩ Việt Quốc pháp lực cao thâm hủy mất, sau khi đoạt xá thì tu vi giảm mạnh nên không dám trở về tông môn vì sợ đồng môn nhòm ngó địa vị và hạ độc thủ. Khi Hàn Lập nhắc việc Ma đạo lục tông đã xâm lấn Việt Quốc, đối phương lỡ miệng nói thời gian chưa tới, khiến Hàn Lập nhận ra hắn biết trước kế hoạch lớn của ma đạo. Hàn Lập lấy Tụ Hồn bát ra uy hiếp bằng chuyện luyện hồn, dù trong lòng chưa thật sự biết Luyện Hồn thuật, còn đối phương yêu cầu hắn dùng Hồn khí thề không hạ độc thủ để đổi lấy bí mật. Sau khi nghe tình hình chiến cuộc, tu sĩ trong thân Khúc Hồn khuyên Hàn Lập không cần đến đại doanh Thất phái vì nơi đó rất có thể đã thành chỗ chết sau khi liên quân bị lừa vào bẫy. Hắn tiết lộ Linh Thú Sơn vốn là phân chi bên ngoài của Ngự Linh tông, việc phản bội trước đó có thể chỉ là màn che mắt của Ma đạo lục tông để gom diệt tu sĩ hai nước. Cuối chương, hắn còn nói Yểm Nguyệt tông từng có quan hệ sâu xa với Hợp Hoan tông, nhưng đã đoạn tuyệt từ mấy trăm năm trước và muốn tự lập."},{"chuong":340,"tieuDe":"Quyển Sáo","tomTat":"Khúc Hồn tiếp tục dùng lời khai về âm mưu Ma đạo để thuyết phục Hàn Lập, giải thích rằng cái chết của tu sĩ Kết Đan trong trận tập kích có thể là do tu sĩ Trúc Cơ dùng bí pháp tạm nâng tu vi để đánh lừa sáu phái. Từ đó Hàn Lập suy ra nếu Linh Thú sơn phản kích ngay trong liên quân, trận thế của Thất phái và các nước đồng minh sẽ bị xé rách, còn Ma đạo có thể đánh úp đại doanh trước ngày quyết chiến. Nghĩ đến khả năng Thất phái đại bại, Hàn Lập bắt đầu tính đường rời Việt quốc hoặc sửa truyền tống trận để tìm nơi tu luyện khác. Khi bị ép đưa chứng cứ, Khúc Hồn thừa nhận có ngọc giản do bổn tông gửi cho Linh Thú sơn và nói túi trữ vật chứa nó được giấu trong một sơn động gần đó. Hắn cũng kể chuyện nguyên thần của mình từng trọng thương ở Gia Nguyên thành, không tìm được tu sĩ để đoạt xá nên nhập vào thân cương thi Khúc Hồn. Trước khi đi lấy chứng cứ, Hàn Lập dán thêm định thần phù lên Khúc Hồn, nhưng sau khi hắn rời đi, ánh mắt Khúc Hồn lộ vẻ quỷ dị. Hàn Lập vào sơn động với Nguyệt Quang thạch, Bạch Lân thuẫn và Quy Xác phòng thân, phát hiện những tảng đá trong động thực ra là đống xương thú. Ngay khi hắn nhận ra nguy hiểm và định lui, một bóng đen phục kích, đánh văng hắn vào vách đá rồi chém Bạch Lân thuẫn vỡ thành hai mảnh."},{"chuong":341,"tieuDe":"Chật Vật","tomTat":"Bạch Lân Thuẫn của Hàn Lập bị một yêu vật dùng chi trước như khảm đao chém hủy, khiến hắn kinh hãi vì đây là pháp khí phòng ngự đỉnh cấp luyện từ bạch lân Mặc Giao. Hắn lập tức rời sơn động, gọi Thần Phong Chu định thoát thân nhưng bị yêu vật chặn đường, rồi nhận ra đối phương là một con bọ ngựa khổng lồ màu xám đen có linh trí và tốc độ đáng sợ. Hàn Lập thi triển La Yên bộ tạo ảo ảnh nhưng bị bọ ngựa phá giải, phải dùng Quy xác pháp khí đỡ đòn và chịu cảnh pháp khí bị chém sâu. Khi bọ ngựa mở cánh phi hành, Hàn Lập dùng nhiều pháp khí công kích nhưng bị đối thủ chấn nát kim nhận, hỏa xoa và tiếp tục truy đuổi trên không, thậm chí còn nhanh hơn Thần Phong Chu. Từ uy thế của nó, Hàn Lập suy đoán yêu thú này mạnh hơn Bạch Tri chu, có thể đạt tới tứ cấp đỉnh giai hoặc ngũ cấp, đủ uy hiếp tu sĩ Kết Đan sơ kỳ. Trong lúc nguy cấp, hắn lao xuống rừng rậm, tung pháp khí thường cùng bốn năm khôi lỗi binh sĩ làm mồi nhử để tranh thủ thời gian. Sau đó Hàn Lập khoác Ẩn Linh sa đoạt từ Tuyên Nhạc để che giấu khí tức và hơi thở, đồng thời thủ sẵn Huyết Linh toản như phương án cuối dù không tin chắc có thể đánh trúng yêu thú quá nhanh này."},{"chuong":342,"tieuDe":"Kinh Nghi","tomTat":"Hàn Lập ẩn nấp trong rừng, căng thẳng theo dõi yêu thú bọ ngựa đang tiến thẳng về phía mình và âm thầm chuẩn bị Huyết Linh Toản để liều mạng ở cự ly gần. Đúng lúc nguy cấp, yêu thú lại đổi hướng bắt một con heo rừng rồi bay đi, khiến Hàn Lập thoát nạn trong gang tấc và càng thêm chắc chắn mình đã bị kẻ chiếm thân Khúc Hồn lừa vào bẫy. Sau khi bình tĩnh lại, hắn suy luận từ thân phận Ngự Linh Tông, sức mạnh của yêu thú và những cơ mật Ma đạo mà đối phương biết, rồi nghi ngờ kẻ kia vốn không phải Trúc Cơ kỳ mà có thể là tu sĩ Kết Đan kỳ đang suy yếu vì đoạt xá. Nhận ra nếu để đối phương khôi phục tu vi thì hậu họa khôn lường, Hàn Lập lập tức quay lại đỉnh núi, quyết tâm giết chết “Khúc Hồn” trước khi y thoát thân. Tới nơi, hắn thấy đối phương vẫn còn bị Định Thần phù dán trên người nên không nói nhiều mà trực tiếp thúc Ô Long đoạt công kích. Tuy nhiên “Khúc Hồn” lại né được đòn dù phù chưa bị gỡ, khiến Hàn Lập kinh nghi và càng dốc sức ra tay. Khi Ô Long đoạt được thúc động mạnh hơn để tung một kích quyết sát, “Khúc Hồn” trong tình thế nguy cấp phun ra một đạo lục quang, cuối cùng chặn được đòn toàn lực của Hàn Lập."},{"chuong":343,"tieuDe":"Lục Hoàng Kiếm","tomTat":"Hàn Lập thấy thân thể Khúc Hồn do nguyên thần lạ điều khiển dùng một thanh tiểu kiếm màu xanh chặn được Ô Long đoạt, liền nhận ra đó là pháp bảo và xác định đối thủ trước kia đích thực là tu sĩ Kết Đan kỳ. Hắn lấy Dẫn Hồn chung định chế phục, nhưng đối phương phun ra viên đan màu xanh biếc phát lục quang hộ thân khiến tiếng chuông mất tác dụng. Hàn Lập chuyển sang thả hơn mười khôi lỗi cấp hai cuối cùng, dồn ép đối thủ bằng cột sáng và mũi tên ánh sáng, rồi bất ngờ dùng Huyết Linh Toản đánh nổ viên đan xanh. Khi lục quang hộ thân tan biến và đối thủ đau đớn ngã xuống, Hàn Lập dùng hỏa cầu thiêu thân Khúc Hồn để dụ quang đoàn nguyên thần bay ra, sau đó chộp lấy và bóp nát. Hắn kiểm tra thấy thân thể Khúc Hồn chỉ bị thương ngoài da, bèn dùng Dẫn Hồn chung khôi phục trạng thái cứng ngắc cho Khúc Hồn. Cuối cùng Hàn Lập nghiên cứu tiểu kiếm, đọc được hai chữ “Lục hoàng”, biết mình chưa thể dùng pháp bảo vô chủ khi chưa đạt Kết Đan nhưng vẫn thu lấy Lục Hoàng Kiếm làm pháp bảo đầu tiên, đồng thời nhặt các mảnh đan xanh nghi có liên hệ tới kim đan Kết Đan kỳ."},{"chuong":344,"tieuDe":"Đại Trận Diệt Yêu","tomTat":"Hàn Lập không vội nghiên cứu mảnh vỡ mà kiểm tra vùng phụ cận rồi cân nhắc cách xử lý yêu thú bọ ngựa. Vì yêu thú trưởng thành khó cưỡng ép thu phục, hắn quyết định dùng Điên đảo ngũ hành trận để bẫy giết, đồng thời tạm chưa trở về đại doanh Thất phái do còn nghi ngờ lời tu sĩ Ngự Linh Tông. Hắn mất một ngày bố trí đủ trận kỳ và trận bàn gần sơn động, sau đó cưỡi Thần Phong Chu dụ yêu thú truy đuổi vào trận. Trong nhiều ngày, huyễn cảnh và khôi lỗi liên tục tiêu hao khiến yêu thú suy kiệt, tạo thời cơ cho Hàn Lập dùng phù bảo tiểu đao màu vàng xuyên đầu giết chết nó. Hắn thu đôi chi trước, cánh xám và hơn mười quả trứng đã chết trong bụng yêu thú, rồi vẫn cẩn thận cất trứng vào hộp ngọc. Quay lại sơn động, Hàn Lập phát hiện di hài áo xám cùng túi trữ vật của tu sĩ Ngự Linh Tông, đồng thời biết người này trước khi mất thân thể đã kịp mang Lục Hoàng Kiếm và lục đan theo nguyên thần rời đi. Túi trữ vật không có pháp khí hay phù bảo cao cấp như hắn kỳ vọng, nhưng lại chứa thức ăn, nhiều mẫu côn trùng còn sống và lục sắc ngọc giản ghi tâm đắc bồi dưỡng kỳ trùng, bí pháp điều khiển cùng bảng xếp hạng yêu trùng. Qua ngọc giản, Hàn Lập biết yêu thú bọ ngựa thật ra được gọi là Kim bối yêu lang, xếp hạng bảy mươi ba, còn các mẫu kỳ trùng tưởng thấp hạng vẫn là chủng loại hiếm có trên thế gian."},{"chuong":345,"tieuDe":"Tiểu Lão Đầu Dữ Chung Thanh","tomTat":"Hàn Lập kiểm tra túi trữ vật đoạt được, chuyển đồ sang túi của mình rồi chém nát túi cũ để tránh dấu hiệu truy tung. Sau một ngày nghỉ, hắn không tới đại doanh Thất phái ngay mà mang Khúc Hồn quay về Hoàng Phong Cốc để dò tình hình. Về động phủ ở Thái Nhạc sơn mạch, hắn phát hiện hai trứng Bạch Tri chu đã nở trong mật thất Linh Nhãn chi tuyền, lại thân cận hắn nhờ Khống Thần cấm chế bằng tinh huyết. Hàn Lập nhận ra chúng đã có tu vi Luyện Khí kỳ tầng ba, tầng bốn và thuộc loại kỳ trùng hiếm, nên đem theo nuôi dạy. Vì phù lục đã tiêu hao nhiều, hắn lấy thêm phù lục dự trữ, để Khúc Hồn lại động phủ rồi vào Hoàng Phong Cốc hỏi tin. Tại Bách Dược viên, hắn gặp Mã sư huynh và Tiêu Thúy Nhi, sau đó báo tin Linh Thú Sơn có thể là nội ứng Ma đạo. Mã sư huynh ban đầu khó tin, nhưng khi Kinh Long chung từ Nghị Sự điện vang đủ tám mươi mốt tiếng, lão nhận định tiền phương có lẽ đại bại và Hoàng Phong Cốc đang đối diện dấu hiệu diệt môn."},{"chuong":346,"tieuDe":"Lệnh Hồ Lão Tổ","tomTat":"Hàn Lập cùng Tiêu lão gia tử vừa rời phòng thì tiếng Kinh Long chung vang lên, khiến Tiêu Thúy Nhi hoảng sợ; hai người lập tức ngự khí đến Nghị Sự điện. Trên đường, Hàn Lập thấy đông đảo tu sĩ trong cốc cũng bay về một hướng nhưng phần lớn chỉ là Luyện Khí kỳ, vì vậy âm thầm lo Hoàng Phong Cốc khó chống đỡ nếu ma đạo công tới. Trong đại sảnh, người ngồi chủ tọa không phải Chung Linh Đạo mà là một lão giả áo gấm râu tóc bạc phơ, chỉ một cái liếc đã khiến Hàn Lập có cảm giác bị nhìn thấu và bị hỏi về công pháp tu luyện nguyên thần. Chung Linh Đạo sau đó giới thiệu lão giả là Lệnh Hồ lão tổ, tu sĩ Nguyên Anh kỳ và Thái thượng trưởng lão duy nhất của Hoàng Phong Cốc, sẽ toàn quyền an bài khi môn phái gặp nguy cơ diệt môn. Lệnh Hồ lão tổ thông báo liên quân Thất phái tiền phương đã đại bại, phòng tuyến thứ hai chỉ miễn cưỡng chống đỡ, nguyên nhân trọng yếu là Linh Thú Sơn phản bội mở đại trận cho người Ma đạo tiến vào. Ông giải thích các tu sĩ Nguyên Anh hai bên đã giao thủ, phía Thất phái rơi vào hạ phong và bị lời thề ràng buộc không được trực tiếp tham chiến, nên chiến cuộc chỉ còn giới hạn ở cấp Kết Đan kỳ. Cuối cùng, Lệnh Hồ lão tổ quyết định Hoàng Phong Cốc cùng năm phái còn lại rời khỏi Việt Quốc để bảo toàn lực lượng, rồi chỉ định hơn nửa tu sĩ trong điện, bao gồm Hàn Lập và Tiêu lão gia tử, theo mình ra hậu điện làm một việc nguy hiểm."},{"chuong":347,"tieuDe":"Triệt Ly","tomTat":"Lệnh Hồ lão tổ triệu tập nhóm tu sĩ có tư chất hoặc công pháp đặc thù, xem họ là mồi lửa để Hoàng Phong Cốc có thể Đông Sơn tái khởi, đồng thời buộc mọi người giữ bí mật tuyệt đối trước khi rút đi. Hàn Lập trên đường về động phủ cân nhắc rằng đi theo tông môn tuy an toàn nhưng có thể khiến con đường Kết Đan của mình bị trì hoãn, nên trong lòng đã nảy ý muốn tách ra. Hắn thu dọn động phủ, lấy túi trữ phù lục, che giấu Linh nhãn chi tuyền, thu Điên đảo ngũ hành đại trận rồi phá sập núi nhỏ để xóa dấu vết. Khi trở lại Nghị sự đại điện, hắn thấy nhóm Trúc Cơ và nhiều đệ tử Luyện Khí đã tập kết, trong đó có Tiêu Thúy Nhi được tiểu lão đầu đưa theo. Lệnh Hồ lão tổ báo Ma đạo đã xuất hiện, Hoàng sư thúc dẫn đội lập tức rời Hoàng Phong Cốc, nhưng giữa đường nhận phi kiếm truyền tin cho biết Ma đạo chia hai lộ vừa vây cốc vừa truy kích đoàn triệt ly. Hoàng sư thúc chọn hơn hai mươi tu sĩ Trúc Cơ, trong đó có Hàn Lập, ở lại đánh lạc hướng địch và phát ngọc giản bản đồ cho họ. Hàn Lập không quá để tâm đến bản đồ vì xem nhiệm vụ nguy hiểm này là cơ hội hiếm có để thoát khỏi con đường chung với Hoàng Phong Cốc và tiếp tục theo đuổi mục tiêu Kết Đan."},{"chuong":348,"tieuDe":"Thiên Hỏa Thuật","tomTat":"Sau khi mọi người hủy hết ngọc giản, Hoàng sư thúc lấy Phong Vân phiên tạo mây trắng rộng hơn mười trượng để che giấu đội Trúc Cơ kỳ Hoàng Phong Cốc. Hàn Lập quan sát pháp bảo này, so sánh với Thanh Hỏa chướng của mình rồi âm thầm chuẩn bị theo cách kín đáo, giao cự kiếm bạc cho Khúc Hồn và giữ các pháp khí phòng thân. Khi đội phục kích chờ địch, bầu trời bất ngờ hóa thành ráng đỏ như dung nham, khiến Hoàng sư thúc nhận ra Thiên Hỏa thuật và buộc mọi người hợp lực dựng vòng bảo hộ. Mưa dung nham uy lực như từng kích của tu sĩ Trúc Cơ kỳ làm vòng bảo hộ suýt sụp, nhưng pháp thuật kết thúc đúng lúc. Ngay sau đó, gần trăm tu sĩ Ma đạo lục tông vô thanh vô tức hiện thân bao vây đội Hoàng Phong Cốc. Một nam tử tóc bạc gầy như bộ xương và một nữ tử xinh đẹp hạ xuống, khiến Hàn Lập nhận ra địch có hai Kết Đan kỳ. Hoàng sư thúc gọi họ là Hồng phấn khô lâu, bị nữ tử nhận ra qua Phong Vân phiên rồi lập tức truyền âm cho mọi người phá vây, ai chạy được thì chạy."},{"chuong":349,"tieuDe":"Độn Tẩu Nguyên Vũ","tomTat":"Phong Vân phiên trong tay Hoàng sư thúc nổ tung, phóng ra sương trắng dày đặc bao phủ chiến trường để tu sĩ Hoàng Phong Cốc tranh thủ tháo chạy, còn ông tiếp tục giao thủ với hai tu sĩ Kết Đan kỳ Ma đạo. Hàn Lập chọn hướng có nhiều người chặn nhưng tu vi yếu hơn, dùng Thanh Hỏa Chướng che thân, Quy Xác pháp khí đỡ công kích và hỏa cầu phá quỷ đầu hắc khí, sau đó nhờ Thần Phong Chu cắt đuôi truy binh. Thoát khỏi vòng vây, hắn hạ xuống núi hoang, dùng linh thạch màu lam khôi phục pháp lực dưới sự canh gác của Khúc Hồn, rồi quyết định không trở lại điểm tập hợp Hoàng Phong Cốc. Hắn chuyển hướng sang Nguyên Vũ Quốc để kiểm tra Truyền tống trận, hy vọng có thể rời khỏi khu vực chiến tranh giữa Ma đạo và Minh đạo. Sau khi Hàn Lập vượt biên, một đội Ma đạo hơn vài chục người tới đồn trú tại biên giới Việt Quốc — Nguyên Vũ Quốc để chặn giết tu sĩ trốn sang sau. Hàn Lập bay tới vùng núi phía tây Kim Mã Thành tìm nơi ở của Tề Vân Tiêu, phát hiện thạch ốc, nhà trúc và trận pháp phòng hộ đã bị phá, trong phòng chỉ có thi thể chưởng quầy trà lâu chứ không phải Tề Vân Tiêu. Ngay sau đó, hai đạo lam quang từ phía nam bay tới, hiện ra một lão giả Trúc Cơ kỳ râu dê và một thanh niên Luyện Khí kỳ đầy sát khí đang hung hăng nhìn Hàn Lập."},{"chuong":350,"tieuDe":"Thuấn Sát","tomTat":"Hàn Lập đến nơi ở đã bị phá của Tề Vân Tiêu và đối chất với một lão giả Trúc Cơ trung kỳ cùng một người thành niên thuộc Phó gia. Qua lời hai người, hắn biết Tề Vân Tiêu còn sống, đồng thời hiểu Phó gia truy cứu vì cho rằng Tề Vân Tiêu đã giết người của họ, chuyện này khiến hắn liên hệ tới lần cứu Tân Như Âm trước đây. Sau khi xác định tại chỗ chỉ có hai đối thủ, Hàn Lập lập tức dùng Ô Long đoạt và hơn mười khôi lỗi nghi binh, còn bản thân phối hợp La Yên Bộ với Thần Phong Chu vòng ra sau dùng ti tuyến cắt đầu cả hai. Hắn thu túi trữ vật, đặc biệt chú ý pháp khí hình đồng tiền phòng ngự của lão giả, rồi dùng hỏa cầu thiêu sạch thi thể. Sau đó Hàn Lập đưa Khúc Hồn bay tới tiểu sơn vô danh nơi Tân Như Âm ẩn cư, thấy sương mù phòng hộ vẫn còn nguyên nên tạm yên tâm. Khi hắn dùng Truyền Âm phù xin vào, trận sương mù biến cảnh vật thành rừng đại thụ ảo hóa rồi mở thông đạo, nhưng giọng nữ bên trong lập tức cảnh giác hỏi lai lịch Khúc Hồn."},{"chuong":351,"tieuDe":"Tề Vân Tiêu Chi Tử","tomTat":"Hàn Lập dẫn Khúc Hồn tới nơi ở của Tân Như Âm và giải thích người đi sau mình chỉ là thi thể do hắn luyện chế, khiến nàng yên tâm mời vào. Tại quần thể trúc ốc, Hàn Lập thấy Tân Như Âm cùng Tiểu Mai đều mặc áo trắng, rồi phát hiện linh vị Tề Vân Tiêu và hiểu người quen cũ đã chết. Tân Như Âm tự xưng quả phụ Tân thị, còn Tiểu Mai giải thích nàng tự nguyện thủ tiết cho Tề Vân Tiêu vì hắn bị hại. Qua lời kể của Tân Như Âm, Tề Vân Tiêu vì thay nàng đi tìm tài liệu trận pháp mà bị tu sĩ Phó gia nghi ngờ truy bắt; Phó gia sau đó vây công chỗ ở của hắn, bị đại trận sát thương nhiều người nhưng vẫn mời cao thủ Kết Đan kỳ phá trận. Tề Vân Tiêu dùng huyễn trận tạm vây cao thủ này để thoát, song chưởng quầy chết tại chỗ, còn hắn trọng thương chạy tới chỗ Tân Như Âm rồi tắt thở. Tân Như Âm cho biết truyền tống trận cổ xưa đã gần sửa xong, đồng thời giao hai hộp ngọc chứa Vân Tiêu tâm đắc, điển tịch luyện khí và tâm huyết trận pháp của mình cho Hàn Lập. Đổi lại, nàng xin Hàn Lập nếu có ngày kết đan thì thay vợ chồng nàng diệt tộc Phó gia, khiến Hàn Lập cũng cảm nhận rõ hận ý sâu nặng của nàng."},{"chuong":352,"tieuDe":"Hứa Hẹn","tomTat":"Hàn Lập cân nhắc lời cầu xin của Tân Như Âm và ban đầu không muốn nhận mối thù với Phó gia, vì trận pháp cùng luyện khí thuật hiện chưa giúp ích nhiều cho hắn khi chưa Kết Đan. Tân Như Âm nói Tề Vân Tiêu chết trong tay Phó gia là do nàng liên lụy, nếu không báo thù cho phu quân thì chết cũng không còn mặt mũi gặp lại. Hàn Lập bắt mạch và phát hiện kinh mạch nàng đã khô héo, chỉ còn sống khoảng hai năm; nàng giải thích nguyên nhân là Long ngâm chi chất vốn thuộc nam giới nhưng lại sinh trên thân nữ. Sau khi biết Tề gia không dám báo thù và sư thừa trận pháp của Tân Như Âm cũng đã mất, Hàn Lập nhận lời hứa có điều kiện rằng tương lai đủ năng lực sẽ ra tay, rồi thu hai hộp ngọc. Vì Truyền tống trận cần một tháng khôi phục, hắn mang Khúc Hồn rời tiểu sơn, tới phường thị Thiên Tinh Tông và nhận thấy nơi này đông tu sĩ bất thường. Hàn Lập quay lại cửa hàng luyện khí, dùng Ô Long đoạt để Đại Hắc và Từ điếm chủ nhận ra mình, rồi vào hậu viện bàn việc luyện khí. Một đại hán Trúc Cơ sơ kỳ bất mãn vì Hàn Lập được ưu tiên tiếp đón, nhưng chỉ một ánh mắt lạnh lẽo đầy sát khí của Hàn Lập đã khiến hắn khiếp sợ."},{"chuong":353,"tieuDe":"Tinh Trần Các","tomTat":"Hàn Lập đem tài liệu lấy từ Bạch Tri chu và bọ ngựa yêu thú cấp bốn cho Từ điếm chủ xem, khiến lão luyện khí sư cực kỳ kích động trước cơ hội xử lý tài liệu cao cấp. Hắn yêu cầu dùng chân Bạch Tri chu luyện thành một bộ pháp khí công kích và hẹn ngày mai chính thức giao tài liệu để Từ điếm chủ nghiên cứu phương pháp luyện chế. Qua lời Từ điếm chủ, Hàn Lập biết tin thảm bại của tu sĩ hai nước cùng Việt quốc đã lan sang Nguyên Vũ quốc, khiến gia tộc tu tiên và tán tu đổ tới phường thị đổi mua vật phẩm tự bảo vệ. Hàn Lập đi quanh phường thị, nhận thấy pháp khí đỉnh giai xuất hiện nhiều hơn trước và mua được vài loại dược tài lạ. Sau đó hắn cùng Khúc Hồn đến Tinh Trần các ở trung tâm phường thị, được nhân viên tầng một giới thiệu cơ cấu chín tầng phân theo cấp bậc tu sĩ. Hàn Lập lên tầng năm, bị gã sai vặt áo đỏ chặn trước tầng sáu vì cần chưởng quầy xác nhận, nên vào đại sảnh gặp phụ nhân trung niên Trúc Cơ hậu kỳ. Khi Hàn Lập nói muốn mua trân phẩm chân chính, phụ nhân hứa Tinh Trần các có thể làm vừa lòng nếu hắn đủ sức, đồng thời cho biết nam tử Trúc Cơ kỳ đang ngồi cũng có cùng mục đích rồi sai Tử Liên dâng trà."},{"chuong":354,"tieuDe":"Lam Phu Nhân","tomTat":"Hàn Lập ngồi chờ tại đại sảnh Tinh Trần các cùng một tu sĩ họ Phiền, còn Khúc Hồn đứng gần cầu thang và bị đối phương nhận ra là luyện thi có linh khí bất thường. Lam phu nhân trở lại cùng hai khôi lỗi bưng khay trân phẩm phủ khăn tơ hồng, thứ có thể ngăn thần thức dò xét của Hàn Lập và tu sĩ họ Phiền. Nàng tự giới thiệu họ Lam rồi bày nhiều pháp khí, trong đó Hàn Tinh nhận được giới thiệu là đoản nhận đỉnh giai luyện từ huyền tinh và băng ngọc, có âm hàn làm suy giảm thực lực địch khi đánh lâu. Tu sĩ họ Phiền nhanh chóng mua Hàn Tinh nhận với giá tám trăm linh thạch rồi rời đi. Hàn Lập nhận ra Lam phu nhân âm thầm dùng thần thức kiểm tra linh thạch, đồng thời không hứng thú với pháp khí thông thường mà trực tiếp hỏi mua đan phương Trúc Cơ kỳ hoặc pháp khí thành bộ càng nhiều món càng tốt. Lam phu nhân cho biết Tinh Trần các gần đây thu được hai phương thuốc và một bộ pháp khí đỉnh giai nhưng giá rất cao, nên yêu cầu Hàn Lập chứng minh có đủ tài lực. Sau khi Hàn Lập đưa túi linh thạch vượt điều kiện, nàng tự dẫn hắn lên tầng sáu để tiếp tục thương lượng."},{"chuong":355,"tieuDe":"Hồng Tuyến Độn Quang Châm","tomTat":"Hàn Lập theo Lam phu nhân lên tầng sáu của cửa hàng, vốn đoán nơi này có thể do cao nhân Kết Đan kỳ trấn giữ, nhưng người tiếp khách lại là Tú nhi, một thiếu nữ phàm nhân không có pháp lực. Tú nhi tiếp nhận yêu cầu mua phương thuốc Trúc Cơ kỳ và pháp khí thành bộ, sai nữ tu sĩ mang hai hộp ngọc lên. Hàn Lập xem hai ngọc giản phương thuốc, bỏ qua Tụ Linh đan đã từng có và chú ý đến Chân Nguyên đan vì phương thuốc này phù hợp với hắn hiện tại. Trong hộp lớn, hắn phát hiện bộ Hồng tuyến độn quang châm gồm mười ba phi châm đỏ lửa, loại pháp khí hiếm thích hợp đánh lén nhưng yêu cầu thần thức mạnh để điều khiển toàn bộ. Tú nhi giải thích Lam phu nhân từng thích bộ châm này nhưng không thể khống chế đủ mười ba cây, còn Hàn Lập thử một lần đã khiến toàn bộ phi châm hóa thành hồng tuyến bay quanh thân. Sau khi nghe giá Chân Nguyên đan và phi châm tổng cộng bốn ngàn linh thạch, Hàn Lập quyết định mua cả hai rồi nghiêm túc hỏi cửa hàng thu mua linh dược ngàn năm như thế nào."},{"chuong":356,"tieuDe":"Họa Phúc Tương Y","tomTat":"Hàn Lập rời Tinh Trần các sau khi dùng hai viên Định Nhan đan và một ngàn linh thạch đổi được Hồng tuyến độn quang châm cùng ngọc giản phương thuốc, đồng thời nhận ra sức hấp dẫn đặc biệt của đan dược trú nhan đối với nữ tu. Hắn không tiếp tục lộ thêm đan dược hay linh thảo vì hiểu rằng tiền tài lộ ra sẽ kéo tới nguy hiểm. Sau một đêm nghỉ ở khách điếm, Hàn Lập đến chỗ Từ điếm chủ luyện khí hơn nửa tháng nhưng phần lớn tài liệu quý bị hủy, chỉ thu được bộ năm phi đao trắng tinh từ chân Bạch Tri chu. Hắn tiếp tục tới tiểu sơn của Tân Như Âm, được nàng báo đã sửa xong Truyền Tống trận cổ xưa và nhận ngọc giản ghi phương pháp khôi phục. Tân Như Âm biết mình chỉ còn sống một, hai năm nên trao cho Hàn Lập trận kỳ, trận bàn do nàng cùng Tề Vân Tiêu luyện chế, khiến Hàn Lập trịnh trọng hứa nếu đủ năng lực sẽ diệt Phó gia để báo thù cho họ. Sau ba ngày ở lại thảo luận trận pháp, Hàn Lập rời đi tới Bạch Trì sơn để nghe ngóng tình hình chiến cuộc Việt quốc và quyết định kế hoạch tiếp theo."},{"chuong":357,"tieuDe":"Bạch Trì Sơn","tomTat":"Hàn Lập cùng Khúc Hồn đến đỉnh Tây Bạch Trì sơn, nơi có cổ tự, thạch đình và nhiều tu sĩ đã tụ tập trước tiểu hội. Nhờ thần thức mạnh, hắn nghe nhóm bốn tán tu bàn về việc Ma đạo đánh bại sáu phái Việt quốc và nguy cơ chiến sự lan sang Nguyên Vũ quốc, Tử Kim quốc. Hàn Lập chủ động chen vào, tự xưng là tán tu để hỏi tình hình mới nhất, khiến nhóm tu sĩ ban đầu kính sợ rồi dần kể chuyện. Đinh lão giả cho biết Việt quốc đang hỗn loạn, một số tu sĩ sáu phái còn ở lại tập kích Ma đạo, các gia tộc tu tiên thì phân hóa thành quy thuận, rút đi hoặc quan sát. Ông cũng nói nhiều trọng địa của các phái đã thất thủ, nhưng tài vật quý phần lớn được đệ tử rút lui mang theo. Tin quan trọng nhất là cao tầng Hoàng Phong Cốc dùng kế Kim thiền thoát xác, hy sinh hai nhóm đệ tử để tinh nhuệ tâm phúc và tài sản tích lũy hơn nghìn năm rút đi hướng khác. Hàn Lập nghe chuyện trong lòng trầm xuống vì mình thuộc nhóm bị bỏ lại, nhưng ngoài mặt vẫn ung dung bình phẩm những đệ tử bị vứt bỏ là ngốc nghếch."},{"chuong":358,"tieuDe":"Vô Biên Hải, Mộ Lan Nhân","tomTat":"Hàn Lập nghe tin từ nhóm tu sĩ và nhận định Việt quốc hiện đã rơi vào cục diện cực loạn, sau đó gọi Khúc Hồn rời sang thạch đình khác để tiếp tục dò hỏi. Sau hai canh giờ thu thập tin tức, hắn xác định chỉ còn hai lựa chọn sinh tồn: tự ngự khí rời khỏi khu vực nguy hiểm, hoặc sửa Truyền Tống trận cổ xưa để đánh cược điểm đến xa xôi. Khi phân tích phương hướng, hắn loại bỏ phía Đông vì Thiên La quốc của Ma đạo, phía Tây vì Phong Đô quốc của Chính đạo minh, rồi tiếp tục bác bỏ hướng Bắc do các tiểu quốc bất ổn và Vô biên hải quá nguy hiểm. Chương mở rộng bối cảnh phía Nam với Cửu quốc minh, Mộ Lan đại thảo nguyên, Mộ Lan tộc, pháp sĩ Mộ Lan và Linh thuật, đồng thời thuật lại cuộc chiến lâu dài vì linh mạch và mỏ linh thạch giữa Mộ Lan với Tu tiên giới cửu quốc. Ở đầu kia thảo nguyên còn có Đột Ngột nhân, Thiên Lan thảo nguyên và lời đồn về một đại đế quốc khổng lồ, nhưng Hàn Lập không tin hoàn toàn những tin này. Cuối cùng, hắn suy đoán lục phái Việt quốc nhiều khả năng sẽ đến Cửu quốc minh và nếu đi phía Nam mình dễ bị kéo lại làm môn hạ Hoàng Phong Cốc, nên quyết định trước tiên phải sửa Truyền Tống trận cổ xưa."},{"chuong":359,"tieuDe":"Kinh Ngộ Cựu Nhân","tomTat":"Hàn Lập rời Bạch Trì sơn, đến phường thị Thiên Tinh tông mua tài liệu tu bổ Truyền Tống trận rồi bí mật lẻn vào Việt quốc từ vùng biên hẻo lánh, nhờ vậy tránh được phần lớn tuần tra Ma đạo. Hắn quay lại mỏ linh thạch chứa Truyền Tống trận cổ, phát hiện nơi này đã bị đệ tử Quỷ Linh môn và Hợp Hoan phái chiếm giữ nên lặng lẽ mở lại động quật dưới đất gần đó. Sau khi thấy trận cổ vẫn còn, hắn dùng trận kỳ huyễn hình cùng Điên Đảo Ngũ Hành trận cải tiến để che giấu và phòng thủ, rồi bắt đầu sửa trận theo ngọc giản. Bảy ngày sau, do kỹ thuật kém làm hỏng nhiều vật liệu, hắn mới sửa được non nửa thì số tài liệu đã cạn, buộc phải bay đêm tới tiểu phường thị phía đông mỏ linh thạch để tìm mua thêm. Trên đường, Hàn Lập phát hiện nhiều độn quang đang lao tới nên dùng Thần Phong Chu hạ xuống ẩn thân, rồi chứng kiến một đạo bạch quang bị huyết vụ và hào quang hồng nhạt truy đuổi. Bạch quang lộ ra nữ tử áo trắng che mặt có giọng nói khiến hắn nhận ra là Nam Cung Uyển, còn phía truy đuổi gồm Vương Thiền, Điền công tử thuộc Hợp Hoan tông và Đổng Huyên Nhi đã lên Trúc Cơ trung kỳ. Vương Thiền bóc trần ý đồ của Điền công tử muốn dùng Huyền Nguyệt Hấp Âm công hấp nạp nguyên âm Nam Cung Uyển để đột phá bình cảnh, khiến nàng phẫn nộ tung kiếm quang trắng xóa phản kích. Hai tu sĩ Ma đạo kinh hãi trước đòn công kích của nàng và lập tức muốn lùi tránh."},{"chuong":360,"tieuDe":"Bán Lộ Kiếp Nhân","tomTat":"Đổng Huyên Nhi, Vương Thiền và Điền công tử truy sát Nam Cung Uyển, tưởng nàng đã suy kiệt khi kiếm quang tan biến nên áp sát. Nam Cung Uyển thật ra đã bị thương nặng sau trận đại chiến với một tu sĩ Kết Đan kỳ, pháp bảo liên hệ nguyên thần tổn hại, lại phải dùng bí thuật hao nguyên khí để cưỡng ép bỏ chạy. Nàng giả vờ suy yếu rồi bất ngờ phóng kiếm khí vây ba người Ma đạo, nhưng linh lực cuối cùng vẫn cạn. Hàn Lập đang ẩn dưới rừng không thể nhìn nàng chết, liền dùng Thần Phong Chu lao lên cứu, ôm nàng rút xuống rừng trước mặt Vương Thiền và Điền công tử. Hai thiếu chủ Ma đạo nhận ra Hàn Lập, lập tức dùng huyết vụ và sáo ngọc hóa khổng tước phấn hồng truy sát. Hàn Lập làm ra vẻ kinh hoảng rồi cùng Nam Cung Uyển biến mất, khiến hai truy binh rơi vào ảo trận cột đá đã chuẩn bị sẵn. Bên ngoài trận, Đổng Huyên Nhi chần chờ vì nhận ra thân ảnh Hàn Lập, còn Điền công tử vẫn hy vọng địa vị hiện nay của nàng ở Hợp Hoan tông sẽ khiến nàng ra tay cản người cũ Hoàng Phong Cốc."},{"chuong":361,"tieuDe":"Ô Long","tomTat":"Hàn Lập ôm nữ tử che mặt dùng Thần Phong Chu đối diện Đổng Huyên Nhi, bị nàng chất vấn chuyện Hồng Phất từng muốn gả nàng cho hắn và việc hắn mang tu sĩ Kết Đan kỳ của Yểm Nguyệt Tông đi. Nhận thấy huyễn trận đơn giản không thể giữ hai người Quỷ Linh Môn lâu, Hàn Lập tung pháp khí, Quy Xác và bốn khôi lỗi thú làm ra thế công quyết liệt để đánh lừa Đổng Huyên Nhi. Đổng Huyên Nhi dùng Hỏa Phượng Cân phối hợp Ma Công hộ thân nhưng bị hư chiêu của Hàn Lập qua mặt, truy đuổi một đoạn rồi mất dấu. Thực ra Hàn Lập đã dùng Hãm Địa Phù ẩn dưới gò đất dưới cây tùng, chờ nàng rời đi mới hiện thân. Sau đó hắn đưa nữ tử vào thụ động khô ráo, truyền linh lực kiểm tra thương thế thì bị cơ thể nàng hút pháp lực đến mức tu vi rơi từ Trúc Cơ trung kỳ xuống Luyện Khí kỳ và hôn mê. Khi tỉnh lại, Hàn Lập tưởng nàng là Nam Cung Uyển, nhưng nữ tử cho biết Nam Cung Uyển là đường tỷ của mình. Nàng còn nói đã nghe chuyện Hàn Lập từ Nam Cung Uyển và từng muốn tới Hoàng Phong Cốc giết hắn, khiến Hàn Lập biến sắc."},{"chuong":362,"tieuDe":"Nam Cung Bình","tomTat":"Hàn Lập tỉnh lại trong động và nhận ra nữ tử trước mặt chưa định giết mình, còn nàng tự xưng là Nam Cung Bình và không muốn hắn gọi là tiền bối. Nam Cung Bình cho biết Hàn Lập đã cứu nàng vì nhầm nàng với đường tỷ Nam Cung Uyển, nhưng vẫn tát hắn hai cái để trừng phạt chuyện đêm trước. Sau đó nàng đưa ra hai phương án bồi thường: cấp linh thạch hoặc đưa hắn về Yểm Nguyệt Tông để luyện đan, song tu phục hồi tu vi và có thể truyền bí thuật. Hàn Lập nghi ngờ phương án thứ hai có bẫy nên chọn nhận linh thạch, được nàng ném cho túi trữ vật màu đỏ chứa linh thạch bậc trung và nhiều tài liệu. Hắn xin thêm Nguyên Ngọc và nhận vài khối ngọc thạch trắng, nhờ đó đủ vật liệu chữa trị truyền tống trận cổ xưa. Trước khi rời đi, Nam Cung Bình hỏi lựa chọn của hắn là ngu hay thông minh, còn Hàn Lập nhờ nàng hỏi thăm Nam Cung Uyển nhưng không được đáp lời. Sau khi nàng đi, chương hé lộ Luân hồi chân quyết là công pháp đã hút chân nguyên Hàn Lập, có điều kiện thi triển nguy hiểm và chỉ bù lại phần hao tổn chứ không tăng thêm tu vi."},{"chuong":363,"tieuDe":"Truyền Tống","tomTat":"Hàn Lập rời thụ động trong tình trạng tu vi đại giảm nên cực kỳ cẩn trọng, mất nhiều thời gian mới trở lại động quật có Khúc Hồn và cổ Truyền tống trận. Sau sáu bảy ngày sửa chữa, hắn hoàn thành trận nhưng phát hiện linh thạch cấp thấp không đủ linh khí, phải thay bằng linh thạch bậc trung. Khi cổ trận phát động, hoàng quang bùng lên xuyên qua cấm chế Điên đảo ngũ hành trận, làm lộ vị trí động quật trước đoàn tu sĩ ma đạo do Vương Thiền dẫn tới. Vương Thiền nhận ra Hàn Lập, còn Lý thị huynh đệ nhận ra đây là cổ Truyền tống trận và lập tức hiểu giá trị của nó. Lão giả Lý thị ra lệnh toàn lực phá trận, nhưng Hàn Lập kịp dùng Đại Na Di lệnh kéo Khúc Hồn truyền tống thoát thân, khiến mọi công kích đánh vào khoảng không. Sau đó phe ma đạo vì không có Đại Na Di lệnh và vì Hàn Lập phá hỏng đầu bên kia nên không thể truy đuổi. Về sau Vương Thiền từng phái người canh động quật nhưng chiến sự ma đạo khiến việc này bị bỏ quên. Sau khi Hàn Lập rời Thiên Nam, Thiên đạo hội thành lập, các thế lực tiếp tục tranh chấp, lục đạo tông phái dàn xếp với Cửu Quốc Minh và Lý Hóa Nguyên về sau chết trận trong cuộc chiến với Pháp Sĩ."}];
